function initAccount(container, api, user) {
  container.querySelector('#acct-name').value = user.name || '';
  container.querySelector('#acct-email').value = user.email || '';

  // Save profile
  container.querySelector('#btn-save-profile').onclick = function() {
    var name = container.querySelector('#acct-name').value.trim();
    var status = container.querySelector('#profile-status');
    if (!name) { status.textContent = 'Name is required.'; status.style.color = 'var(--danger)'; return; }
    this.disabled = true;
    var btn = this;
    api.patch('/api/users/me', { name: name }).then(function(r) {
      btn.disabled = false;
      if (r.ok) { status.textContent = 'Saved.'; status.style.color = 'var(--success)'; }
      else { status.textContent = (r.error && r.error.message) || 'Save failed.'; status.style.color = 'var(--danger)'; }
    });
  };

  // Base64URL helpers for WebAuthn
  function b64urlToBytes(b64) {
    var s = b64.replace(/-/g, '+').replace(/_/g, '/');
    while (s.length % 4) s += '=';
    var bin = atob(s);
    var arr = new Uint8Array(bin.length);
    for (var i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  }
  function bytesToB64url(buf) {
    var arr = new Uint8Array(buf);
    var s = '';
    for (var i = 0; i < arr.length; i++) s += String.fromCharCode(arr[i]);
    return btoa(s).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
  }

  // Load passkeys
  function loadPasskeys() {
    api.get('/api/users/me/passkeys').then(function(r) {
      var el = container.querySelector('#passkey-list');
      if (!r.ok || !r.data || r.data.length === 0) {
        el.innerHTML = '<div style="color:var(--t2);font-size:13px;padding:8px 0">No passkeys registered yet.</div>';
        return;
      }
      el.innerHTML = '<table class="tbl"><thead><tr><th>Device</th><th>Backed up</th><th>Last used</th><th>Registered</th><th></th></tr></thead><tbody>' +
        r.data.map(function(pk) {
          return '<tr><td>' + (pk.device_name || 'Passkey') + '</td><td>' + (pk.backed_up ? 'Yes' : 'No') + '</td><td>' + (pk.last_used_at ? new Date(pk.last_used_at).toLocaleDateString() : 'Never') + '</td><td>' + new Date(pk.created_at).toLocaleDateString() + '</td><td><button class="btn danger btn-revoke-pk" data-id="' + pk.id + '" style="padding:4px 10px;font-size:12px">Revoke</button></td></tr>';
        }).join('') + '</tbody></table>';
      el.querySelectorAll('.btn-revoke-pk').forEach(function(btn) {
        btn.onclick = function() {
          if (!confirm('Revoke this passkey?')) return;
          api.delete('/api/users/me/passkeys/' + btn.getAttribute('data-id')).then(function(r2) {
            if (r2.ok) loadPasskeys();
          });
        };
      });
    });
  }
  loadPasskeys();

  // Register passkey
  container.querySelector('#btn-register-passkey').onclick = function() {
    var status = container.querySelector('#passkey-status');
    var btn = this;
    if (!window.PublicKeyCredential) {
      status.textContent = 'WebAuthn is not supported in this browser.';
      status.style.color = 'var(--danger)';
      return;
    }
    btn.disabled = true;
    status.textContent = 'Starting registration...';
    status.style.color = 'var(--t2)';
    api.post('/api/users/me/passkeys').then(function(r) {
      if (!r.ok) {
        btn.disabled = false;
        status.textContent = (r.error && r.error.message) || 'Failed to start registration.';
        status.style.color = 'var(--danger)';
        return;
      }
      var opts = r.data;
      var createOpts = {
        publicKey: {
          rp: opts.rp,
          user: { id: b64urlToBytes(opts.user.id), name: opts.user.name, displayName: opts.user.displayName },
          challenge: b64urlToBytes(opts.challenge),
          pubKeyCredParams: opts.pubKeyCredParams,
          timeout: opts.timeout || 60000,
          attestation: opts.attestation || 'none',
          authenticatorSelection: opts.authenticatorSelection
        }
      };
      if (opts.excludeCredentials) {
        createOpts.publicKey.excludeCredentials = opts.excludeCredentials.map(function(c) {
          return { id: b64urlToBytes(c.id), type: c.type, transports: c.transports };
        });
      }
      status.textContent = 'Waiting for authenticator...';
      return navigator.credentials.create(createOpts);
    }).then(function(credential) {
      if (!credential) { btn.disabled = false; return; }
      status.textContent = 'Verifying...';
      var response = credential.response;
      var body = {
        id: credential.id,
        rawId: bytesToB64url(credential.rawId),
        type: credential.type,
        response: {
          attestationObject: bytesToB64url(response.attestationObject),
          clientDataJSON: bytesToB64url(response.clientDataJSON)
        }
      };
      if (response.getTransports) body.response.transports = response.getTransports();
      return api.post('/api/users/me/passkeys/verify', body);
    }).then(function(r) {
      btn.disabled = false;
      if (!r) return;
      if (r.ok) {
        status.textContent = 'Passkey registered!';
        status.style.color = 'var(--success)';
        loadPasskeys();
      } else {
        status.textContent = (r.error && r.error.message) || 'Verification failed.';
        status.style.color = 'var(--danger)';
      }
    }).catch(function(err) {
      btn.disabled = false;
      if (err.name === 'NotAllowedError') {
        status.textContent = 'Registration cancelled.';
      } else {
        status.textContent = 'Error: ' + (err.message || 'Unknown');
      }
      status.style.color = 'var(--danger)';
    });
  };

  // Load sessions
  api.get('/api/users/me/sessions').then(function(r) {
    var el = container.querySelector('#session-list');
    if (!r.ok || !r.data || r.data.length === 0) {
      el.innerHTML = '<div style="color:var(--t2);font-size:13px;padding:8px 0">No active sessions.</div>';
      return;
    }
    el.innerHTML = '<table class="tbl"><thead><tr><th>Device</th><th>Last active</th><th>Created</th><th></th></tr></thead><tbody>' +
      r.data.map(function(s) {
        var info = typeof s.device_info === 'object' && s.device_info ? (s.device_info.ua || s.device_info.type || 'Session') : (s.device_info || 'Session');
        if (typeof info === 'object') info = 'Session';
        return '<tr><td>' + info + '</td><td>' + new Date(s.last_active_at).toLocaleString() + '</td><td>' + new Date(s.created_at).toLocaleString() + '</td><td><button class="btn danger btn-revoke-session" data-id="' + s.id + '" style="padding:4px 10px;font-size:12px">Revoke</button></td></tr>';
      }).join('') + '</tbody></table>';
    el.querySelectorAll('.btn-revoke-session').forEach(function(btn) {
      btn.onclick = function() {
        if (!confirm('Revoke this session?')) return;
        api.delete('/api/users/me/sessions/' + btn.getAttribute('data-id')).then(function(r2) {
          if (r2.ok) btn.closest('tr').remove();
        });
      };
    });
  });


  // ── Notification Preferences ──
  var notifEl = container.querySelector('#notif-prefs');
  if (notifEl) {
    api.get('/api/users/me/settings').then(function(r) {
      var prefs = (r.ok && r.data) ? r.data : {};
      var items = [
        { key: 'notify_calls', label: 'Support call alerts', desc: 'Get notified when a customer needs support', default: true },
        { key: 'notify_inbox', label: 'Inbox messages', desc: 'Get notified when you receive a new message', default: true }
      ];
      notifEl.innerHTML = items.map(function(item) {
        var isOn = prefs[item.key] !== undefined ? prefs[item.key] !== false : item.default;
        return '<div style="display:flex;align-items:center;justify-content:space-between;padding:12px 0;border-bottom:1px solid var(--bdr)">' +
          '<div><div style="font-size:14px;font-weight:500;color:var(--t1)">' + item.label + '</div>' +
          '<div style="font-size:12px;color:var(--t3);margin-top:2px">' + item.desc + '</div></div>' +
          '<label class="notif-toggle" style="position:relative;width:44px;height:24px;flex-shrink:0;cursor:pointer">' +
          '<input type="checkbox" data-key="' + item.key + '"' + (isOn ? ' checked' : '') + ' style="opacity:0;width:0;height:0;position:absolute">' +
          '<span style="position:absolute;top:0;left:0;right:0;bottom:0;background:' + (isOn ? 'var(--acc)' : 'var(--bg3)') + ';border-radius:12px;transition:background .2s"></span>' +
          '<span style="position:absolute;top:2px;' + (isOn ? 'left:22px' : 'left:2px') + ';width:20px;height:20px;background:#fff;border-radius:50%;transition:left .2s;box-shadow:0 1px 3px rgba(0,0,0,.3)"></span>' +
          '</label></div>';
      }).join('');
      notifEl.querySelectorAll('input[type="checkbox"]').forEach(function(cb) {
        cb.onchange = function() {
          var key = this.getAttribute('data-key');
          var isOn = this.checked;
          var track = this.nextElementSibling;
          var knob = track.nextElementSibling;
          track.style.background = isOn ? 'var(--acc)' : 'var(--bg3)';
          knob.style.left = isOn ? '22px' : '2px';
          var update = {};
          update[key] = isOn;
          api.patch('/api/users/me/settings', update).then(function(r) {
            if (r.ok && window.__xrayToast) window.__xrayToast('Notification preference saved', 'success');
          });
        };
      });
    });
  }
}

