function initBilling(container, api, user) {
  // Block access for users without billing permission
  if (user && !user.is_owner && !user.is_platform_admin && !user.has_billing) {
    container.innerHTML = '<div style="text-align:center;padding:60px 20px;color:var(--t3);font-size:14px"><p>You do not have billing permissions.</p><p style="margin-top:8px">Contact your account owner to request access.</p></div>';
    return;
  }
  var loading = container.querySelector('#billing-loading');
  var content = container.querySelector('#billing-content');
  var statusEl = container.querySelector('#billing-status');
  var portalLink = container.querySelector('#billing-portal-link');

  // Auto-refresh billing status when user returns to this tab (e.g. after Stripe checkout)
  var wasHidden = false;
  document.addEventListener('visibilitychange', function billingVis() {
    if (document.hidden) {
      wasHidden = true;
    } else if (wasHidden) {
      wasHidden = false;
      // User came back to this tab — refresh billing status (they may have just paid)
      api.get('/api/stripe/status').then(function(r) {
        if (r.ok && r.data) renderStatus(r.data);
      });
    }
  });

  // Load billing status
  api.get('/api/stripe/status').then(function(r) {
    loading.style.display = 'none';
    content.style.display = '';
    if (r.ok && r.data) renderStatus(r.data);
    renderStripePricingTable();
    loadInvoices();
    // Load portal URL from settings
    api.get('/api/stripe/config').then(function(cr) {
      if (cr.ok && cr.data && cr.data.portalUrl && portalLink) {
        portalLink.href = cr.data.portalUrl;
      }
    }).catch(function() {});
  }).catch(function() {
    loading.style.display = 'none';
    content.style.display = '';
    renderStripePricingTable();
    loadInvoices();
  });

  function renderStatus(data) {
    if (!statusEl) return;
    var hasActive = data.subscriptions && data.subscriptions.some(function(s) { return s.status === 'active' || s.status === 'trialing'; });
    if (data.billingOverride) {
      statusEl.innerHTML = '<div class="billing-badge active">Plan: Unlimited (Override)</div>';
      return;
    }
    if (!hasActive && data.plan === 'free') {
      statusEl.innerHTML = '<div class="billing-badge free">No active subscription</div>';
      return;
    }
    var html = '';
    if (data.subscriptions) {
      data.subscriptions.forEach(function(s) {
        var statusClass = s.status === 'active' ? 'active' : s.status === 'trialing' ? 'trialing' : 'inactive';
        var ends = s.currentPeriodEnd ? ' &middot; Renews ' + new Date(s.currentPeriodEnd).toLocaleDateString() : '';
        var cancel = s.cancelAtPeriodEnd ? ' &middot; <span style="color:var(--danger)">Cancels at period end</span>' : '';
        html += '<div class="billing-badge ' + statusClass + '">' + escHtml(s.productName) + ' &middot; ' + s.status + ends + cancel + '</div>';
      });
    }
    statusEl.innerHTML = html || '<div class="billing-badge free">Free plan</div>';
    // Show manage subscription link when there's an active subscription
    // Portal link is always visible for users to manage their Stripe account
  }

  function renderStripePricingTable() {
    var embed = container.querySelector('#stripe-pricing-embed');
    if (!embed) return;
    api.get('/api/stripe/config').then(function(r) {
      if (!r.ok || !r.data || !r.data.publishableKey || !r.data.pricingTableId) {
        embed.innerHTML = '<div style="color:var(--t3);font-size:14px;padding:20px 0">Stripe billing is not configured yet.</div>';
        return;
      }
      if (!document.querySelector('script[src*="pricing-table"]')) {
        var script = document.createElement('script');
        script.async = true;
        script.src = 'https://js.stripe.com/v3/pricing-table.js';
        document.head.appendChild(script);
      }
      var attrs = 'pricing-table-id="' + escHtml(r.data.pricingTableId) + '" publishable-key="' + escHtml(r.data.publishableKey) + '"';
      if (user && user.email) attrs += ' customer-email="' + escHtml(user.email) + '"';
      if (user && user.tenant_id) attrs += ' client-reference-id="' + escHtml(user.tenant_id) + '"';
      embed.innerHTML = '<stripe-pricing-table ' + attrs + '></stripe-pricing-table>';
    }).catch(function() {
      embed.innerHTML = '<div style="color:var(--t3);font-size:14px;padding:20px 0">Could not load billing configuration.</div>';
    });
  }

  // Upload invoice
  container.querySelector('#billing-upload-btn').onclick = function() {
    var fileInput = container.querySelector('#billing-invoice-files');
    if (!fileInput.files || fileInput.files.length === 0) { alert('Select at least one file'); return; }
    var btn = this; btn.disabled = true; btn.textContent = 'Uploading...';
    var fd = new FormData();
    for (var i = 0; i < fileInput.files.length; i++) fd.append('files', fileInput.files[i]);
    fd.append('contextType', 'invoice');
    fd.append('contextId', 'billing');
    fetch('/api/uploads', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + (window.getAccessToken ? window.getAccessToken() : '') },
      body: fd,
      credentials: 'include'
    }).then(function(r) { return r.json(); }).then(function(r) {
      btn.disabled = false; btn.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg> Upload';
      if (r.ok || r.data) {
        fileInput.value = '';
        if (window.__xrayToast) window.__xrayToast('Invoice uploaded');
        loadInvoices();
      } else {
        alert('Upload failed: ' + (r.error ? r.error.message : 'Unknown error'));
      }
    }).catch(function() {
      btn.disabled = false; btn.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg> Upload';
      alert('Upload failed');
    });
  };

  function loadInvoices() {
    var list = container.querySelector('#billing-invoices-list');
    api.get('/api/uploads/context/invoice/billing').then(function(r) {
      if (!r.ok || !r.data || r.data.length === 0) {
        list.innerHTML = '<div style="color:var(--t3);font-size:13px;padding:8px 0">No invoices uploaded yet.</div>';
        return;
      }
      list.innerHTML = r.data.map(function(f) {
        var date = f.created_at ? new Date(f.created_at).toLocaleDateString() : '';
        var dlUrl = '/api/uploads/' + f.id + '/download';
        return '<div class="billing-invoice-item"><div class="inv-info"><span class="inv-name">' + escHtml(f.original_name || f.filename) + '</span><span class="inv-date">' + date + '</span></div><button class="btn sm" data-url="' + escHtml(dlUrl) + '" data-name="' + escHtml(f.original_name || f.filename) + '" data-mime="' + escHtml(f.mime_type || '') + '">View</button></div>';
      }).join('');
      list.querySelectorAll('[data-url]').forEach(function(btn) {
        btn.onclick = function() {
          if (window.__xrayOpenViewer) window.__xrayOpenViewer(this.dataset.url, this.dataset.name, this.dataset.mime);
          else window.open(this.dataset.url, '_blank');
        };
      });
    });
  }

  function escHtml(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }
}

team.js:
function initTeam(container, api, user) {
  var teamMembers = [];
  window.__xrayRefreshTeamView = function() { loadTeamMembers(); loadInvitations(); };
  var composeModal = container.querySelector('#team-compose-modal');

  function loadTeamMembers() {
  api.get('/api/users').then(function(r) {
    var tbody = container.querySelector('#team-tbody');
    var empty = container.querySelector('#team-empty');
    if (!r.ok || !r.data || r.data.length === 0) { empty.style.display = ''; tbody.parentElement.style.display = 'none'; return; }
    teamMembers = r.data;
    tbody.innerHTML = r.data.map(function(m, i) {
      var msgBtn = m.id !== user.id ? '<button class="btn sm" data-msg-idx="' + i + '" style="font-size:12px;padding:4px 10px">Message</button>' : '';
      var editBtn = (user.is_owner || user.is_platform_admin) && m.id !== user.id ? ' <button class="btn sm" data-edit-idx="' + i + '" style="font-size:12px;padding:4px 10px">Edit</button><button class="btn sm danger" data-del-idx="' + i + '" style="font-size:12px;padding:4px 10px">Remove</button>' : '';
      return '<tr style="cursor:pointer" data-row-idx="' + i + '"><td><div style="font-weight:500">' + (m.name || '-') + '</div><div style="font-size:12px;color:var(--t2)">' + m.email + '</div></td><td>' + (m.role_name || '-') + (m.has_admin ? ' <span style="display:inline-block;padding:2px 8px;font-size:11px;font-weight:600;border-radius:12px;background:rgba(59,130,246,.15);color:#3b82f6;margin-left:4px">Admin</span>' : '') + (m.has_billing ? ' <span style="display:inline-block;padding:2px 8px;font-size:11px;font-weight:600;border-radius:12px;background:rgba(168,85,247,.15);color:#a855f7;margin-left:4px">Billing</span>' : '') + (m.has_replay ? ' <span style="display:inline-block;padding:2px 8px;font-size:11px;font-weight:600;border-radius:12px;background:rgba(245,158,11,.15);color:#f59e0b;margin-left:4px">Replay</span>' : '') + '</td><td><span class="badge ' + (m.status || 'active') + '">' + (m.status || 'active') + '</span></td><td>' + (m.last_login_at ? new Date(m.last_login_at).toLocaleDateString() : 'Never') + '</td><td style="white-space:nowrap">' + msgBtn + editBtn + '</td></tr>';
    }).join('');

    tbody.querySelectorAll('[data-edit-idx]').forEach(function(btn) {
      btn.onclick = function() {
        var m = teamMembers[parseInt(this.dataset.editIdx)];
        if (!m) return;
        openEditMember(m);
      };
    });
    // Clicking anywhere on a row opens edit modal
    tbody.querySelectorAll('tr[data-row-idx]').forEach(function(row) {
      row.onclick = function(e) {
        if (e.target.closest('button')) return; // don't trigger if clicking a button
        var m = teamMembers[parseInt(this.dataset.rowIdx)];
        if (!m) return;
        openEditMember(m);
      };
    });
    tbody.querySelectorAll('[data-del-idx]').forEach(function(btn) {
      btn.onclick = function() {
        var m = teamMembers[parseInt(this.dataset.delIdx)];
        if (!m) return;
        if (!confirm('Remove ' + m.name + ' (' + m.email + ') from the team? This cannot be undone.')) return;
        api.delete('/api/users/' + m.id).then(function(dr) {
          if (!dr.ok) { alert('Failed to remove: ' + (dr.error ? dr.error.message : '')); return; }
          if (window.__xrayToast) window.__xrayToast('Member removed', 'success');
          location.reload();
        });
      };
    });
    tbody.querySelectorAll('[data-msg-idx]').forEach(function(btn) {
      btn.onclick = function() {
        var m = teamMembers[parseInt(this.dataset.msgIdx)];
        if (!m) return;
        openComposeForMember(m);
      };
    });

    // Search filter
    var searchInput = container.querySelector('#team-search');
    if (searchInput) {
      searchInput.oninput = function() {
        var q = this.value.toLowerCase();
        var rows = tbody.querySelectorAll('tr');
        rows.forEach(function(row, i) {
          var m = teamMembers[i];
          if (!m) return;
          var match = !q || (m.name || '').toLowerCase().indexOf(q) !== -1 || (m.email || '').toLowerCase().indexOf(q) !== -1 || (m.role_name || '').toLowerCase().indexOf(q) !== -1;
          row.style.display = match ? '' : 'none';
        });
        var visible = Array.from(rows).filter(function(r) { return r.style.display !== 'none'; });
        container.querySelector('#team-empty').style.display = visible.length ? 'none' : '';
      };
    }
  });

  }
  loadTeamMembers();


  function loadInvitations() {
    var invList = container.querySelector('#invite-list');
    if (!invList) return;
    // Only load if user can manage invitations
    if (!(user.is_owner || user.is_platform_admin || user.has_admin)) {
      invList.innerHTML = '';
      return;
    }
    api.get('/api/invitations').then(function(r) {
      if (!r.ok || !r.data || r.data.length === 0) {
        invList.innerHTML = '<div style="color:var(--t2);font-size:13px;padding:8px 0">No pending invitations.</div>';
        return;
      }
      invList.innerHTML = r.data.map(function(inv) {
        var statusColor = inv.status === 'pending' ? 'var(--acc)' : inv.status === 'expired' ? '#f59e0b' : 'var(--t3)';
        var date = inv.created_at ? new Date(inv.created_at).toLocaleDateString() : '';
        var expiry = inv.expires_at ? new Date(inv.expires_at).toLocaleDateString() : '';
        return '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px 12px;border:1px solid var(--bdr);border-radius:8px;margin-bottom:6px;background:var(--bg3)">'
          + '<div style="flex:1;min-width:0">'
          + '<div style="font-weight:500;color:var(--t1)">' + (inv.email || '') + '</div>'
          + '<div style="font-size:12px;color:var(--t3)">Sent ' + date + ' \u00b7 Expires ' + expiry + ' \u00b7 <span style="color:' + statusColor + '">' + (inv.status || 'pending') + '</span></div>'
          + '</div>'
          + (inv.status === 'pending' ? '<button class="btn sm" style="color:var(--danger);border-color:rgba(239,68,68,.3);font-size:12px" data-revoke-id="' + inv.id + '">Revoke</button>' : '')
          + '</div>';
      }).join('');
      invList.querySelectorAll('[data-revoke-id]').forEach(function(btn) {
        btn.onclick = function() {
          var invId = this.dataset.revokeId;
          api.delete('/api/invitations/' + invId).then(function(dr) {
            if (dr.ok) {
              if (window.__xrayToast) window.__xrayToast('Invitation revoked', 'success');
              loadInvitations();
            }
          });
        };
      });
    });
  }

  function openEditMember(member) {
    var roleModal = container.querySelector('#team-role-modal');
    var roleSelect = container.querySelector('#team-role-select');
    var modalBody = roleModal.querySelector('.modal-body');
    roleModal.querySelector('.modal-title').textContent = 'Edit member';

    // Build the full edit modal body
    modalBody.innerHTML = '<p style="font-size:14px;color:var(--t2);margin-bottom:12px">Editing: <strong style="color:var(--t1)">' + (member.name || member.email) + '</strong> <span style="font-size:13px;color:var(--t3)">' + (member.email || '') + '</span></p>'
      + '<div class="fg" style="margin-bottom:16px"><label style="display:block;font-size:13px;color:var(--t2);margin-bottom:5px">Role</label><select id="team-role-select" style="width:100%;padding:10px 14px;font-size:14px;color:var(--t1);background:var(--bg4);border:1px solid var(--bdr);border-radius:8px;font-family:var(--font);outline:0"><option value="">Loading...</option></select></div>'
      + '<div style="display:flex;gap:12px;margin-bottom:16px"><div style="flex:1"><label style="display:block;font-size:13px;color:var(--t2);margin-bottom:5px">Admin permission</label><button id="toggle-has-admin" data-on="' + (member.has_admin ? '1' : '0') + '" style="padding:6px 16px;font-size:13px;border-radius:20px;border:1px solid ' + (member.has_admin ? '#22c55e' : 'var(--bdr)') + ';background:' + (member.has_admin ? 'rgba(34,197,94,.15)' : 'var(--bg4)') + ';color:' + (member.has_admin ? '#22c55e' : 'var(--t3)') + ';cursor:pointer;font-family:var(--font);font-weight:500;transition:all .15s">' + (member.has_admin ? 'Enabled' : 'Disabled') + '</button></div><div style="flex:1"><label style="display:block;font-size:13px;color:var(--t2);margin-bottom:5px">Billing permission</label><button id="toggle-has-billing" data-on="' + (member.has_billing ? '1' : '0') + '" style="padding:6px 16px;font-size:13px;border-radius:20px;border:1px solid ' + (member.has_billing ? '#22c55e' : 'var(--bdr)') + ';background:' + (member.has_billing ? 'rgba(34,197,94,.15)' : 'var(--bg4)') + ';color:' + (member.has_billing ? '#22c55e' : 'var(--t3)') + ';cursor:pointer;font-family:var(--font);font-weight:500;transition:all .15s">' + (member.has_billing ? 'Enabled' : 'Disabled') + '</button></div><div style="flex:1"><label style="display:block;font-size:13px;color:var(--t2);margin-bottom:5px">Replay permission</label><button id="toggle-has-replay" data-on="' + (member.has_replay ? '1' : '0') + '" style="padding:6px 16px;font-size:13px;border-radius:20px;border:1px solid ' + (member.has_replay ? '#f59e0b' : 'var(--bdr)') + ';background:' + (member.has_replay ? 'rgba(245,158,11,.15)' : 'var(--bg4)') + ';color:' + (member.has_replay ? '#f59e0b' : 'var(--t3)') + ';cursor:pointer;font-family:var(--font);font-weight:500;transition:all .15s">' + (member.has_replay ? 'Enabled' : 'Disabled') + '</button></div></div>'
      + '<div class="fg" style="flex:1;display:flex;flex-direction:column;min-height:0"><label style="display:block;font-size:13px;color:var(--t2);margin-bottom:8px">Dashboard access</label><div id="edit-dash-list" style="flex:1;overflow-y:auto"><div style="color:var(--t3);font-size:13px">Loading dashboards...</div></div></div>';

    roleModal.style.display = 'flex';
    // Make modal use full height
    var modalBox = roleModal.querySelector('.modal');
    if (modalBox) { modalBox.style.height = 'calc(100vh - 70px)'; modalBox.style.maxHeight = 'calc(100vh - 70px)'; modalBox.style.display = 'flex'; modalBox.style.flexDirection = 'column'; }
    modalBody.style.flex = '1';
    modalBody.style.padding = window.innerWidth < 600 ? '12px' : '20px';
    modalBody.style.overflowY = 'auto';
    modalBody.style.minHeight = '0';
    var newRoleSelect = modalBody.querySelector('#team-role-select');
    var dashList = modalBody.querySelector('#edit-dash-list');

    // Load roles
    api.get('/api/roles/assignable').then(function(rr) {
      if (!rr.ok || !rr.data || !rr.data.length) {
        // Fallback: show basic role options
        newRoleSelect.innerHTML = '<option value="">Owner</option><option value="" selected>Member</option>';
        return;
      }
      newRoleSelect.innerHTML = (rr.data || []).map(function(rl) {
        var sel = (rl.name.toLowerCase() === (member.role_name || '').toLowerCase() || rl.slug === (member.role_name || '').toLowerCase()) ? ' selected' : '';
        return '<option value="' + rl.id + '"' + sel + '>' + rl.name + '</option>';
      }).join('');
    });

    // Load all dashboards and member's current access
    Promise.all([
      api.get('/api/dashboards'),
      api.get('/api/users/' + member.id + '/dashboard-access')
    ]).then(function(results) {
      var dashR = results[0];
      var accessR = results[1];
      var dashboards = ((dashR.ok ? dashR.data : []) || []).filter(function(d) { return !user.is_platform_admin || !d.tenant_id || d.tenant_id === member.tenant_id; });
      var accessIds = {};
      if (accessR.ok && accessR.data) {
        (accessR.data || []).forEach(function(a) { accessIds[a.dashboard_id || a.id] = true; });
      }
      if (!dashboards.length) {
        dashList.innerHTML = '<div style="color:var(--t3);font-size:13px">No dashboards available</div>';
        return;
      }
      var allGranted = dashboards.length > 0 && dashboards.every(function(d) { return !!accessIds[d.id]; });
      var allHtml = '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px 12px;border:1px solid var(--acc);border-radius:8px;margin-bottom:10px;background:rgba(62,232,181,.04)">'
        + '<div style="flex:1"><div style="font-size:14px;font-weight:600;color:var(--t1)">All Dashboards</div>'
        + '<div style="font-size:11px;color:var(--t3)">Grant access to all current and future dashboards</div></div>'
        + '<button id="dash-toggle-all" style="padding:4px 14px;font-size:12px;border-radius:20px;border:1px solid ' + (allGranted ? 'var(--acc)' : 'var(--bdr)') + ';background:' + (allGranted ? 'var(--acc-dim)' : 'var(--bg4)') + ';color:' + (allGranted ? 'var(--acc)' : 'var(--t3)') + ';cursor:pointer;font-family:var(--font);font-weight:500">' + (allGranted ? 'All Visible' : 'Grant All') + '</button></div>';
      dashList.innerHTML = allHtml + dashboards.map(function(d) {
        var hasAccess = !!accessIds[d.id];
        var detailsId = 'dash-detail-' + d.id;
        return '<div style="border:1px solid var(--bdr);border-radius:8px;margin-bottom:6px;background:var(--bg3)">'
          + '<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 10px;cursor:pointer" class="dash-row-header" data-details="' + detailsId + '">'
          + '<div style="flex:1;min-width:0"><div style="font-size:13px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + (d.name || 'Untitled') + '</div>'
          + '<div style="font-size:11px;color:var(--t3)">' + (d.status || 'draft') + '</div></div>'
          + '<button class="dash-access-toggle" data-dash-id="' + d.id + '" data-has-access="' + (hasAccess ? '1' : '0') + '" style="padding:4px 12px;font-size:12px;border-radius:20px;border:1px solid ' + (hasAccess ? 'var(--acc)' : 'var(--bdr)') + ';background:' + (hasAccess ? 'var(--acc-dim)' : 'var(--bg4)') + ';color:' + (hasAccess ? 'var(--acc)' : 'var(--t3)') + ';cursor:pointer;font-family:var(--font);font-weight:500;transition:all .15s">' + (hasAccess ? 'Visible' : 'Hidden') + '</button>'
          + '</div>'
          + '<div id="' + detailsId + '" style="display:none;padding:12px 14px;border-top:1px solid var(--bdr);font-size:12px;color:var(--t2);background:var(--bg2);border-radius:0 0 8px 8px">'
          + (d.tile_image_url ? '<img src="' + d.tile_image_url + '" style="width:100%;max-height:140px;object-fit:cover;border-radius:6px;margin-bottom:10px">' : '')
          + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px 16px">'
          + '<div><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:2px">Name</div><div style="font-weight:500;color:var(--t1)">' + (d.name || '-') + '</div></div>'
          + '<div><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:2px">Status</div><div style="color:var(--t1)">' + (d.status || 'draft') + '</div></div>'
          + '<div><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:2px">Created</div><div style="color:var(--t1)">' + (d.created_at ? new Date(d.created_at).toLocaleString() : '-') + '</div></div>'
          + '<div><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:2px">Updated</div><div style="color:var(--t1)">' + (d.updated_at ? new Date(d.updated_at).toLocaleString() : '-') + '</div></div>'
          + '<div><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:2px">Views</div><div style="color:var(--t1)">' + (d.view_count || 0) + '</div></div>'
          + (d.tenant_name ? '<div><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:2px">Tenant</div><div style="color:var(--t1)">' + d.tenant_name + '</div></div>' : '')
          + '</div>'
          + (d.description ? '<div style="margin-top:10px"><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:2px">Description</div><div style="color:var(--t1)">' + d.description + '</div></div>' : '')
          + (d.connectors && d.connectors.length ? '<div style="margin-top:10px"><div style="font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:var(--t3);margin-bottom:4px">Connectors</div>' + d.connectors.map(function(c) { return '<span style="display:inline-block;padding:2px 8px;font-size:11px;border-radius:4px;background:var(--bg3);color:var(--t2);margin-right:4px;margin-bottom:3px">' + (c.connection_name || c.source_key || '-') + '</span>'; }).join('') + '</div>' : '')
          + '</div></div>';
      }).join('');

      // Expand/collapse dashboard details on header click
      dashList.querySelectorAll('.dash-row-header').forEach(function(hdr) {
        hdr.onclick = function(e) {
          if (e.target.closest('.dash-access-toggle')) return;
          var det = dashList.querySelector('#' + this.dataset.details);
          if (det) det.style.display = det.style.display === 'none' ? '' : 'none';
        };
      });

      // Toggle ALL dashboards
      var toggleAllBtn = dashList.querySelector('#dash-toggle-all');
      if (toggleAllBtn) {
        toggleAllBtn.onclick = function() {
          var allToggles = dashList.querySelectorAll('.dash-access-toggle');
          var allVisible = Array.from(allToggles).every(function(t) { return t.dataset.hasAccess === '1'; });
          toggleAllBtn.disabled = true;
          toggleAllBtn.textContent = allVisible ? 'Revoking...' : 'Granting...';
          var promises = [];
          allToggles.forEach(function(t) {
            var dashId = t.dataset.dashId;
            var has = t.dataset.hasAccess === '1';
            if (allVisible && has) {
              promises.push(api.delete('/api/dashboards/' + dashId + '/access/' + member.id).then(function(r) {
                if (r.ok) { t.dataset.hasAccess = '0'; t.textContent = 'Hidden'; t.style.borderColor = 'var(--bdr)'; t.style.background = 'var(--bg4)'; t.style.color = 'var(--t3)'; }
              }));
            } else if (!allVisible && !has) {
              promises.push(api.post('/api/dashboards/' + dashId + '/access', { userId: member.id }).then(function(r) {
                if (r.ok) { t.dataset.hasAccess = '1'; t.textContent = 'Visible'; t.style.borderColor = 'var(--acc)'; t.style.background = 'var(--acc-dim)'; t.style.color = 'var(--acc)'; }
              }));
            }
          });
          Promise.all(promises).then(function() {
            toggleAllBtn.disabled = false;
            var nowAll = Array.from(allToggles).every(function(t) { return t.dataset.hasAccess === '1'; });
            toggleAllBtn.textContent = nowAll ? 'All Visible' : 'Grant All';
            toggleAllBtn.style.borderColor = nowAll ? 'var(--acc)' : 'var(--bdr)';
            toggleAllBtn.style.background = nowAll ? 'var(--acc-dim)' : 'var(--bg4)';
            toggleAllBtn.style.color = nowAll ? 'var(--acc)' : 'var(--t3)';
          });
        };
      }

      // Toggle dashboard access
      dashList.querySelectorAll('.dash-access-toggle').forEach(function(tog) {
        tog.onclick = function() {
          var dashId = this.dataset.dashId;
          var has = this.dataset.hasAccess === '1';
          var btn = this;
          btn.disabled = true;
          if (has) {
            api.delete('/api/dashboards/' + dashId + '/access/' + member.id).then(function(r) {
              btn.disabled = false;
              if (!r.ok) { if (window.__xrayToast) window.__xrayToast('Failed to revoke access', 'error'); return; }
              btn.dataset.hasAccess = '0';
              btn.textContent = 'Hidden';
              btn.style.borderColor = 'var(--bdr)';
              btn.style.background = 'var(--bg4)';
              btn.style.color = 'var(--t3)';
            });
          } else {
            api.post('/api/dashboards/' + dashId + '/access', { userId: member.id }).then(function(r) {
              btn.disabled = false;
              if (!r.ok) { if (window.__xrayToast) window.__xrayToast('Failed to grant access', 'error'); return; }
              btn.dataset.hasAccess = '1';
              btn.textContent = 'Visible';
              btn.style.borderColor = 'var(--acc)';
              btn.style.background = 'var(--acc-dim)';
              btn.style.color = 'var(--acc)';
            });
          }
        };
      });
    });

    // Auto-save role on change
    newRoleSelect.onchange = function() {
      var roleId = this.value;
      if (!roleId) return;
      var sel = this;
      sel.disabled = true;
      api.patch('/api/users/' + member.id, { roleId: roleId }).then(function(ur) {
        sel.disabled = false;
        if (!ur.ok) { if (window.__xrayToast) window.__xrayToast('Failed to update role', 'error'); return; }
        if (window.__xrayToast) window.__xrayToast('Role updated', 'success');
      });
    };

    // Permission toggle handlers
    function setupPermToggle(btnId, field) {
      var btn = modalBody.querySelector('#' + btnId);
      if (!btn) return;
      btn.onclick = function() {
        var isOn = btn.dataset.on === '1';
        var newVal = !isOn;
        btn.disabled = true;
        var patch = {};
        patch[field] = newVal;
        api.patch('/api/users/' + member.id, patch).then(function(r) {
          btn.disabled = false;
          if (!r.ok) { if (window.__xrayToast) window.__xrayToast('Failed to update permission', 'error'); return; }
          btn.dataset.on = newVal ? '1' : '0';
          btn.textContent = newVal ? 'Enabled' : 'Disabled';
          btn.style.borderColor = newVal ? '#22c55e' : 'var(--bdr)';
          btn.style.background = newVal ? 'rgba(34,197,94,.15)' : 'var(--bg4)';
          btn.style.color = newVal ? '#22c55e' : 'var(--t3)';
          member[field] = newVal;
          if (window.__xrayToast) window.__xrayToast('Permission updated', 'success');
          // Refresh the member list so permission badges update in real-time
          if (typeof loadTeamMembers === 'function') loadTeamMembers();
        });
      };
    }
    setupPermToggle('toggle-has-admin', 'has_admin');
    setupPermToggle('toggle-has-billing', 'has_billing');
    setupPermToggle('toggle-has-replay', 'has_replay');
  }

  function openComposeForMember(member) {
    container.querySelector('#team-compose-to').value = member.name + ' (' + member.email + ')';
    container.querySelector('#team-compose-subject').value = '';
    container.querySelector('#team-compose-body').value = '';
    container.querySelector('#team-compose-files').value = '';
    composeModal.style.display = 'flex';
    composeModal._recipientId = member.id;
    container.querySelector('#team-compose-subject').focus();
  }

  container.querySelector('#team-compose-close').onclick = function() { composeModal.style.display = 'none'; };
  container.querySelector('#team-compose-cancel').onclick = function() { composeModal.style.display = 'none'; };
  container.querySelector('#team-compose-send').onclick = function() {
    var subject = container.querySelector('#team-compose-subject').value.trim();
    var body = container.querySelector('#team-compose-body').value.trim();
    if (!subject || !body) { alert('Subject and message are required'); return; }
    var btn = this; btn.disabled = true; btn.textContent = 'Sending...';
    api.post('/api/inbox', { recipientIds: [composeModal._recipientId], subject: subject, body: body }).then(function(r) {
      btn.disabled = false; btn.textContent = 'Send';
      if (!r.ok) { alert('Failed to send'); return; }
      var filesInput = container.querySelector('#team-compose-files');
      if (filesInput.files && filesInput.files.length > 0) {
        var fd = new FormData();
        for (var i = 0; i < filesInput.files.length; i++) fd.append('files', filesInput.files[i]);
        fd.append('contextType', 'inbox');
        fd.append('contextId', r.data.threadId);
        fetch('/api/uploads', { method: 'POST', headers: { Authorization: 'Bearer ' + window.getAccessToken() }, body: fd }).catch(function() {});
      }
      composeModal.style.display = 'none';
      if (window.__xrayToast) window.__xrayToast('Message sent', 'success');
    });
  };

  container.querySelector('#team-role-close').onclick = function() { container.querySelector('#team-role-modal').style.display = 'none'; };

  var modal = container.querySelector('#invite-modal');
  var inviteBtn = container.querySelector('#btn-invite-member');
  if (!(user.is_owner || user.is_platform_admin)) { inviteBtn.style.display = 'none'; }
  inviteBtn.onclick = function() { modal.style.display = 'flex'; container.querySelector('#invite-email').value = ''; container.querySelector('#invite-email').focus(); };
  container.querySelector('#btn-cancel-invite').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#btn-send-invite').onclick = function() {
    var email = container.querySelector('#invite-email').value.trim();
    if (!email) return;
    var btn = this; btn.disabled = true;
    api.post('/api/invitations', { email: email }).then(function(r) {
      btn.disabled = false;
      if (r.ok) {
        modal.style.display = 'none';
        if (window.__xrayToast) window.__xrayToast('Invitation sent to ' + email, 'success');
        if (typeof loadTeamMembers === 'function') loadTeamMembers();
        loadInvitations();
      } else {
        var msg = (r.error && r.error.message) || 'Failed to send invitation';
        if (window.__xrayToast) window.__xrayToast(msg, 'error');
        else alert(msg);
      }
    }).catch(function() {
      btn.disabled = false;
      if (window.__xrayToast) window.__xrayToast('Network error sending invitation', 'error');
    });
  };
}

