admin_builder.js:
function initBuilder(container, api, user) {
  console.log('[XRay] initBuilder loaded, container:', !!container, 'api:', !!api);
  var tenantSel = container.querySelector('#build-tenant');
  var tenantInfo = container.querySelector('#build-tenant-info');
  var templateSel = container.querySelector('#build-template');
  var methodSel = container.querySelector('#build-method');
  var bodyGroup = container.querySelector('#build-body-group');
  var errEl = container.querySelector('#builder-err');
  var titleEl = container.querySelector('#builder-title');
  var editId = null;
  var tenants = [];
  var templates = [];

  function showErr(msg) { errEl.textContent = msg; errEl.style.display = msg ? 'block' : 'none'; if (msg) { errEl.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); console.error('[XRay Builder]', msg); } }

  // Toggle body field visibility based on method
  function toggleBody() {
    bodyGroup.style.display = methodSel.value === 'GET' ? 'none' : '';
  }
  methodSel.onchange = toggleBody;
  toggleBody();

  // Load tenants
  var tenantSearchInput = container.querySelector('#build-tenant-search');
  var tenantDropdown = container.querySelector('#build-tenant-dropdown');

  api.get('/api/admin/tenants?limit=100').then(function(r) {
    if (!r.ok) return;
    tenants = r.data.data || r.data || [];
    // Check if hash has tenant pre-selected
    var hash = location.hash;
    var tenantMatch = hash.match(/tenant=([^&]+)/);
    if (tenantMatch) { selectTenant(tenantMatch[1]); }
    else if (tenants.length === 1) { selectTenant(tenants[0].id); }
    updateTenantInfo();
  });

  function selectTenant(id) {
    var t = tenants.find(function(x) { return x.id === id; });
    if (t) {
      tenantSel.value = t.id;
      if (tenantSearchInput) tenantSearchInput.value = t.name + (t.owner_email ? ' (' + t.owner_email + ')' : '');
    }
  }

  function renderTenantDropdown(filter) {
    if (!tenantDropdown) return;
    var q = (filter || '').toLowerCase();
    var filtered = tenants.filter(function(t) {
      if (!q) return true;
      return (t.name && t.name.toLowerCase().indexOf(q) >= 0) ||
             (t.owner_email && t.owner_email.toLowerCase().indexOf(q) >= 0);
    });
    if (!filtered.length) {
      tenantDropdown.innerHTML = '<div style="padding:10px;color:var(--t3);font-size:13px">No tenants found</div>';
      tenantDropdown.style.display = '';
      return;
    }
    tenantDropdown.innerHTML = filtered.map(function(t) {
      return '<div class="tenant-dropdown-item" data-id="' + t.id + '">' +
        '<strong>' + (t.name || 'Unnamed') + '</strong>' +
        (t.owner_email ? '<span style="color:var(--t3);font-size:12px;margin-left:6px">' + t.owner_email + '</span>' : '') +
        '</div>';
    }).join('');
    tenantDropdown.style.display = '';
    tenantDropdown.querySelectorAll('.tenant-dropdown-item').forEach(function(item) {
      item.onclick = function() {
        selectTenant(this.dataset.id);
        tenantDropdown.style.display = 'none';
        updateTenantInfo();
      };
    });
  }

  if (tenantSearchInput) {
    tenantSearchInput.onfocus = function() { renderTenantDropdown(this.value); };
    tenantSearchInput.oninput = function() { renderTenantDropdown(this.value); tenantSel.value = ''; };
    document.addEventListener('mousedown', function(e) {
      if (tenantDropdown && !tenantDropdown.contains(e.target) && e.target !== tenantSearchInput) {
        tenantDropdown.style.display = 'none';
      }
    });
  }

  // Load templates
  api.get('/api/admin/connection-templates').then(function(r) {
    if (!r.ok) return;
    templates = r.data || [];
    templates.forEach(function(t) {
      var opt = document.createElement('option');
      opt.value = t.id;
      opt.textContent = t.name;
      templateSel.appendChild(opt);
    });
  });

  // Update tenant info display
  function updateTenantInfo() {
    var t = tenants.find(function(x) { return x.id === tenantSel.value; });
    tenantInfo.textContent = t ? 'Owner: ' + (t.owner_email || 'none') + ' | Members: ' + (t.member_count || 0) : '';
  }
  tenantSel.onchange = updateTenantInfo;

  // Apply template
  templateSel.onchange = function() {
    var tmpl = templates.find(function(x) { return x.id === templateSel.value; });
    if (!tmpl) return;
    if (tmpl.fetch_method) methodSel.value = tmpl.fetch_method;
    if (tmpl.fetch_url) container.querySelector('#build-url').value = tmpl.fetch_url;
    if (tmpl.fetch_headers) container.querySelector('#build-headers').value = JSON.stringify(tmpl.fetch_headers, null, 2);
    if (tmpl.fetch_body) container.querySelector('#build-body').value = JSON.stringify(tmpl.fetch_body, null, 2);
    toggleBody();
  };

  // Check if editing existing dashboard
  var hashParts = location.hash.split('?');
  var editMatch = (hashParts[1] || '').match(/edit=([^&]+)/);
  if (editMatch) {
    editId = editMatch[1];
    titleEl.textContent = 'Edit dashboard';
    api.get('/api/admin/dashboards/' + editId).then(function(r) {
      if (!r.ok) return;
      var d = r.data;
      selectTenant(d.tenant_id || '');
      container.querySelector('#build-name').value = d.name || '';
      container.querySelector('#build-desc').value = d.description || '';
      container.querySelector('#build-url').value = d.fetch_url || '';
      methodSel.value = d.fetch_method || 'GET';
      container.querySelector('#build-headers').value = d.fetch_headers ? JSON.stringify(d.fetch_headers, null, 2) : '{}';
      container.querySelector('#build-body').value = d.fetch_body ? JSON.stringify(d.fetch_body, null, 2) : '';
      if (d.fetch_query_params) {
        var qpEl = container.querySelector('#build-query-params');
        if (qpEl) qpEl.value = JSON.stringify(d.fetch_query_params, null, 2);
      }
      // Extract auth token from headers if present
      if (d.fetch_headers && d.fetch_headers.Authorization) {
        var authEl = container.querySelector('#build-auth-token');
        if (authEl) {
          var authVal = d.fetch_headers.Authorization;
          if (authVal.indexOf('Bearer ') === 0) authVal = authVal.substring(7);
          authEl.value = authVal;
        }
      }
      container.querySelector('#build-status').value = d.status || 'draft';
      container.querySelector('#build-tile-image').value = d.tile_image_url || '';
      toggleBody();
      updateTenantInfo();
    });
  }

  // Save
  var saveBtn = container.querySelector('#build-save');
  console.log('[XRay] Save button element:', saveBtn);
  if (!saveBtn) { console.error('[XRay] #build-save not found!'); return; }
  saveBtn.onclick = function() {
    console.log('[XRay] Save clicked');
    var tenant = tenantSel.value;
    var name = container.querySelector('#build-name').value.trim();
    var url = container.querySelector('#build-url').value.trim();
    if (!tenant) { showErr('Please select a tenant.'); return; }
    if (!name) { showErr('Dashboard name is required.'); return; }
    showErr('');

    var headers = {};
    var body = null;
    try {
      var hVal = container.querySelector('#build-headers').value.trim();
      if (hVal) headers = JSON.parse(hVal);
    } catch(e) { showErr('Headers must be valid JSON.'); return; }
    try {
      var bVal = container.querySelector('#build-body').value.trim();
      if (bVal) body = JSON.parse(bVal);
    } catch(e) { showErr('Body must be valid JSON.'); return; }

    // Handle auth bearer token -> merge into headers
    var authToken = (container.querySelector('#build-auth-token') || {}).value || '';
    if (authToken.trim()) {
      headers['Authorization'] = 'Bearer ' + authToken.trim();
    }

    // Handle query params
    var queryParams = null;
    try {
      var qVal = (container.querySelector('#build-query-params') || {}).value || '';
      if (qVal.trim() && qVal.trim() !== '{}') queryParams = JSON.parse(qVal);
    } catch(e) { showErr('Query parameters must be valid JSON.'); return; }

    var payload = {
      name: name,
      description: container.querySelector('#build-desc').value.trim() || undefined,
      fetchMethod: methodSel.value,
      fetchUrl: url || undefined,
      fetchHeaders: headers,
      fetchBody: body,
      fetchQueryParams: queryParams,
      status: container.querySelector('#build-status').value,
      tileImageUrl: container.querySelector('#build-tile-image').value.trim() || undefined,
    };
    if (!editId) payload.tenantId = tenant;

    var btn = this;
    btn.disabled = true;
    var req = editId
      ? api.patch('/api/admin/dashboards/' + editId, payload)
      : api.post('/api/admin/dashboards', payload);

    req.then(function(r) {
      btn.disabled = false;
      if (!r.ok) { showErr((r.error && r.error.message) || 'Save failed.'); return; }
      location.hash = 'admin_dashboards';
    }).catch(function(e) { btn.disabled = false; console.error('[XRay] Save error:', e); showErr('Network error: ' + (e.message || e)); });
  };

  // Preview
  container.querySelector('#build-preview').onclick = function() {
    var url = container.querySelector('#build-url').value.trim();
    if (!url && !editId) { showErr('Enter a connection URL to preview.'); return; }
    showErr('');
    var area = container.querySelector('#build-preview-area');
    var content = container.querySelector('#build-preview-content');
    area.style.display = '';
    content.innerHTML = '<div style="color:var(--t3)">Fetching...</div>';

    if (editId) {
      api.post('/api/admin/dashboards/' + editId + '/fetch', {}).then(function(r) {
        if (!r.ok) { content.innerHTML = '<div style="color:var(--err)">Error: ' + ((r.error && r.error.message) || 'Fetch failed') + '</div>'; return; }
        renderPreview(content, r.data);
      }).catch(function() { content.innerHTML = '<div style="color:var(--err)">Network error</div>'; });
    } else {
      content.innerHTML = '<div style="color:var(--t3)">Save the dashboard first to test the connection.</div>';
    }
  };

  function renderPreview(el, data) {
    if (data.html) {
      el.innerHTML = '<div style="color:var(--acc);margin-bottom:8px">Connection successful</div><pre style="white-space:pre-wrap;font-size:12px;max-height:300px;overflow:auto">' + escHtml(data.html.substring(0, 2000)) + '</pre>';
    } else {
      el.innerHTML = '<div style="color:var(--acc);margin-bottom:8px">Connection successful</div><pre style="white-space:pre-wrap;font-size:12px;max-height:300px;overflow:auto">' + escHtml(JSON.stringify(data, null, 2).substring(0, 2000)) + '</pre>';
    }
  }

  function escHtml(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  // Save as template
  container.querySelector('#build-save-template').onclick = function() {
    var name = prompt('Template name:');
    if (!name) return;
    var headers = {};
    var body = null;
    try {
      var hVal = container.querySelector('#build-headers').value.trim();
      if (hVal) headers = JSON.parse(hVal);
    } catch(e) { showErr('Headers must be valid JSON.'); return; }
    try {
      var bVal = container.querySelector('#build-body').value.trim();
      if (bVal) body = JSON.parse(bVal);
    } catch(e) { showErr('Body must be valid JSON.'); return; }

    api.post('/api/admin/connection-templates', {
      name: name,
      fetchMethod: methodSel.value,
      fetchUrl: container.querySelector('#build-url').value.trim() || undefined,
      fetchHeaders: headers,
      fetchBody: body,
      fetchQueryParams: queryParams,
    }).then(function(r) {
      if (!r.ok) { showErr('Failed to save template.'); return; }
      var opt = document.createElement('option');
      opt.value = r.data.id;
      opt.textContent = r.data.name;
      templateSel.appendChild(opt);
      templateSel.value = r.data.id;
      showErr('');
      alert('Template saved!');
    });
  };
}

admin_settings.js:
function initSettings(container, api, user) {
  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok || !r.data) return;
    var settings = {};
    (r.data || []).forEach(function(s) { settings[s.key] = s.value; });
    var billingOverride = container.querySelector('#set-billing-override');
    var signupEnabled = container.querySelector('#set-signup-enabled');
    if (billingOverride) billingOverride.checked = settings['billing_override'] === 'true';
    if (signupEnabled) signupEnabled.checked = settings['signup_enabled'] !== 'false';
  });
  window.saveToggles = function() {
    var updates = {
      billing_override: container.querySelector('#set-billing-override').checked ? 'true' : 'false',
      signup_enabled: container.querySelector('#set-signup-enabled').checked ? 'true' : 'false'
    };
    api.patch('/api/admin/settings', updates).then(function(r) {
      if (r.ok) { if (window.__xrayToast) window.__xrayToast('Settings saved', 'success'); }
      else { alert('Failed to save'); }
    });
  };
  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    var s = r.data || {};
    var el = function(id) { return container.querySelector('#' + id); };
    if (el('set-smtp-host')) el('set-smtp-host').value = s.smtp_host || '';
    if (el('set-smtp-port')) el('set-smtp-port').value = s.smtp_port || '';
    if (el('set-smtp-user')) el('set-smtp-user').value = s.smtp_user || '';
    if (el('set-smtp-from')) el('set-smtp-from').value = s.smtp_from || '';
    if (el('set-name')) el('set-name').value = s['platform.name'] || '';
    if (el('set-support')) el('set-support').value = s['platform.support_email'] || '';
    if (el('set-domain')) el('set-domain').value = s['platform.domain'] || '';
    if (el('set-share-domain')) el('set-share-domain').value = s['platform.share_domain'] || '';
    if (el('set-stripe-pk')) el('set-stripe-pk').value = s.stripe_publishable_key || '';
    if (el('set-stripe-table')) el('set-stripe-table').value = s.stripe_pricing_table_id || '';
  });

  window.saveSmtp = function() {
    var el = function(id) { return container.querySelector('#' + id); };
    var updates = { smtp_host: el('set-smtp-host').value, smtp_port: el('set-smtp-port').value, smtp_user: el('set-smtp-user').value, smtp_from: el('set-smtp-from').value };
    var pass = el('set-smtp-pass').value;
    if (pass) updates.smtp_pass = pass;
    api.patch('/api/admin/settings', updates).then(function(r) {
      alert(r.ok ? 'SMTP settings saved.' : (r.error && r.error.message) || 'Failed');
    });
  };

  window.testSmtp = function() {
    var email = prompt('Send test email to:');
    if (!email) return;
    api.post('/api/admin/test-email', { to: email }).then(function(r) {
      alert(r.ok ? 'Test email sent!' : (r.error && r.error.message) || 'Failed');
    });
  };

  window.savePlatform = function() {
    var el = function(id) { return container.querySelector('#' + id); };
    api.patch('/api/admin/settings', {
      'platform.name': el('set-name').value,
      'platform.support_email': el('set-support').value,
      'platform.domain': el('set-domain').value,
      'platform.share_domain': el('set-share-domain').value
    }).then(function(r) {
      alert(r.ok ? 'Platform settings saved.' : (r.error && r.error.message) || 'Failed');
    });
  };

  window.saveStripe = function() {
    var el = function(id) { return container.querySelector('#' + id); };
    api.patch('/api/admin/settings', {
      stripe_publishable_key: el('set-stripe-pk').value,
      stripe_pricing_table_id: el('set-stripe-table').value
    }).then(function(r) {
      alert(r.ok ? 'Stripe config saved.' : (r.error && r.error.message) || 'Failed');
    });
  };
}

admin_meet.js:
function initAdminMeet(container, api, user) {
  var urlInput = container.querySelector('#meet-server-url');
  var keyInput = container.querySelector('#meet-api-key');
  var statusEl = container.querySelector('#meet-status');
  var apiHintEl = container.querySelector('#meet-api-url-hint');

  function updateApiHint() {
    var url = urlInput.value.trim().replace(/\/+$/, '');
    if (!url) { apiHintEl.textContent = ''; return; }
    try {
      var u = new URL(url);
      var apiHost = 'api.' + u.hostname;
      apiHintEl.innerHTML = 'API URL (auto-derived): <strong>' + u.protocol + '//' + apiHost + '</strong>';
    } catch(e) { apiHintEl.textContent = ''; }
  }
  urlInput.oninput = updateApiHint;

  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    var settings = r.data || [];
    settings.forEach(function(s) {
      if (s.key === 'meet_server_url') urlInput.value = s.value || '';
      if (s.key === 'meet_api_key' && s.value && s.value !== '') keyInput.placeholder = 'Key configured (enter new to change)';
    });
    updateApiHint();
  });

  container.querySelector('#btn-save-meet').onclick = function() {
    var url = urlInput.value.trim().replace(/\/+$/, '');
    var key = keyInput.value.trim();
    var updates = {};
    if (url) updates.meet_server_url = url;
    if (key) updates.meet_api_key = key;
    if (Object.keys(updates).length === 0) { statusEl.textContent = 'Enter at least one field to update.'; statusEl.className = 'meet-status err'; return; }
    api.patch('/api/admin/settings', updates).then(function(r) {
      if (r.ok) {
        statusEl.textContent = 'MEET settings saved successfully. The call button will appear shortly.';
        statusEl.className = 'meet-status ok';
        if (typeof window.__xrayRefreshMeetWidget === 'function') window.__xrayRefreshMeetWidget();
      } else {
        statusEl.textContent = 'Failed to save: ' + (r.error ? r.error.message : 'Unknown error');
        statusEl.className = 'meet-status err';
      }
    });
  };

  container.querySelector('#btn-test-meet').onclick = function() {
    statusEl.innerHTML = '<span style="color:var(--t2)">Testing connection...</span>';
    statusEl.className = 'meet-status';
    api.post('/api/meet/test-connection', {}).then(function(r) {
      if (!r.ok) {
        statusEl.textContent = 'Test failed: ' + (r.error ? r.error.message : 'Unknown error');
        statusEl.className = 'meet-status err';
        return;
      }
      var d = r.data;
      var html = '';
      if (d.success) {
        html = '<div style="color:#059669;font-weight:600;margin-bottom:8px">Connection successful!</div>';
        html += '<div style="font-size:12px;color:var(--t2)">Working API URL: <strong style="color:var(--acc)">' + d.workingUrl + '</strong></div>';
      } else {
        html = '<div style="color:#dc2626;font-weight:600;margin-bottom:8px">Connection failed</div>';
        html += '<div style="font-size:12px;color:var(--t3);margin-bottom:4px">The server could not reach the MEET API. Make sure the API subdomain DNS is configured.</div>';
      }
      html += '<div style="margin-top:8px;font-size:12px">';
      html += '<div style="color:var(--t3);margin-bottom:4px">Connection attempts:</div>';
      (d.attempts || []).forEach(function(a) {
        var icon = a.ok ? '<span style="color:#059669">&#x2713;</span>' : '<span style="color:#dc2626">&#x2717;</span>';
        html += '<div style="padding:4px 0;border-bottom:1px solid var(--bdr)">' + icon + ' <strong>' + a.url + '</strong><br><span style="color:var(--t3);font-size:11px;margin-left:18px">' + a.status + '</span></div>';
      });
      html += '</div>';
      statusEl.innerHTML = html;
      statusEl.className = 'meet-status';
    }).catch(function() {
      statusEl.textContent = 'Network error testing connection';
      statusEl.className = 'meet-status err';
    });
  };


  // XRay Support webhook config
  var supportToggle = container.querySelector('#support-webhook-enabled');
  var supportUrlGroup = container.querySelector('#support-webhook-url-group');
  var supportUrlInput = container.querySelector('#support-webhook-url');
  var supportStatusEl = container.querySelector('#support-status');

  if (supportToggle) {
    supportToggle.onchange = function() {
      if (supportUrlGroup) supportUrlGroup.style.display = this.checked ? '' : 'none';
    };
  }

  // Load support settings
  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    var settings = r.data || [];
    if (Array.isArray(settings)) {
      settings.forEach(function(s) {
        if (s.key === 'support_webhook_enabled' && s.value === 'true') {
          if (supportToggle) { supportToggle.checked = true; if (supportUrlGroup) supportUrlGroup.style.display = ''; }
        }
        if (s.key === 'support_webhook_url' && s.value) {
          if (supportUrlInput) supportUrlInput.value = s.value;
        }
      });
    } else {
      if (settings.support_webhook_enabled === 'true') {
        if (supportToggle) { supportToggle.checked = true; if (supportUrlGroup) supportUrlGroup.style.display = ''; }
      }
      if (settings.support_webhook_url) {
        if (supportUrlInput) supportUrlInput.value = settings.support_webhook_url;
      }
    }
  });

  // Support call config elements
  var supportEnabled = container.querySelector('#support-enabled');
  var ringDuration = container.querySelector('#support-ring-duration');
  var soundEnabled = container.querySelector('#support-sound-enabled');
  var vibrationEnabled = container.querySelector('#support-vibration-enabled');
  var activeHoursEnabled = container.querySelector('#support-active-hours-enabled');
  var activeHoursStart = container.querySelector('#support-active-hours-start');
  var activeHoursEnd = container.querySelector('#support-active-hours-end');
  var hoursGroup = container.querySelector('#support-hours-group');
  var hoursEndGroup = container.querySelector('#support-hours-end-group');

  if (activeHoursEnabled) {
    activeHoursEnabled.onchange = function() {
      var show = this.checked ? '' : 'none';
      if (hoursGroup) hoursGroup.style.display = show;
      if (hoursEndGroup) hoursEndGroup.style.display = show;
    };
  }

  // Load support call config
  api.get('/api/meet/support-config').then(function(r) {
    if (!r.ok || !r.data) return;
    var c = r.data;
    if (supportEnabled) supportEnabled.checked = c.enabled !== false;
    if (ringDuration) ringDuration.value = c.ring_duration || 120;
    if (soundEnabled) soundEnabled.checked = c.sound_enabled !== false;
    if (vibrationEnabled) vibrationEnabled.checked = c.vibration_enabled !== false;
    var soundSelect = container.querySelector('#support-sound-select');
    if (soundSelect && c.sound) soundSelect.value = c.sound;
    if (activeHoursEnabled) {
      activeHoursEnabled.checked = !!c.active_hours_enabled;
      if (c.active_hours_enabled) {
        if (hoursGroup) hoursGroup.style.display = '';
        if (hoursEndGroup) hoursEndGroup.style.display = '';
      }
    }
    if (activeHoursStart && c.active_hours_start) activeHoursStart.value = c.active_hours_start;
    if (activeHoursEnd && c.active_hours_end) activeHoursEnd.value = c.active_hours_end;
  }).catch(function() {});

  var saveSupportBtn = container.querySelector('#btn-save-support');
  if (saveSupportBtn) {
    saveSupportBtn.onclick = function() {
      var updates = {
        support_webhook_enabled: supportToggle && supportToggle.checked ? 'true' : 'false',
        support_webhook_url: supportUrlInput ? supportUrlInput.value.trim() : '',
        support_enabled: supportEnabled && supportEnabled.checked ? 'true' : 'false',
        support_ring_duration: ringDuration ? String(ringDuration.value) : '120',
        support_sound_enabled: soundEnabled && soundEnabled.checked ? 'true' : 'false',
        support_vibration_enabled: vibrationEnabled && vibrationEnabled.checked ? 'true' : 'false',
        support_active_hours_enabled: activeHoursEnabled && activeHoursEnabled.checked ? 'true' : 'false',
        support_active_hours_start: activeHoursStart ? activeHoursStart.value : '00:00',
        support_active_hours_end: activeHoursEnd ? activeHoursEnd.value : '23:59',
        support_sound: container.querySelector('#support-sound-select') ? container.querySelector('#support-sound-select').value : 'classic'
      };
      api.patch('/api/admin/settings', updates).then(function(r) {
        if (r.ok) {
          if (supportStatusEl) { supportStatusEl.textContent = 'Support settings saved.'; supportStatusEl.className = 'meet-status ok'; }
        } else {
          if (supportStatusEl) { supportStatusEl.textContent = 'Failed to save.'; supportStatusEl.className = 'meet-status err'; }
        }
      });
    };
  }

  // Preview sound button
  var previewBtn = container.querySelector('#btn-preview-sound');
  if (previewBtn) {
    previewBtn.onclick = function() {
      var soundName = (container.querySelector('#support-sound-select') || {}).value || 'classic';
      try {
        var ctx = new (window.AudioContext || window.webkitAudioContext)();
