function initDashboardList(container, api, user) {
  var grid = container.querySelector('#dashboards-grid');
  var empty = container.querySelector('#dashboards-empty');
  var viewer = container.querySelector('#dashboard-viewer');
  var headerTitle = document.getElementById('header-center-title');
  var sidebar = document.getElementById('sidebar');
  var banner = container.querySelector('#dashboard-sub-banner');
  var addSlotBtn = container.querySelector('#btn-add-dash-slot');
  var searchInput = container.querySelector('#dash-search');
  var isPlatformAdmin = user && user.is_platform_admin;

  var VISION_PRODUCT = 'prod_UB9nZ8qktPbtyi';

  function showViewLogModal(dashboardId, dashName) {
    var modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.style.zIndex = '9002';
    modal.innerHTML = '<div class="modal" style="width:500px"><div class="modal-head"><div class="modal-title">View log: ' + escHtml(dashName || '') + '</div><button class="modal-close" id="_vl-close">&times;</button></div><div class="modal-body"><div id="_vl-list" style="max-height:400px;overflow-y:auto"><div style="color:var(--t3);font-size:13px;text-align:center;padding:20px">Loading...</div></div></div></div>';
    document.body.appendChild(modal);
    modal.querySelector('#_vl-close').onclick = function() { modal.remove(); };
    modal.onclick = function(e) { if (e.target === modal) modal.remove(); };

    api.get('/api/dashboards/' + dashboardId + '/views').then(function(r) {
      var list = modal.querySelector('#_vl-list');
      if (!r.ok || !r.data || !r.data.length) {
        list.innerHTML = '<div style="color:var(--t3);font-size:13px;text-align:center;padding:20px">No views recorded</div>';
        return;
      }
      list.innerHTML = '<table class="tbl" style="font-size:13px"><thead><tr><th>User</th><th>Viewed at</th></tr></thead><tbody>' + r.data.map(function(v) {
        return '<tr><td><div style="font-weight:500">' + escHtml(v.name || v.email || '-') + '</div>' + (v.name && v.email ? '<div style="font-size:11px;color:var(--t3)">' + escHtml(v.email) + '</div>' : '') + '</td><td style="white-space:nowrap">' + fmtDateTime(v.viewed_at) + '</td></tr>';
      }).join('') + '</tbody></table>';
    }).catch(function() {
      modal.querySelector('#_vl-list').innerHTML = '<div style="color:var(--danger);font-size:13px;text-align:center;padding:20px">Failed to load view log</div>';
    });
  }

  function showDashDeleteConfirm(d, parentOverlay) {
    var modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.style.zIndex = '9001';
    modal.innerHTML = '<div class="modal" style="width:420px"><div class="modal-head"><div class="modal-title">Delete dashboard</div><button class="modal-close" id="_del-dash-close">&times;</button></div><div class="modal-body"><p style="font-size:14px;color:var(--t2)">Delete <strong style="color:var(--t1)">' + escHtml(d.name) + '</strong>? This cannot be undone.</p></div><div class="modal-foot"><button class="btn" id="_del-dash-cancel">Cancel</button><button class="btn danger" id="_del-dash-confirm">Delete</button></div></div>';
    document.body.appendChild(modal);
    modal.querySelector('#_del-dash-close').onclick = function() { modal.remove(); };
    modal.querySelector('#_del-dash-cancel').onclick = function() { modal.remove(); };
    modal.querySelector('#_del-dash-confirm').onclick = function() {
      var btn = this; btn.disabled = true; btn.textContent = 'Deleting...';
      api.delete('/api/admin/dashboards/' + d.id).then(function(r) {
        btn.disabled = false; btn.textContent = 'Delete';
        modal.remove();
        if (!r.ok) { if (window.__xrayToast) window.__xrayToast(r.error ? r.error.message : 'Failed to delete', 'error'); return; }
        if (parentOverlay) parentOverlay.remove();
        if (window.__xrayToast) window.__xrayToast('Dashboard deleted', 'success');
        loadDashboards();
      });
    };
    modal.onclick = function(e) { if (e.target === modal) modal.remove(); };
  }

  function showSubModal() {
    var existing = document.getElementById('sub-required-modal');
    if (existing) { existing.style.display = 'flex'; return; }
    var overlay = document.createElement('div');
    overlay.id = 'sub-required-modal';
    overlay.className = 'modal-overlay';
    overlay.style.display = 'flex';
    overlay.innerHTML = '<div class="modal" style="width:420px;max-width:90vw;max-height:90vh;overflow-y:auto">'
      + '<div class="modal-head"><div class="modal-title">Subscription required</div><button class="modal-close" id="sub-modal-close">&times;</button></div>'
      + '<div class="modal-body" style="text-align:center;padding:24px">'
      + '<svg viewBox="0 0 24 24" width="48" height="48" stroke="var(--acc)" fill="none" stroke-width="1.5" style="margin:0 auto 16px"><path d="M12 2L2 7l10 5 10-5-10-5z"/><path d="M2 17l10 5 10-5"/><path d="M2 12l10 5 10-5"/></svg>'
      + '<h3 style="margin-bottom:8px;color:var(--t1)">XRay Vision Required</h3>'
      + '<p style="color:var(--t2);font-size:14px;margin-bottom:20px">An XRay Vision subscription is required to open dashboards. Subscribe to unlock full dashboard access.</p>'
      + '<div style="display:flex;gap:8px;justify-content:center">'
      + '<button class="btn" id="sub-modal-cancel">Cancel</button>'
      + '<button class="btn primary" id="sub-modal-subscribe">Subscribe now</button>'
      + '</div></div></div>';
    document.body.appendChild(overlay);

    // Load dashboard replays
    (function loadDashReplays() {
      var rList = overlay.querySelector('#dd-replays-list');
      if (!rList) return;
      api.get('/api/v1/replay/segments?dashboard_id=' + encodeURIComponent(dash.id) + '&limit=10').then(function(r) {
        var segs = r.ok ? (r.data && r.data.data || r.data && r.data.segments || (Array.isArray(r.data) ? r.data : [])) : [];
        if (!segs.length) { rList.innerHTML = '<div class="replay-no-data" style="padding:20px;font-size:13px;color:var(--t2)">No recordings yet</div>'; return; }
        function fmtDur(ms) { if (!ms) return '-'; var s = Math.floor(ms/1000); var m = Math.floor(s/60); s = s%60; return m+':'+(s<10?'0':'')+s; }
        var h = '<div class="replay-row replay-row-head" style="grid-template-columns:1.5fr 1fr 0.6fr 0.5fr"><div>User</div><div>Date</div><div>Duration</div><div>Clicks</div></div>';
        segs.forEach(function(seg) {
          h += '<div class="replay-row" style="grid-template-columns:1.5fr 1fr 0.6fr 0.5fr" data-seg-id="' + seg.id + '">';
          h += '<div>' + (seg.user_name||seg.user_email||'-') + '</div>';
          h += '<div>' + (seg.started_at ? new Date(seg.started_at).toLocaleDateString() : '-') + '</div>';
          h += '<div>' + fmtDur(seg.duration_ms) + '</div>';
          h += '<div>' + (seg.click_count != null ? seg.click_count : '-') + '</div></div>';
        });
        rList.innerHTML = h;
        rList.querySelectorAll('.replay-row:not(.replay-row-head)').forEach(function(row) {
          row.onclick = function() {
            overlay.remove();
            if (window.location.hash !== '#session_replay') window.location.hash = 'session_replay';
            setTimeout(function() {
              var segId = row.getAttribute('data-seg-id');
              var ev = new CustomEvent('xray-open-replay', { detail: { segmentId: segId } });
              window.dispatchEvent(ev);
            }, 500);
          };
        });
      });
    })();

    document.getElementById('sub-modal-close').onclick = function() { overlay.style.display = 'none'; };
    document.getElementById('sub-modal-cancel').onclick = function() { overlay.style.display = 'none'; };
    document.getElementById('sub-modal-subscribe').onclick = function() { overlay.style.display = 'none'; window.location.hash = 'billing'; };
    overlay.onclick = function(e) { if (e.target === overlay) overlay.style.display = 'none'; };
  }
  var DASHBOARD_PRODUCT = 'prod_UB9fsE1JmQjRgw';
  var hasVision = false;
  var dashSlots = 0;
  var allDashboards = [];

  function checkBilling() {
    if (isPlatformAdmin) { hasVision = true; dashSlots = 999; loadDashboards(); return; }
    api.get('/api/stripe/plan').then(function(r) {
      if (!r.ok) { loadDashboards(); return; }
      hasVision = r.data.hasVision;
      dashSlots = r.data.dashSlots || 0;
      if (r.data.billingOverride) { hasVision = true; dashSlots = 999; }
      if (!hasVision) {
        banner.className = 'dash-sub-banner warn';
        banner.innerHTML = '<span>An <strong>XRay Vision</strong> subscription is required to open dashboards.</span><button class="btn primary" id="btn-buy-vision" style="flex-shrink:0">Subscribe now</button>';
        banner.style.display = 'flex';
        banner.querySelector('#btn-buy-vision').onclick = function() { window.location.hash = 'billing'; };
      } else {
        // Access granted — hide banner and subscription modal if showing
        banner.style.display = 'none';
        var subModal = document.getElementById('sub-required-modal');
        if (subModal) subModal.style.display = 'none';
      }
      loadDashboards();
    }).catch(function() { loadDashboards(); });
  }

  function exitViewer() {
    viewer.classList.remove('active');
    delete viewer.dataset.dashboardId;
    if (typeof onReplaySegmentChange === 'function') onReplaySegmentChange();
    viewer.innerHTML = '';
    if (headerTitle) { headerTitle.style.display = 'none'; headerTitle.textContent = ''; }
    if (sidebar && sidebar.dataset.dashCollapsed) { sidebar.classList.remove('collapsed'); delete sidebar.dataset.dashCollapsed; }
    grid.style.display = '';
    if (!grid.children.length) empty.style.display = '';
  }

  function openDashboard(d) {
    if (d.status === 'disabled') {
      if (window.__xrayToast) window.__xrayToast('This dashboard is currently unavailable', 'error');
      return;
    }
    if (d.status !== 'active' && d.status !== 'disabled') return;
    if (!isPlatformAdmin && !hasVision) {
      showSubModal();
      return;
    }
    grid.style.display = 'none';
    empty.style.display = 'none';
    if (headerTitle) { headerTitle.textContent = d.name; headerTitle.style.display = ''; }
    if (sidebar && !sidebar.classList.contains('collapsed')) { sidebar.classList.add('collapsed'); sidebar.dataset.dashCollapsed = '1'; }
    viewer.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--t3)"><div class="spinner" style="margin-right:10px"></div> Loading dashboard...</div>';
    viewer.classList.add('active');
    viewer.dataset.dashboardId = d.id;
    if (typeof onReplaySegmentChange === 'function') onReplaySegmentChange();

    var loadTimedOut = false;
    var loadTimer = setTimeout(function() {
      loadTimedOut = true;
      if (viewer.classList.contains('active')) {
        viewer.innerHTML = '<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;color:var(--danger);gap:12px"><p>Dashboard took too long to load.</p><button class="btn" id="_dash_retry">Retry</button></div>';
        var rb = viewer.querySelector('#_dash_retry');
        if (rb) rb.onclick = function() { openDashboard(d); };
      }
    }, 30000);

    function handleRenderError(msg) {
      if (loadTimedOut) return;
      clearTimeout(loadTimer);
      viewer.innerHTML = '<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;color:var(--danger);gap:12px"><p>' + (msg || 'Failed to load dashboard.') + '</p><button class="btn" id="_dash_retry">Retry</button></div>';
      var rb = viewer.querySelector('#_dash_retry');
      if (rb) rb.onclick = function() { openDashboard(d); };
    }

    var attempts = 0;
    var maxRetries = 1;

    function tryRender() {
      attempts++;
      api.post('/api/dashboards/' + d.id + '/render', {}).then(function(r) {
        if (loadTimedOut) return;
        if (!r.ok) {
          if (attempts <= maxRetries) { setTimeout(tryRender, 3000); return; }
          clearTimeout(loadTimer);
          handleRenderError('Failed to load dashboard.');
          return;
        }
        clearTimeout(loadTimer);
        var data = r.data;
        viewer.innerHTML = '';
        try {
          var dashStyle = document.createElement('style');
          dashStyle.textContent = (data.css || '');
          viewer.appendChild(dashStyle);

          var dashContent = document.createElement('div');
          dashContent.className = 'dash-render-root';
          dashContent.style.cssText = 'width:100%;height:100%;overflow:auto;margin:0;font-family:system-ui,-apple-system,sans-serif';
          dashContent.innerHTML = (data.html || '');
          viewer.appendChild(dashContent);

          // Scripts added via innerHTML don't execute — re-create them
          dashContent.querySelectorAll('script').forEach(function(old) {
            var ns = document.createElement('script');
            if (old.src) ns.src = old.src; else ns.textContent = old.textContent;
            old.parentNode.replaceChild(ns, old);
          });

          // Execute the main dashboard JS
          if (data.js) {
            var dashScript = document.createElement('script');
            dashScript.textContent = data.js;
            viewer.appendChild(dashScript);
          }
        } catch(e) {
          handleRenderError('Error rendering dashboard.');
        }
      }).catch(function() {
        if (loadTimedOut) return;
        if (attempts <= maxRetries) { setTimeout(tryRender, 3000); return; }
        handleRenderError('Network error.');
      });
    }

    tryRender();
  }

  window.addEventListener('hashchange', function handler() {
    if (viewer.classList.contains('active') && location.hash.replace('#','').split('?')[0] !== 'dashboard_list') {
      exitViewer();
      window.removeEventListener('hashchange', handler);
    }
  });
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape' && viewer.classList.contains('active')) exitViewer();
  });

  // Search handler
  if (searchInput) {
    searchInput.addEventListener('input', function() {
      renderGrid(allDashboards);
    });
  }
  var tenantFilterEl = container.querySelector('#dash-tenant-filter');
  if (tenantFilterEl) {
    tenantFilterEl.addEventListener('change', function() {
      renderGrid(allDashboards);
    });
  }

  function loadDashboards() {
    api.get('/api/dashboards').then(function(r) {
      if (!r.ok || !r.data || r.data.length === 0) {
        allDashboards = [];
        empty.style.display = '';
        grid.style.display = 'none';
        renderAvailableSlots(0);
        return;
      }

      // Sort by updated_at descending (most recently updated first)
      allDashboards = r.data.sort(function(a, b) {
        var ta = a.updated_at || a.created_at || '';
        var tb = b.updated_at || b.created_at || '';
        return tb.localeCompare(ta);
      });

      // Render custom widgets
      var customArea = container.querySelector('#dashboard-custom-widgets');
      if (customArea) {
        var widgets = allDashboards.filter(function(d) { return d.status === 'active' && d.name && d.name.indexOf('[widget]') === 0; });
        if (widgets.length) {
          customArea.innerHTML = widgets.map(function(w, i) {
            return '<div class="dash-widget-custom" data-idx="' + i + '"><div style="padding:8px 12px;font-size:12px;color:var(--t2);border-bottom:1px solid var(--bdr)">' + w.name.replace('[widget] ','') + '</div><div class="widget-frame" data-id="' + w.id + '"></div></div>';
          }).join('');
          widgets.forEach(function(w, i) {
            var frame = customArea.querySelectorAll('.widget-frame')[i];
            if (!frame) return;
            api.post('/api/dashboards/' + w.id + '/render', {}).then(function(rr) {
              if (!rr.ok) return;
              var iframe = document.createElement('iframe');
              iframe.sandbox = 'allow-scripts allow-same-origin';
              iframe.style.cssText = 'width:100%;height:200px;border:none';
              frame.appendChild(iframe);
              try {
                var doc = iframe.contentDocument || iframe.contentWindow.document;
                doc.open();
                doc.write('<!DOCTYPE html><html><head><style>body{margin:0;font-family:system-ui,sans-serif;background:transparent;color:#f0f1f4}' + (rr.data.css||'') + '</style></head><body>' + (rr.data.html||'') + '<scr'+'ipt>' + (rr.data.js||'') + '</scr'+'ipt></body></html>');
                doc.close();
              } catch(e) {
                frame.innerHTML = '<div style="padding:16px;color:var(--danger);font-size:13px">Widget failed to load</div>';
              }
            });
          });
        }
      }

      renderGrid(allDashboards);

      // Populate tenant filter for platform admin
      if (isPlatformAdmin) {
        var tenantFilter = container.querySelector('#dash-tenant-filter');
        if (tenantFilter) {
          var tenants = {};
          allDashboards.forEach(function(d) { if (d.tenant_name) tenants[d.tenant_name] = true; });
          var tenantNames = Object.keys(tenants).sort();
          if (tenantNames.length > 1) {
            tenantFilter.style.display = '';
            var currentVal = tenantFilter.value;
            tenantFilter.innerHTML = '<option value="">All tenants</option>' + tenantNames.map(function(t) {
              return '<option value="' + t + '"' + (t === currentVal ? ' selected' : '') + '>' + t + '</option>';
            }).join('');
          }
        }
      }
    }).catch(function() {
      empty.textContent = 'Failed to load dashboards.';
      empty.style.display = '';
      grid.style.display = 'none';
    });
  }

  function renderGrid(allDash) {
    // Filter by search
    var query = (searchInput && searchInput.value || '').toLowerCase().trim();
    var tenantFilterVal = '';
    var tenantFilterEl = container.querySelector('#dash-tenant-filter');
    if (tenantFilterEl) tenantFilterVal = tenantFilterEl.value;
    var dashboards = allDash.filter(function(d) { return !d.name || d.name.indexOf('[widget]') !== 0; });
    if (tenantFilterVal) {
      dashboards = dashboards.filter(function(d) { return d.tenant_name === tenantFilterVal; });
    }
    if (query) {
      dashboards = dashboards.filter(function(d) {
        return (d.name && d.name.toLowerCase().indexOf(query) >= 0) ||
               (d.description && d.description.toLowerCase().indexOf(query) >= 0) ||
               (d.tenant_name && d.tenant_name.toLowerCase().indexOf(query) >= 0);
      });
    }

    if (!dashboards.length) {
      empty.style.display = '';
      empty.textContent = query ? 'No dashboards match your search' : 'No dashboards yet';
      grid.style.display = 'none';
      return;
    }
    empty.style.display = 'none';
    grid.style.display = '';

    var activeDashCount = dashboards.filter(function(d) { return d.status === 'active'; }).length;
    var canShare = (user && (user.is_owner || user.role === 'admin')) || isPlatformAdmin;

    grid.innerHTML = dashboards.map(function(d, i) {
      var isActive = d.status === 'active' || d.status === 'disabled';
      var isDisabled = d.status === 'disabled';
      var statusLabel = d.status || 'draft';
      var statusClass = 'status-' + (statusLabel === 'active' ? 'active' : statusLabel === 'draft' ? 'draft' : statusLabel === 'archived' ? 'archived' : statusLabel === 'disabled' ? 'disabled' : 'inactive');
      var cardClass = 'dash-card' + (isActive ? '' : isDisabled ? ' disabled-card' : ' inactive');
      var imgHtml = d.tile_image_url
        ? '<div class="dash-card-img"><img src="' + d.tile_image_url + '" alt=""></div>'
        : '<div class="dash-card-img"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1" style="width:48px;height:48px;color:var(--t3)"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg></div>';
      var tooltip = d.last_viewed_at ? 'Last viewed: ' + new Date(d.last_viewed_at).toLocaleString() : 'Not yet viewed';
      var lockHtml = '';
      if (isDisabled) {
        lockHtml = '<div class="dash-card-lock"><svg viewBox="0 0 24 24" width="12" height="12" stroke="currentColor" fill="none" stroke-width="2"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg> Currently unavailable</div>';
      } else if (!isActive) {
        lockHtml = '<div class="dash-card-lock"><svg viewBox="0 0 24 24" width="12" height="12" stroke="currentColor" fill="none" stroke-width="2"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg> ' + (statusLabel === 'draft' ? 'In development' : statusLabel === 'archived' ? 'Archived' : statusLabel === 'disabled' ? 'Currently unavailable' : 'In development') + '</div>';
      }
      var tenantHtml = isPlatformAdmin && d.tenant_name ? '<div class="dash-card-tenant">' + escHtml(d.tenant_name) + '</div>' : '';
      var connBadges = '';
      var conns = d.connectors || [];
      if (conns.length) {
        connBadges = '<div class="dash-card-connectors">' + conns.slice(0, 3).map(function(c) {
          return '<span class="dash-card-conn-badge">' + escHtml(c.connection_name || c.source_key) + '</span>';
        }).join('') + (conns.length > 3 ? '<span class="dash-card-conn-badge">+' + (conns.length - 3) + '</span>' : '') + '</div>';
      }
      var metaHtml = '<div class="dash-card-meta">';
      metaHtml += '<span><svg viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>' + fmtDate(d.created_at) + '</span>';
      metaHtml += '<span><svg viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>' + fmtDate(d.updated_at) + '</span>';
      metaHtml += '<span><svg viewBox="0 0 24 24"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>' + (d.view_count || 0) + '</span>';
      metaHtml += '</div>';
      var detailsBtn = '<button class="dash-details-btn" data-detail-idx="' + i + '">Details</button>';
      var shareBtn = isActive ? (canShare ? '<button class="dash-share-btn' + (d.is_public ? ' is-public' : '') + '" data-share-idx="' + i + '" title="' + (d.is_public ? 'Public' : 'Private') + '"><svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg></button>' : (d.is_public ? '<button class="dash-share-btn is-public dash-copy-link" data-token="' + (d.public_token || '') + '" title="Public — click to copy link"><svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg></button>' : '<span class="dash-share-btn is-internal" title="Internal only"><svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg></span>')) : '';
      return '<div class="' + cardClass + '" data-idx="' + i + '">' + shareBtn + '<span class="dash-card-status ' + statusClass + '">' + statusLabel + '</span><div class="dash-card-tooltip">' + tooltip + '</div>' + imgHtml + '<div class="dash-card-body"><h3>' + d.name + '</h3><p>' + (d.description || '') + '</p>' + tenantHtml + connBadges + metaHtml + lockHtml + '</div>' + detailsBtn + '</div>';
    }).join('');

    grid.querySelectorAll('.dash-card').forEach(function(card) {
      card.onclick = function(e) {
        if (e.target.closest('.dash-share-btn')) return;
        if (e.target.closest('.dash-details-btn')) return;
        var d = dashboards[parseInt(this.dataset.idx)];
        if (d.status === 'disabled') {
          if (window.__xrayToast) window.__xrayToast('This dashboard is currently unavailable', 'error');
          return;
        }
        if (e.target.closest('.dash-card-body')) {
          openDetailsModal(d);
          return;
        }
        if (d.status === 'active') openDashboard(d);
      };
    });

    // Non-admin copy link handler
    grid.querySelectorAll('[data-copy-share-idx]').forEach(function(btn) {
      btn.onclick = function(e) {
        e.stopPropagation();
        var idx = parseInt(this.dataset.copyShareIdx);
        var dd = dashboards[idx];
        if (!dd || !dd.share_url) return;
        navigator.clipboard.writeText(dd.share_url).then(function() {
          if (window.__xrayToast) window.__xrayToast('Share link copied!', 'success');
        }).catch(function() {
          if (window.__xrayToast) window.__xrayToast('Failed to copy link', 'error');
        });
      };
    });

    grid.querySelectorAll('.dash-share-btn[data-share-idx]').forEach(function(btn) {
      btn.onclick = function(e) {
        e.stopPropagation();
        if (this.classList.contains('dash-copy-link')) {
          var token = this.dataset.token;
          if (token) {
            var url = window.location.origin + '/share/' + token;
            navigator.clipboard.writeText(url).then(function() {
              if (window.__xrayToast) window.__xrayToast('Link copied!', 'success');
            }).catch(function() {
              if (window.__xrayToast) window.__xrayToast('Could not copy link', 'error');
            });
          }
          return;
        }
        var idx = this.dataset.shareIdx;
        if (idx == null) return;
        var d = dashboards[parseInt(idx)];
        openShareModal(d);
      };
    });

    grid.querySelectorAll('.dash-details-btn').forEach(function(btn) {
      btn.onclick = function(e) {
        e.stopPropagation();
        var d = dashboards[parseInt(this.dataset.detailIdx)];
        openDetailsModal(d);
      };
    });

    if (!query) renderAvailableSlots(activeDashCount);
  }

  function renderAvailableSlots(activeDashCount) {
    if (isPlatformAdmin) return;
    // Empty slots removed for cleaner view
    if (dashSlots < 5 && !isPlatformAdmin) {
      addSlotBtn.style.display = '';
      addSlotBtn.onclick = function() { window.location.hash = 'billing'; };
    }
  }

  function openShareModal(d) {
    api.get('/api/dashboards/' + d.id + '/share').then(function(r) {
      if (!r.ok) { alert((r.error && r.error.message) || 'Failed to get share status'); return; }
      showShareDialog(d, r.data);
    }).catch(function() { alert('Network error'); });
  }

  function showShareDialog(d, shareData) {
    var overlay = document.createElement('div');
    overlay.className = 'dash-share-modal';
    var hasLink = !!shareData.public_token;
    var isPublic = shareData.is_public;
    var shareUrl = shareData.share_url || '';

    function renderModal() {
      var html = '<div class="dash-share-box"><h3>Share: ' + escHtml(d.name) + '</h3>';
      if (!hasLink) {
        // No share link yet — offer to create one
        html += '<p class="share-sub">Create a share link for this dashboard. You can choose internal (admin-only) or public access.</p>';
        html += '<div class="dash-share-actions"><button class="btn-make-public" id="share-create-btn">Create Share Link</button><button class="btn-close-share" id="share-close-btn">Cancel</button></div>';
      } else {
        // Link exists — show Internal/Public toggle
        html += '<div style="display:flex;align-items:center;gap:12px;margin:12px 0">';
        html += '<span style="font-size:13px;color:var(--t2)">Visibility:</span>';
        html += '<label style="position:relative;width:48px;height:26px;flex-shrink:0;cursor:pointer">';
        html += '<input type="checkbox" id="share-vis-toggle"' + (isPublic ? ' checked' : '') + ' style="opacity:0;width:0;height:0;position:absolute">';
        var tBg = isPublic ? 'var(--acc)' : '#ef4444';
        html += '<span id="share-track" style="position:absolute;top:0;left:0;right:0;bottom:0;background:' + tBg + ';border-radius:13px;transition:background .2s"></span>';
        html += '<span id="share-knob" style="position:absolute;top:3px;' + (isPublic ? 'left:25px' : 'left:3px') + ';width:20px;height:20px;background:#fff;border-radius:50%;transition:left .2s;box-shadow:0 1px 3px rgba(0,0,0,.3)"></span>';
        html += '</label>';
        html += '<span id="share-lbl" style="font-size:14px;font-weight:600;color:' + (isPublic ? 'var(--acc)' : '#ef4444') + '">' + (isPublic ? 'Public' : 'Internal') + '</span>';
        html += '</div>';
        html += '<p style="font-size:12px;color:var(--t3);margin-bottom:12px">' + (isPublic ? 'All team members can see and copy this link.' : 'Only admins can see and copy this link (for digital signage, automations, etc.)') + '</p>';
        html += '<div class="dash-share-link-row"><input type="text" id="share-url-input" value="' + escHtml(shareUrl) + '" readonly><button id="share-copy-btn">Copy link</button><button id="share-native-btn">Share</button></div>';
        html += '<div class="dash-share-actions"><button class="btn-delist" id="share-revoke-btn">Revoke Link</button><button class="btn-close-share" id="share-close-btn">Close</button></div>';
      }
      html += '</div>';
      overlay.innerHTML = html;

      // Bind events
      overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };
      var closeBtn = overlay.querySelector('#share-close-btn');
      if (closeBtn) closeBtn.onclick = function() { overlay.remove(); };

      var createBtn = overlay.querySelector('#share-create-btn');
      if (createBtn) createBtn.onclick = function() {
        createBtn.disabled = true;
        createBtn.textContent = 'Creating...';
        api.post('/api/dashboards/' + d.id + '/share').then(function(r) {
          if (r.ok && r.data) {
            hasLink = true;
            isPublic = false;
            shareUrl = r.data.share_url || '';
            renderModal();
            loadDashboards();
          } else {
            createBtn.disabled = false;
            createBtn.textContent = 'Create Share Link';
            if (window.__xrayToast) window.__xrayToast('Failed to create link', 'error');
          }
        });
      };

      var toggle = overlay.querySelector('#share-vis-toggle');
      if (toggle) toggle.onchange = function() {
        var newPublic = this.checked;
        var track = overlay.querySelector('#share-track');
        var knob = overlay.querySelector('#share-knob');
        var lbl = overlay.querySelector('#share-lbl');
        var desc = lbl.parentElement.nextElementSibling;
        track.style.background = newPublic ? 'var(--acc)' : '#ef4444';
        knob.style.left = newPublic ? '25px' : '3px';
        lbl.textContent = newPublic ? 'Public' : 'Internal';
        lbl.style.color = newPublic ? 'var(--acc)' : '#ef4444';
