    'https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1557683316-973673baf926?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1523961131990-5ea7c61b2107?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1504639725590-34d0984388bd?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1531297484001-80022131f5a1?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1488229297570-58520851e868?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1550751827-4bd374c3f58b?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1434030216411-0b793f4b4173?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1543286386-2e659306cd6c?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1560472355-536de3962603?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1579403124614-197f69d8187b?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1611162617474-5b21e879e113?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1614064641938-3bbee52942c7?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1580894894513-541e068a3e2b?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1562654501-a0ccc0fc3fb1?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1498050108023-c5249f4df085?w=400&h=300&fit=crop','https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=400&h=300&fit=crop'
  ];

  function openDetailsModal(d) {
    var canEdit = (user && user.is_owner) || isPlatformAdmin;
    var overlay = document.createElement('div');
    overlay.className = 'dash-detail-modal';
    var conns = d.connectors || [];
    var html = '<div class="dash-detail-box">';
    html += '<div class="dash-detail-header"><h3>' + escHtml(d.name) + '</h3><button class="dash-detail-close">&times;</button></div>';
    html += '<div class="dash-detail-body">';

    // Image section
    html += '<div class="dash-img-section">';
    if (d.tile_image_url) html += '<img class="dash-img-preview" src="' + escHtml(d.tile_image_url) + '" alt="">';
    if (canEdit) {
      html += '<div class="dash-img-actions">';
      html += '<button id="dd-img-upload-btn">Upload image</button>';
      html += '<button id="dd-img-library-btn">Choose from library</button>';
      html += '<input type="file" id="dd-img-file" accept="image/*" style="display:none">';
      html += '</div>';
      html += '<div id="dd-img-library" class="dash-img-library" style="display:none"></div>';
    }
    html += '</div>';

    // Info section
    html += '<div class="dash-detail-section"><h4>Details</h4>';
    html += '<div class="dash-detail-grid">';
    html += '<div class="dash-detail-item"><label>Name</label>' + escHtml(d.name) + '</div>';
    html += '<div class="dash-detail-item"><label>Status</label>' + (d.status || 'draft') + '</div>';
    html += '<div class="dash-detail-item"><label>Created</label>' + fmtDateTime(d.created_at) + '</div>';
    html += '<div class="dash-detail-item"><label>Updated</label>' + fmtDateTime(d.updated_at) + '</div>';
    html += '<div class="dash-detail-item"><label>Views</label><a href="#" class="dd-view-count-link" style="color:var(--acc);cursor:pointer;text-decoration:none" data-dash-id="' + d.id + '">' + (d.view_count || 0) + ' <span style="font-size:11px;color:var(--t3)">View log</span></a></div>';
    if (isPlatformAdmin && d.tenant_name) html += '<div class="dash-detail-item"><label>Tenant</label>' + escHtml(d.tenant_name) + '</div>';
    html += '</div>';
    if (d.description) html += '<div class="dash-detail-item" style="margin-top:8px"><label>Description</label>' + escHtml(d.description) + '</div>';
    html += '</div>';

    // Connectors section
    html += '<div class="dash-detail-section" style="display:none"><h4>Connectors</h4>';
    html += '<div id="dd-connectors" class="dash-detail-connectors">';
    if (conns.length) {
      html += conns.map(function(c) {
        var rm = canEdit ? '<button class="dash-conn-detach" data-sid="' + c.id + '">remove</button>' : '';
        return '<div class="dash-detail-conn"><span>' + escHtml(c.connection_name || c.source_key) + '</span><span class="conn-type">' + escHtml(c.source_type || '') + '</span>' + rm + '</div>';
      }).join('');
    } else {
      html += '<div class="dash-no-data">No connectors attached</div>';
    }
    html += '</div>';
    if (canEdit) {
      html += '<div class="dash-conn-attach"><select id="dd-conn-select"><option value="">Select a connector to attach...</option></select>';
      html += '<div class="dash-conn-attach-row"><input id="dd-conn-key" placeholder="Source key (e.g. main_data)"><input id="dd-conn-table" placeholder="Table name"><button class="dash-conn-attach-btn" id="dd-conn-add">Attach</button></div></div>';
    }
    html += '</div>';

    // Access list section (visible to all, toggles only for owners/admins)
    html += '<div class="dash-detail-section"><h4>Team</h4>';
    html += '<div id="dd-access-list" class="dash-detail-connectors"><div class="dash-no-data">Loading...</div></div>';
    html += '</div>';

    // Replays section
    html += '<div class="dash-detail-section dash-replays"><h4>Recent Replays</h4>';
    html += '<div id="dd-replays-list" class="replay-dash-mini"><div class="replay-no-data" style="padding:20px;font-size:13px;color:var(--t2)">Loading...</div></div>';
    html += '</div>';

    // Comments section
    html += '<div class="dash-detail-section dash-comments" style="display:none"><h4>Comments</h4>';
    html += '<div id="dd-comments-list"></div>';
    html += '<div id="dd-comments-more" class="dash-comment-more" style="display:none">Load more</div>';
    html += '<div class="dash-comment-form"><textarea id="dd-comment-input" placeholder="Add a comment..." rows="1"></textarea><button id="dd-comment-submit">Post</button></div>';
    html += '</div>';

    html += '</div></div>';
    overlay.innerHTML = html;
    document.body.appendChild(overlay);

    overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };
    overlay.querySelector('.dash-detail-close').onclick = function() { overlay.remove(); };

    // View log click handler
    overlay.querySelectorAll('.dd-view-count-link').forEach(function(link) {
      link.onclick = function(e) {
        e.preventDefault();
        var dashId = this.dataset.dashId;
        showViewLogModal(dashId, d.name);
      };
    });

    // ── Image upload ──
    if (canEdit) {
      var fileInput = overlay.querySelector('#dd-img-file');
      overlay.querySelector('#dd-img-upload-btn').onclick = function() { fileInput.click(); };
      fileInput.onchange = function() {
        if (!this.files || !this.files[0]) return;
        var fd = new FormData();
        fd.append('image', this.files[0]);
        fetch('/api/dashboards/' + d.id + '/image/upload', {
          method: 'POST',
          headers: { 'Authorization': 'Bearer ' + (window.getAccessToken ? window.getAccessToken() : '') },
          body: fd
        }).then(function(r) { return r.json(); }).then(function(r) {
          if (r.ok) { d.tile_image_url = r.data.imageUrl; overlay.remove(); openDetailsModal(d); loadDashboards(); }
          else alert((r.error && r.error.message) || 'Upload failed');
        });
      };

      var libOpen = false;
      overlay.querySelector('#dd-img-library-btn').onclick = function() {
        var libDiv = overlay.querySelector('#dd-img-library');
        libOpen = !libOpen;
        if (libOpen) {
          libDiv.style.display = 'grid';
          libDiv.innerHTML = IMAGE_LIBRARY.map(function(url) {
            return '<img src="' + url + '" loading="lazy" alt="">';
          }).join('');
          libDiv.querySelectorAll('img').forEach(function(img) {
            img.onclick = function() {
              api.patch('/api/dashboards/' + d.id + '/image', { imageUrl: this.src }).then(function(r) {
                if (r.ok) { d.tile_image_url = img.src; overlay.remove(); openDetailsModal(d); loadDashboards(); }
                else alert('Failed to set image');
              });
            };
          });
        } else {
          libDiv.style.display = 'none';
        }
      };
    }

    // ── Connectors ──
    if (canEdit) {
      api.get('/api/dashboards/' + d.id + '/available-connectors').then(function(r) {
        if (!r.ok || !r.data) return;
        var sel = overlay.querySelector('#dd-conn-select');
        r.data.forEach(function(c) {
          var opt = document.createElement('option');
          opt.value = c.id;
          opt.textContent = c.name + ' (' + c.source_type + ')';
          sel.appendChild(opt);
        });
      });

      overlay.querySelector('#dd-conn-add').onclick = function() {
        var connId = overlay.querySelector('#dd-conn-select').value;
        var key = overlay.querySelector('#dd-conn-key').value.trim();
        var tbl = overlay.querySelector('#dd-conn-table').value.trim();
        if (!connId || !key || !tbl) { alert('Select a connector and fill in source key and table name'); return; }
        api.post('/api/dashboards/' + d.id + '/connectors', { connectionId: connId, sourceKey: key, tableName: tbl }).then(function(r) {
          if (r.ok) { overlay.remove(); loadDashboards(); /* will re-fetch connectors */ }
          else alert((r.error && r.error.message) || 'Failed');
        });
      };

      overlay.querySelectorAll('.dash-conn-detach').forEach(function(btn) {
        btn.onclick = function() {
          var sid = this.dataset.sid;
          if (!confirm('Remove this connector?')) return;
          api.delete('/api/dashboards/' + d.id + '/connectors/' + sid).then(function(r) {
            if (r.ok) { overlay.remove(); loadDashboards(); }
            else alert('Failed');
          });
        };
      });
    }

    // Load access list (visible to all, toggles only for canEdit)
    api.get('/api/dashboards/' + d.id + '/team-access').then(function(r) {
        var listEl = overlay.querySelector('#dd-access-list');
        if (!listEl) return;
        if (!r.ok || !r.data || !r.data.length) {
          listEl.innerHTML = '<div class="dash-no-data">No team members found</div>';
          return;
        }
        var allTeam = r.data;
        var teamPage = 0;
        var teamLimit = 10;
        var teamFilter = '';

        function renderTeamList() {
          var filtered = allTeam;
          if (teamFilter) {
            var q = teamFilter.toLowerCase();
            filtered = allTeam.filter(function(u) { return (u.name || '').toLowerCase().indexOf(q) !== -1 || (u.email || '').toLowerCase().indexOf(q) !== -1; });
          }
          var total = filtered.length;
          var pages = Math.ceil(total / teamLimit);
          if (teamPage >= pages && pages > 0) teamPage = pages - 1;
          var pageItems = filtered.slice(teamPage * teamLimit, (teamPage + 1) * teamLimit);
          var h = '<input type="text" placeholder="Search team..." style="width:100%;padding:7px 10px;background:var(--bg3);border:1px solid var(--bdr);border-radius:6px;color:var(--t1);font-size:12px;outline:0;margin-bottom:8px;box-sizing:border-box;font-family:var(--font)" id="dd-team-search" value="' + (teamFilter || '') + '">';
          // Two-column grid (5 rows max per column = 10 per page)
          h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:0;border-top:1px solid var(--bdr)">';
          pageItems.forEach(function(u, idx) {
            var hasAccess = u.has_access;
            var ownerBadge = u.is_owner ? '<span style="display:inline-block;padding:1px 5px;font-size:9px;font-weight:600;border-radius:3px;background:rgba(62,232,181,.15);color:var(--acc);margin-left:3px">Owner</span>' : '';
            var toggleBtn = '';
            if (canEdit) {
              var btnStyle = hasAccess ? 'border-color:var(--acc);background:var(--acc-dim,rgba(62,232,181,.1));color:var(--acc)' : 'border-color:var(--bdr);background:var(--bg4);color:var(--t3)';
              toggleBtn = '<button class="team-access-toggle" data-uid="' + u.id + '" data-has="' + (hasAccess ? '1' : '0') + '" style="padding:2px 10px;font-size:10px;border-radius:12px;border:1px solid;cursor:pointer;font-family:var(--font);font-weight:500;flex-shrink:0;' + btnStyle + '">' + (hasAccess ? 'Visible' : 'Hidden') + '</button>';
            } else {
              toggleBtn = hasAccess ? '<span style="font-size:10px;color:var(--acc);flex-shrink:0">Visible</span>' : '<span style="font-size:10px;color:var(--t3);flex-shrink:0">Hidden</span>';
            }
            // Right border on left column items (odd index = right column)
            var borderRight = (idx % 2 === 0) ? 'border-right:1px solid var(--bdr);' : '';
            h += '<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 10px;border-bottom:1px solid var(--bdr);' + borderRight + 'gap:4px">'
              + '<div style="min-width:0;overflow:hidden;flex:1"><div style="font-weight:500;font-size:13px;color:var(--t1);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(u.name || u.email) + ownerBadge + '</div>'
              + (u.name ? '<div style="font-size:10px;color:var(--t3);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(u.email) + '</div>' : '')
              + '</div>' + toggleBtn + '</div>';
          });
          h += '</div>';
          // Pagination: always show, with page selector
          var pagStyle = 'font-size:11px;padding:2px 8px;min-width:24px;text-align:center';
          h += '<div style="display:flex;align-items:center;justify-content:center;gap:4px;margin-top:8px;font-size:11px;color:var(--t3)">';
          h += '<button class="btn sm" id="dd-team-prev" style="' + pagStyle + '"' + (teamPage <= 0 ? ' disabled style="' + pagStyle + ';opacity:.3;cursor:default"' : '') + '>&laquo; Prev</button>';
          // Page numbers: show first, last, and up to 5 around current
          if (pages > 0) {
            var startP = Math.max(0, teamPage - 2);
            var endP = Math.min(pages, startP + 5);
            if (endP - startP < 5) startP = Math.max(0, endP - 5);
            if (startP > 0) { h += '<button class="btn sm dd-team-page" data-p="0" style="' + pagStyle + '">1</button>'; if (startP > 1) h += '<span>...</span>'; }
            for (var p = startP; p < endP; p++) {
              var sel = p === teamPage ? ';background:var(--acc);color:#000;border-color:var(--acc)' : '';
              h += '<button class="btn sm dd-team-page" data-p="' + p + '" style="' + pagStyle + sel + '">' + (p + 1) + '</button>';
            }
            if (endP < pages) { if (endP < pages - 1) h += '<span>...</span>'; h += '<button class="btn sm dd-team-page" data-p="' + (pages - 1) + '" style="' + pagStyle + '">' + pages + '</button>'; }
          }
          h += '<button class="btn sm" id="dd-team-next" style="' + pagStyle + '"' + (teamPage >= pages - 1 ? ' disabled style="' + pagStyle + ';opacity:.3;cursor:default"' : '') + '>Next &raquo;</button>';
          h += '</div>';
          listEl.innerHTML = h;
          var searchInput = listEl.querySelector('#dd-team-search');
          if (searchInput) { searchInput.oninput = function() { teamFilter = this.value; teamPage = 0; renderTeamList(); }; searchInput.focus(); searchInput.setSelectionRange(searchInput.value.length, searchInput.value.length); }
          var prevBtn = listEl.querySelector('#dd-team-prev');
          var nextBtn = listEl.querySelector('#dd-team-next');
          if (prevBtn && !prevBtn.disabled) prevBtn.onclick = function() { teamPage--; renderTeamList(); };
          if (nextBtn && !nextBtn.disabled) nextBtn.onclick = function() { teamPage++; renderTeamList(); };
          listEl.querySelectorAll('.dd-team-page').forEach(function(pb) {
            pb.onclick = function() { teamPage = parseInt(this.dataset.p); renderTeamList(); };
          });
          if (canEdit) {
            listEl.querySelectorAll('.team-access-toggle').forEach(function(btn) {
              btn.onclick = function() {
                var uid = this.dataset.uid;
                var has = this.dataset.has === '1';
                var el = this;
                el.disabled = true;
                if (has) {
                  api.delete('/api/dashboards/' + d.id + '/access/' + uid).then(function(dr) {
                    el.disabled = false;
                    if (dr.ok) { el.dataset.has = '0'; el.textContent = 'Hidden'; el.style.borderColor = 'var(--bdr)'; el.style.background = 'var(--bg4)'; el.style.color = 'var(--t3)'; var u2 = allTeam.find(function(x){return x.id===uid;}); if(u2) u2.has_access=false; }
                  });
                } else {
                  api.post('/api/dashboards/' + d.id + '/access', { userId: uid }).then(function(gr) {
                    el.disabled = false;
                    if (gr.ok) { el.dataset.has = '1'; el.textContent = 'Visible'; el.style.borderColor = 'var(--acc)'; el.style.background = 'var(--acc-dim,rgba(62,232,181,.1))'; el.style.color = 'var(--acc)'; var u2 = allTeam.find(function(x){return x.id===uid;}); if(u2) u2.has_access=true; }
                  });
                }
              };
            });
          }
        }
        renderTeamList();
      }).catch(function() {});

    // ── Comments (paginated) ──
    var commentOffset = 0;
    var commentLimit = 10;
    var commentTotal = 0;

    function loadComments(append) {
      api.get('/api/dashboards/' + d.id + '/comments?limit=' + commentLimit + '&offset=' + commentOffset).then(function(r) {
        if (!r.ok) return;
        commentTotal = r.meta && r.meta.total || 0;
        var list = overlay.querySelector('#dd-comments-list');
        var items = r.data || [];
        var html = items.map(function(c) {
          return '<div class="dash-comment"><div class="dash-comment-head"><span class="dash-comment-author">' + escHtml(c.author_name || c.author_email || 'Unknown') + '</span><span class="dash-comment-time">' + fmtDateTime(c.created_at) + '</span></div><div class="dash-comment-body">' + escHtml(c.content) + '</div></div>';
        }).join('');
        if (!items.length && !append) html = '<div class="dash-no-data">No comments yet</div>';
        if (append) list.insertAdjacentHTML('beforeend', html);
        else list.innerHTML = html;
        var moreBtn = overlay.querySelector('#dd-comments-more');
        if (commentOffset + commentLimit < commentTotal) moreBtn.style.display = '';
        else moreBtn.style.display = 'none';
      });
    }

    loadComments(false);

    overlay.querySelector('#dd-comments-more').onclick = function() {
      commentOffset += commentLimit;
      loadComments(true);
    };

    overlay.querySelector('#dd-comment-submit').onclick = function() {
      var input = overlay.querySelector('#dd-comment-input');
      var val = input.value.trim();
      if (!val) return;
      api.post('/api/dashboards/' + d.id + '/comments', { content: val }).then(function(r) {
        if (r.ok) { input.value = ''; commentOffset = 0; loadComments(false); }
        else alert((r.error && r.error.message) || 'Failed');
      });
    };
  }

    function fmtDateTime(s) { if (!s) return '-'; try { var d = new Date(s); return d.toLocaleDateString(undefined, {month:'short',day:'numeric',year:'numeric'}) + ' ' + d.toLocaleTimeString(undefined, {hour:'2-digit',minute:'2-digit'}); } catch(e) { return '-'; } }
  function escHtml(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  // Listen for WebSocket dashboard access changes
  function onWsMessage(evt) {
    try {
      var msg = JSON.parse(evt.data);
      if (msg.type === 'dashboard:access-granted' || msg.type === 'dashboard:access-revoked' || msg.type === 'dashboard:share-changed') {
        loadDashboards();
      }
    } catch(e) {}
  }
  if (window.__xrayWs && window.__xrayWs.readyState === 1) {
    window.__xrayWs.addEventListener('message', onWsMessage);
  }
  window.__xrayDashWsHandler = onWsMessage;

  // Handle real-time billing changes (WebSocket billing:updated event)
  window.__xrayBillingChanged = function(data) {
    if (data && typeof data.hasVision !== 'undefined') {
      hasVision = data.hasVision;
      if (hasVision) {
        banner.style.display = 'none';
      } else {
        banner.className = 'dash-sub-banner warn';
        banner.innerHTML = '<span>An <strong>XRay Vision</strong> subscription is required to open dashboards.</span><button class="btn primary" id="btn-buy-vision" style="flex-shrink:0">Subscribe now</button>';
        banner.style.display = 'flex';
        banner.querySelector('#btn-buy-vision').onclick = function() { window.location.hash = 'billing'; };
      }
    }
  };
  window.__xrayRefreshDashboardList = function() { checkBilling(); };

  checkBilling();
}

connections.css:
.connections-view .empty-state{text-align:center;padding:80px 24px}
.connections-view .empty-icon{margin-bottom:12px;color:var(--t3)}
.connections-view .empty-title{font-size:16px;font-weight:600;margin-bottom:4px}
.connections-view .empty-desc{font-size:14px;color:var(--t2)}
.connections-view .tbl td img{width:32px;height:32px;border-radius:6px;object-fit:contain;background:var(--bg4);padding:4px}
.connections-view .conn-row:hover{background:var(--bg3)}
.connections-view .status-badge{display:inline-block;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:500}
.connections-view .status-active{background:rgba(34,197,94,.12);color:#22c55e}
.connections-view .status-pending{background:rgba(234,179,8,.12);color:#eab308}
.connections-view .status-error{background:rgba(239,68,68,.12);color:#ef4444}
.connections-view .status-inactive{background:rgba(142,145,160,.12);color:#8e91a0}
.connections-view .status-disabled{background:rgba(142,145,160,.12);color:#8e91a0}
.connections-view textarea{width:100%;resize:vertical;min-height:60px;padding:8px 10px;border:1px solid var(--br);border-radius:6px;background:var(--bg2);color:var(--t1);font-size:13px;font-family:inherit}
.connections-view .conn-upload-area,.connections-view .conn-detail-upload-area{border:2px dashed var(--br);border-radius:8px;padding:20px;text-align:center;cursor:pointer;color:var(--t3);display:flex;flex-direction:column;align-items:center;gap:6px;font-size:13px;transition:border-color .15s,background .15s}
.connections-view .conn-upload-area:hover,.connections-view .conn-detail-upload-area:hover,.connections-view .conn-upload-area.drag-over,.connections-view .conn-detail-upload-area.drag-over{border-color:var(--accent);background:rgba(99,102,241,.04)}
.connections-view .conn-detail-upload-area{padding:12px;flex-direction:row}
.connections-view .conn-files-list{display:flex;flex-direction:column;gap:4px;margin-top:8px}
.connections-view .conn-file-item{display:flex;align-items:center;gap:8px;padding:6px 10px;border-radius:6px;font-size:13px;background:var(--bg3);cursor:pointer;transition:background .15s}
.connections-view .conn-file-item:hover{background:var(--bg4)}
.connections-view .conn-file-item span{flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.connections-view .conn-file-remove{background:none;border:none;color:var(--t3);cursor:pointer;font-size:16px;padding:0 4px;line-height:1}
.connections-view .conn-no-files{font-size:13px;color:var(--t3);padding:8px 0}
.connections-view .modal-lg{max-width:640px;width:100%}
.connections-view .conn-detail-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:20px;padding-bottom:16px;border-bottom:1px solid var(--br)}
.connections-view .conn-detail-row{display:flex;gap:12px;font-size:13px}
.connections-view .conn-detail-label{font-weight:600;min-width:80px;color:var(--t2)}
.connections-view .conn-section{margin-top:20px}
