function initConnections(container, api, user) {
  var modal = container.querySelector('#conn-modal');
  var detailModal = container.querySelector('#conn-detail-modal');
  var isPlatformAdmin = user && user.is_platform_admin;
  var CONNECTOR_PRODUCT = 'prod_UB9ztFWlgoXCe1';
  var currentConnId = null;
  var commentsPage = 1;
  var commentsPerPage = 10;
  var pendingFiles = [];

  var fallbackIcon = '<svg viewBox="0 0 24 24" width="32" height="32" stroke="currentColor" fill="none" stroke-width="1" style="color:var(--t3)"><line x1="16.5" y1="9.4" x2="7.5" y2="4.21"/><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg>';

  function esc(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  function loadConnections() {
    api.get('/api/connections').then(function(r) {
      var tbody = container.querySelector('#connections-tbody');
      var empty = container.querySelector('#connections-empty');
      if (!r.ok || !r.data || r.data.length === 0) { empty.style.display = ''; tbody.parentElement.style.display = 'none'; return; }
      empty.style.display = 'none'; tbody.parentElement.style.display = '';
      tbody.innerHTML = r.data.map(function(c) {
        var imgHtml = c.image_url
          ? '<img src="' + esc(c.image_url) + '" alt="">'
          : fallbackIcon;
        var statusCls = 'status-' + (c.status || 'active');
        var createdDate = c.created_at ? new Date(c.created_at).toLocaleDateString() : '-';
        return '<tr class="conn-row" data-id="' + c.id + '" style="cursor:pointer"><td style="width:48px">' + imgHtml + '</td><td><strong>' + esc(c.name) + '</strong></td><td>' + esc(c.source_type || '-') + '</td><td><span class="status-badge ' + statusCls + '">' + esc(c.status || 'active') + '</span></td><td>' + createdDate + '</td></tr>';
      }).join('');

      tbody.querySelectorAll('.conn-row').forEach(function(row) {
        row.onclick = function() { openDetail(row.getAttribute('data-id')); };
      });
    });
  }

  /* ---- Detail modal ---- */
  function openDetail(id) {
    currentConnId = id;
    commentsPage = 1;
    detailModal.style.display = 'flex';
    container.querySelector('#conn-detail-title').textContent = 'Loading…';
    container.querySelector('#conn-detail-type').textContent = '-';
    container.querySelector('#conn-detail-status').innerHTML = '';
    container.querySelector('#conn-detail-desc').textContent = '';
    container.querySelector('#conn-detail-files-list').innerHTML = '';
    container.querySelector('#conn-detail-comments').innerHTML = '';
    container.querySelector('#conn-comments-pagination').innerHTML = '';

    api.get('/api/connections/' + id).then(function(r) {
      if (!r.ok) return;
      var c = r.data;
      container.querySelector('#conn-detail-title').textContent = c.name || 'Connection';
      container.querySelector('#conn-detail-type').textContent = c.source_type || '-';
      var statusCls = 'status-' + (c.status || 'active');
      container.querySelector('#conn-detail-status').innerHTML = '<span class="status-badge ' + statusCls + '">' + esc(c.status || 'active') + '</span>';
      container.querySelector('#conn-detail-desc').textContent = c.description || c.source_detail || '-';
    });

    loadDetailFiles(id);
    loadComments(id, 1);
  }

  function loadDetailFiles(id) {
    api.get('/api/uploads/context/connection/' + id).then(function(r) {
      var list = container.querySelector('#conn-detail-files-list');
      if (!r.ok || !r.data || r.data.length === 0) { list.innerHTML = '<div class="conn-no-files">No files uploaded.</div>'; return; }
      list.innerHTML = r.data.map(function(f) {
        return '<div class="conn-file-item" data-url="' + esc(f.url || f.file_url || '') + '" data-name="' + esc(f.original_name || f.file_name || 'file') + '" data-mime="' + esc(f.mime_type || '') + '">' +
          '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" fill="none" stroke-width="1.5"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>' +
          '<span>' + esc(f.original_name || f.file_name || 'file') + '</span></div>';
      }).join('');
      list.querySelectorAll('.conn-file-item').forEach(function(el) {
        el.onclick = function() {
          var url = el.getAttribute('data-url');
          var name = el.getAttribute('data-name');
          var mime = el.getAttribute('data-mime');
          if (window.__xrayOpenViewer) window.__xrayOpenViewer(url, name, mime);
        };
      });
    });
  }

  function loadComments(id, page) {
    commentsPage = page;
    api.get('/api/connections/' + id + '/comments?page=' + page + '&limit=' + commentsPerPage).then(function(r) {
      var wrap = container.querySelector('#conn-detail-comments');
      var pagWrap = container.querySelector('#conn-comments-pagination');
      if (!r.ok || !r.data || r.data.length === 0) {
        wrap.innerHTML = '<div class="conn-no-files">No comments yet.</div>';
        pagWrap.innerHTML = '';
        return;
      }
      wrap.innerHTML = r.data.map(function(c) {
        var authorName = c.is_platform_admin ? 'XRay Tech' : (c.author_name || c.user_name || 'User');
        var dateStr = c.created_at ? new Date(c.created_at).toLocaleDateString() : '';
        return '<div class="conn-comment-item">' +
          '<div class="conn-comment-header"><strong>' + esc(authorName) + '</strong><span class="conn-comment-date">' + esc(dateStr) + '</span></div>' +
          '<div class="conn-comment-body">' + esc(c.content || c.body || '') + '</div></div>';
      }).join('');
      var total = r.total || r.data.length;
      var totalPages = Math.ceil(total / commentsPerPage);
      if (totalPages > 1) {
        var btns = '';
        for (var p = 1; p <= totalPages; p++) {
          btns += '<button class="btn btn-sm conn-page-btn' + (p === page ? ' primary' : '') + '" data-page="' + p + '">' + p + '</button>';
        }
        pagWrap.innerHTML = btns;
        pagWrap.querySelectorAll('.conn-page-btn').forEach(function(b) {
          b.onclick = function() { loadComments(id, parseInt(b.getAttribute('data-page'))); };
        });
      } else {
        pagWrap.innerHTML = '';
      }
    });
  }

  /* ---- Upload helpers ---- */
  function uploadFiles(files, contextId, cb) {
    if (!files || files.length === 0) { if (cb) cb(); return; }
    var fd = new FormData();
    for (var i = 0; i < files.length; i++) fd.append('files', files[i]);
    fd.append('contextType', 'connection');
    if (contextId) fd.append('contextId', contextId);
    var token = localStorage.getItem('token') || '';
    fetch('/api/uploads', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token }, body: fd })
      .then(function(r) { return r.json(); })
      .then(function() { if (cb) cb(); })
      .catch(function() { if (cb) cb(); });
  }

  /* ---- New connection modal ---- */
  var uploadArea = container.querySelector('#conn-files');
  var fileInput = container.querySelector('#conn-files-input');
  var filesList = container.querySelector('#conn-files-list');
  if (uploadArea && fileInput) {
    uploadArea.onclick = function() { fileInput.click(); };
    uploadArea.ondragover = function(e) { e.preventDefault(); uploadArea.classList.add('drag-over'); };
    uploadArea.ondragleave = function() { uploadArea.classList.remove('drag-over'); };
    uploadArea.ondrop = function(e) { e.preventDefault(); uploadArea.classList.remove('drag-over'); addPendingFiles(e.dataTransfer.files); };
    fileInput.onchange = function() { addPendingFiles(fileInput.files); fileInput.value = ''; };
  }
  function addPendingFiles(fl) {
    for (var i = 0; i < fl.length; i++) pendingFiles.push(fl[i]);
    renderPendingFiles();
  }
  function renderPendingFiles() {
    if (!filesList) return;
    filesList.innerHTML = pendingFiles.map(function(f, i) {
      return '<div class="conn-file-item"><svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="1.5"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg><span>' + esc(f.name) + '</span><button class="conn-file-remove" data-i="' + i + '">&times;</button></div>';
    }).join('');
    filesList.querySelectorAll('.conn-file-remove').forEach(function(b) {
      b.onclick = function(e) { e.stopPropagation(); pendingFiles.splice(parseInt(b.getAttribute('data-i')), 1); renderPendingFiles(); };
    });
  }

  if (container.querySelector('#btn-new-connection')) {
    container.querySelector('#btn-new-connection').onclick = function() {
      modal.style.display = 'flex';
      container.querySelector('#conn-name').value = '';
      container.querySelector('#conn-type').value = '';
      container.querySelector('#conn-description').value = '';
      pendingFiles = [];
      if (filesList) filesList.innerHTML = '';
      container.querySelector('#conn-name').focus();
    };
  }
  if (container.querySelector('#btn-close-conn-modal')) {
    container.querySelector('#btn-close-conn-modal').onclick = function() { modal.style.display = 'none'; };
  }
  if (container.querySelector('#btn-cancel-conn')) {
    container.querySelector('#btn-cancel-conn').onclick = function() { modal.style.display = 'none'; };
  }
  if (container.querySelector('#btn-submit-conn')) {
    container.querySelector('#btn-submit-conn').onclick = function() {
      var name = container.querySelector('#conn-name').value.trim();
      var sourceType = container.querySelector('#conn-type').value;
      var description = container.querySelector('#conn-description').value.trim();
      if (!name) { alert('Connection name is required.'); return; }
      if (!sourceType) { alert('Please select a source type.'); return; }
      var btn = this; btn.disabled = true; btn.textContent = 'Creating…';
      api.post('/api/connections', { name: name, sourceType: sourceType, description: description }).then(function(r) {
        btn.disabled = false; btn.textContent = 'Create connection';
        if (!r.ok) { alert(r.error ? r.error.message : 'Failed to create connection'); return; }
        var connId = r.data && r.data.id;
        if (pendingFiles.length > 0 && connId) {
          uploadFiles(pendingFiles, connId, function() {
            pendingFiles = [];
            modal.style.display = 'none';
            loadConnections();
          });
        } else {
          modal.style.display = 'none';
          loadConnections();
        }
      });
    };
  }

  /* ---- Detail modal events ---- */
  if (container.querySelector('#btn-close-detail-modal')) {
    container.querySelector('#btn-close-detail-modal').onclick = function() { detailModal.style.display = 'none'; currentConnId = null; };
  }
  detailModal.onclick = function(e) { if (e.target === detailModal) { detailModal.style.display = 'none'; currentConnId = null; } };
  modal.onclick = function(e) { if (e.target === modal) modal.style.display = 'none'; };

  /* Detail file upload */
  var detailUploadArea = container.querySelector('#conn-detail-files-drop');
  var detailFileInput = container.querySelector('#conn-detail-files-input');
  if (detailUploadArea && detailFileInput) {
    detailUploadArea.onclick = function() { detailFileInput.click(); };
    detailUploadArea.ondragover = function(e) { e.preventDefault(); detailUploadArea.classList.add('drag-over'); };
    detailUploadArea.ondragleave = function() { detailUploadArea.classList.remove('drag-over'); };
    detailUploadArea.ondrop = function(e) { e.preventDefault(); detailUploadArea.classList.remove('drag-over'); uploadFiles(e.dataTransfer.files, currentConnId, function() { loadDetailFiles(currentConnId); }); };
    detailFileInput.onchange = function() { uploadFiles(detailFileInput.files, currentConnId, function() { loadDetailFiles(currentConnId); }); detailFileInput.value = ''; };
  }

  /* Send comment */
  if (container.querySelector('#btn-send-comment')) {
    container.querySelector('#btn-send-comment').onclick = function() {
      var input = container.querySelector('#conn-comment-input');
      var content = input.value.trim();
      if (!content || !currentConnId) return;
      var btn = this; btn.disabled = true;
      api.post('/api/connections/' + currentConnId + '/comments', { content: content }).then(function(r) {
        btn.disabled = false;
        if (r.ok) { input.value = ''; loadComments(currentConnId, 1); }
      });
    };
  }

  loadConnections();
}

admin_tenants.js:
function initAdminTenants(container, api, user) {
  var modal = container.querySelector('#tenant-modal');
  var detailModal = container.querySelector('#tenant-detail-modal');
  var _currentTenantId = currentTenantId = null;

  var tierLimits = { free: 0, pro5: 5, pro10: 10, e20: 20, e40: 40 };

  container.querySelector('#detail-plan-tier').onchange = function() {
    var limit = tierLimits[this.value];
    if (limit !== undefined) container.querySelector('#detail-dash-limit').value = limit;
  };

  var _currentTenantId = null;
  container.querySelector('#detail-replay-enabled').onchange = function() {
    if (!_currentTenantId) return;
    var el = this;
    api.patch('/api/admin/tenants/' + _currentTenantId + '/replay', { replay_enabled: el.checked }).then(function(r) {
      if (r.ok && window.__xrayToast) window.__xrayToast('Replay ' + (r.data.replay_enabled ? 'enabled' : 'disabled'), 'success');
      else if (!r.ok) { el.checked = !el.checked; if (window.__xrayToast) window.__xrayToast('Failed to update', 'error'); }
    });
  };

  container.querySelector('#detail-replay-visible').onchange = function() {
    if (!_currentTenantId) return;
    var el = this;
    api.patch('/api/admin/tenants/' + _currentTenantId + '/replay', { replay_visible: el.checked }).then(function(r) {
      if (r.ok && window.__xrayToast) window.__xrayToast('Replay tab ' + (r.data.replay_visible ? 'visible' : 'hidden') + ' for tenant', 'success');
      else if (!r.ok) { el.checked = !el.checked; if (window.__xrayToast) window.__xrayToast('Failed to update', 'error'); }
    });
  };

  function loadTenants() {
    api.get('/api/admin/tenants').then(function(r) {
      if (!r.ok) return;
      var tenants = r.data.data || r.data || [];
      container.querySelector('#tenants-tbody').innerHTML = tenants.map(function(t) {
        var statusColor = t.status === 'active' ? 'var(--acc)' : t.status === 'archived' ? 'var(--t3)' : '#f59e0b';
        return '<tr data-id="' + t.id + '" data-name="' + t.name + '" style="cursor:pointer">'
          + '<td><strong>' + t.name + '</strong></td>'
          + '<td><code>' + t.slug + '</code></td>'
          + '<td>' + (t.owner_email || '-') + '</td>'
          + '<td>' + (t.member_count || 0) + '</td>'
          + '<td><span style="color:var(--acc)">' + (t.plan || 'free') + '</span></td>'
          + '<td><span style="color:' + statusColor + ';font-size:12px;text-transform:capitalize">' + (t.status || 'active') + '</span></td>'
          + '<td>' + new Date(t.created_at).toLocaleDateString() + '</td>'
          + '</tr>';
      }).join('');
      container.querySelectorAll('tr[data-id]').forEach(function(row) {
        row.onclick = function() { openDetail(this.dataset.id, this.dataset.name); };
      });
    });
  }

  function openDetail(tenantId, tenantName) {
    currentTenantId = tenantId;
    container.querySelector('#detail-tenant-name').textContent = tenantName;
    container.querySelector('#detail-plan-tier').value = 'free';
    container.querySelector('#detail-dash-limit').value = '0';
    container.querySelector('#detail-billing-override').checked = false;
    container.querySelector('#detail-replay-enabled').checked = false;
    container.querySelector('#detail-replay-visible').checked = false;
    container.querySelector('#detail-owner').value = '';
    container.querySelector('#detail-slug').value = '';
    container.querySelector('#note-input').value = '';
    detailModal.style.display = 'flex';
    container.querySelector('#member-add-name').value = '';
    container.querySelector('#member-add-email').value = '';

    api.get('/api/admin/tenants/' + tenantId).then(function(r) {
      if (!r.ok) return;
      container.querySelector('#detail-replay-enabled').checked = !!r.data.replay_enabled;
      container.querySelector('#detail-replay-visible').checked = !!r.data.replay_visible;
      container.querySelector('#detail-owner').value = r.data.owner_email || r.data.owner_user_id || '-';
      var archBtn = container.querySelector('#btn-archive-tenant');
      if (r.data.status === 'archived') { archBtn.textContent = 'Restore tenant'; archBtn.className = 'btn'; }
      else { archBtn.textContent = 'Archive tenant'; archBtn.className = 'btn danger'; }
      container.querySelector('#detail-slug').value = r.data.slug || '';
      if (r.data.billing_state) {
        var bs = r.data.billing_state;
        container.querySelector('#detail-plan-tier').value = bs.plan_tier || 'free';
        container.querySelector('#detail-dash-limit').value = bs.dashboard_limit || tierLimits[bs.plan_tier] || 0;
      }
    });
    api.get('/api/stripe/override/' + tenantId + '/status').then(function(r) {
      container.querySelector('#detail-billing-override').checked = r.ok && r.data && r.data.override;
    }).catch(function() {});
    loadNotes();
    loadMembers();
  }

  function loadNotes() {
    if (!currentTenantId) return;
    api.get('/api/admin/tenants/' + currentTenantId + '/notes').then(function(r) {
      var list = container.querySelector('#notes-list');
      if (!r.ok || !r.data || !r.data.length) { list.innerHTML = '<div style="text-align:center;color:var(--t3);padding:12px">No notes yet.</div>'; return; }
      list.innerHTML = r.data.map(function(n) {
        return '<div class="note-item" data-note-id="' + n.id + '"><div class="note-meta"><span>' + escHtml(n.author_name || n.author_email || 'Admin') + ' &middot; ' + new Date(n.created_at).toLocaleString() + '</span><div class="note-actions"><button class="note-edit">Edit</button><button class="note-del">Delete</button></div></div><div class="note-content">' + escHtml(n.content) + '</div></div>';
      }).join('');
      list.querySelectorAll('.note-edit').forEach(function(btn) {
        btn.onclick = function() { var item = this.closest('.note-item'); var noteId = item.dataset.noteId; var cur = item.querySelector('.note-content').textContent; var nv = prompt('Edit note:', cur); if (nv !== null && nv !== cur) api.patch('/api/admin/tenants/' + currentTenantId + '/notes/' + noteId, { content: nv }).then(function(r) { if (r.ok) loadNotes(); }); };
      });
      list.querySelectorAll('.note-del').forEach(function(btn) {
        btn.onclick = function() { var noteId = this.closest('.note-item').dataset.noteId; if (confirm('Delete?')) api.delete('/api/admin/tenants/' + currentTenantId + '/notes/' + noteId).then(function(r) { if (r.ok) loadNotes(); }); };
      });
    });
  }

  function escHtml(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  function loadMembers() {
    if (!currentTenantId) return;
    var list = container.querySelector('#members-list');
    api.get('/api/admin/tenants/' + currentTenantId + '/members').then(function(r) {
      if (!r.ok || !r.data || !r.data.length) { list.innerHTML = '<div style="text-align:center;color:var(--t3);padding:12px">No members.</div>'; return; }
      list.innerHTML = r.data.map(function(m) {
        var roleBadge = m.is_owner ? '<span class="member-role owner">Owner</span>' : '<span class="member-role">' + escHtml(m.role_name || m.role_slug || 'member') + '</span>';
        var statusDot = m.status === 'active' ? '#3ee8b5' : '#ef4444';
        var lastLogin = m.last_login_at ? new Date(m.last_login_at).toLocaleDateString() : 'Never';
        return '<div class="member-row"><div class="member-info"><div style="display:flex;align-items:center;gap:6px"><span class="member-dot" style="background:' + statusDot + '"></span><strong>' + escHtml(m.name) + '</strong>' + roleBadge + '</div><div style="font-size:12px;color:var(--t3)">' + escHtml(m.email) + ' \u00b7 Last login: ' + lastLogin + '</div></div><button class="member-del-btn" data-uid="' + m.id + '" title="Remove user">\u00d7</button></div>';
      }).join('');
      list.querySelectorAll('.member-del-btn').forEach(function(btn) {
        btn.onclick = function() {
          var uid = this.dataset.uid;
          if (!confirm('Remove this user? This cannot be undone.')) return;
          api.delete('/api/admin/tenants/' + currentTenantId + '/members/' + uid).then(function(r) {
            if (!r.ok) { alert(r.error ? r.error.message : 'Failed'); return; }
            loadMembers();
            // Load global billing override status
  api.get('/api/admin/settings').then(function(r) {
    var el = container.querySelector('#tenant-global-billing');
    if (!el) return;
    if (!r.ok || !r.data) return;
    var settings = {};
    if (Array.isArray(r.data)) {
      r.data.forEach(function(s) { settings[s.key] = s.value; });
    } else {
      settings = r.data;
    }
    var isOn = settings['billing_override'] === 'true';
    el.innerHTML = '<div style="display:flex;align-items:center;gap:12px"><span class="bo-pill ' + (isOn ? 'on' : 'off') + '">' + (isOn ? '✓ Billing Override: ON' : '✗ Billing Override: OFF') + '</span><button class="btn sm" id="btn-toggle-bo">' + (isOn ? 'Disable' : 'Enable') + '</button></div>';
    container.querySelector('#btn-toggle-bo').onclick = function() {
      var newVal = !isOn;
      api.patch('/api/admin/settings', { billing_override: newVal ? 'true' : 'false' }).then(function(sr) {
        if (sr.ok) {
          isOn = newVal;
          el.innerHTML = '<div style="display:flex;align-items:center;gap:12px"><span class="bo-pill ' + (isOn ? 'on' : 'off') + '">' + (isOn ? '✓ Billing Override: ON' : '✗ Billing Override: OFF') + '</span><button class="btn sm" id="btn-toggle-bo">' + (isOn ? 'Disable' : 'Enable') + '</button></div>';
          container.querySelector('#btn-toggle-bo').onclick = arguments.callee;
          if (window.__xrayToast) window.__xrayToast('Billing override ' + (isOn ? 'enabled' : 'disabled'), 'success');
        }
      });
    };
  });
  loadTenants();
          });
        };
      });
    });
  }

  container.querySelector('#btn-add-note').onclick = function() {
    var input = container.querySelector('#note-input');
    var content = input.value.trim();
    if (!content) return;
    api.post('/api/admin/tenants/' + currentTenantId + '/notes', { content: content }).then(function(r) { if (r.ok) { input.value = ''; loadNotes(); } });
  };

  container.querySelector('#btn-close-detail').onclick = function() { detailModal.style.display = 'none'; };
  container.querySelector('#btn-close-detail-foot').onclick = function() { detailModal.style.display = 'none'; };

  container.querySelector('#btn-save-detail').onclick = function() {
    if (!currentTenantId) return;
    var btn = this; btn.disabled = true;
    var tier = container.querySelector('#detail-plan-tier').value;
    var dl = container.querySelector('#detail-dash-limit').value;
    var overrideChecked = container.querySelector('#detail-billing-override').checked;
    api.post('/api/stripe/override/' + currentTenantId, { enabled: overrideChecked }).catch(function() {});
    api.patch('/api/admin/tenants/' + currentTenantId + '/plan', { planTier: tier, dashboardLimit: parseInt(dl, 10) || 0 }).then(function(r) {
      btn.disabled = false;
      if (!r.ok) { alert(r.error ? r.error.message : 'Failed'); return; }
      detailModal.style.display = 'none';
      loadTenants();
    });
  };

  // Create tenant
  container.querySelector('#btn-create-tenant').onclick = function() { modal.style.display = 'flex'; container.querySelector('#tenant-name').value = ''; container.querySelector('#tenant-slug').value = ''; container.querySelector('#tenant-name').focus(); };
  container.querySelector('#btn-close-tenant-modal').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#btn-cancel-tenant').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#tenant-name').oninput = function() { container.querySelector('#tenant-slug').value = this.value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, ''); };
  container.querySelector('#btn-submit-tenant').onclick = function() {
    var name = container.querySelector('#tenant-name').value.trim();
    var slug = container.querySelector('#tenant-slug').value.trim();
    if (!name || !slug) { alert('Name and slug are required.'); return; }
    var btn = this; btn.disabled = true;
    api.post('/api/admin/tenants', { name: name, slug: slug }).then(function(r) {
      btn.disabled = false;
      if (!r.ok) { alert(r.error ? r.error.message : 'Failed'); return; }
      modal.style.display = 'none';
      loadTenants();
    });
  };

  // Add member
  container.querySelector('#btn-add-member').onclick = function() {
    if (!currentTenantId) return;
    var name = container.querySelector('#member-add-name').value.trim();
    var email = container.querySelector('#member-add-email').value.trim();
    var role = container.querySelector('#member-add-role').value;
    if (!name || !email) { alert('Name and email are required.'); return; }
    var btn = this; btn.disabled = true;
    api.post('/api/admin/tenants/' + currentTenantId + '/members', { name: name, email: email, role: role }).then(function(r) {
      btn.disabled = false;
      if (!r.ok) { alert(r.error ? r.error.message : 'Failed'); return; }
      container.querySelector('#member-add-name').value = '';
      container.querySelector('#member-add-email').value = '';
      loadMembers();
      loadTenants();
    });
  };

  // Archive tenant
  container.querySelector('#btn-archive-tenant').onclick = function() {
    if (!currentTenantId) return;
    var btn = this;
    var isArchived = btn.textContent.trim() === 'Restore tenant';
    var newStatus = isArchived ? 'active' : 'archived';
    if (!isArchived && !confirm('Archive this tenant? Users will not be able to log in.')) return;
    btn.disabled = true;
    api.patch('/api/admin/tenants/' + currentTenantId + '/status', { status: newStatus }).then(function(r) {
      btn.disabled = false;
      if (!r.ok) { alert(r.error ? r.error.message : 'Failed'); return; }
      btn.textContent = newStatus === 'archived' ? 'Restore tenant' : 'Archive tenant';
      btn.className = newStatus === 'archived' ? 'btn' : 'btn danger';
      loadTenants();
    });
  };

  loadTenants();
}

admin_dashboards.js:
function initAdminDashboards(container, api, user) {
  var allItems = [];
  var searchEl = container.querySelector('#dash-search');
  var filterEl = container.querySelector('#dash-filter-status');
  var sortEl = container.querySelector('#dash-sort');
  var tbody = container.querySelector('#admin-dash-tbody');

  function render() {
    var q = searchEl.value.toLowerCase();
    var filterStatus = filterEl.value;
    var sort = sortEl.value;
    var items = allItems.filter(function(d) {
      if (filterStatus && d.status !== filterStatus) return false;
      if (q && d.name.toLowerCase().indexOf(q) === -1 && (d.tenant_name || '').toLowerCase().indexOf(q) === -1 && (d.description || '').toLowerCase().indexOf(q) === -1) return false;
      return true;
    });
    items.sort(function(a, b) {
      if (sort === 'name_asc') return a.name.localeCompare(b.name);
      if (sort === 'name_desc') return b.name.localeCompare(a.name);
      if (sort === 'updated_desc') return new Date(b.updated_at || 0) - new Date(a.updated_at || 0);
      if (sort === 'viewed_desc') return new Date(b.last_viewed_at || 0) - new Date(a.last_viewed_at || 0);
      if (sort === 'created_asc') return new Date(a.created_at) - new Date(b.created_at);
      return new Date(b.created_at) - new Date(a.created_at);
    });
    if (!items.length) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:var(--t2);padding:40px">' + (allItems.length ? 'No matching dashboards.' : 'No dashboards created yet.') + '</td></tr>';
      return;
    }
    tbody.innerHTML = items.map(function(d) {
      var statusCls = 'status-' + (d.status || 'draft');
      var connIcon = d.fetch_url ? '<span style="color:var(--acc)">&#x2713; Connected</span>' : '<span style="color:var(--t3)">-</span>';
      var edited = d.updated_at ? new Date(d.updated_at).toLocaleDateString() : '-';
      var viewed = d.last_viewed_at ? new Date(d.last_viewed_at).toLocaleDateString() + ' ' + new Date(d.last_viewed_at).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : '-';
      return '<tr data-id="' + d.id + '">'
        + '<td><strong>' + d.name + '</strong>' + (d.description ? '<br><small style="color:var(--t3)">' + d.description + '</small>' : '') + '</td>'
        + '<td>' + (d.tenant_name || '-') + (d.owner_email ? '<br><small style="color:var(--t3)">' + d.owner_email + '</small>' : '') + '</td>'
        + '<td>' + connIcon + '</td>'
        + '<td><span class="status-badge ' + statusCls + '">' + (d.status || 'draft') + '</span></td>'
        + '<td>' + edited + '</td>'
        + '<td>' + viewed + '</td>'
        + '<td>' + new Date(d.created_at).toLocaleDateString() + '</td>'
        + '<td><button class="btn sm danger dash-delete-btn" data-del-id="' + d.id + '" data-del-name="' + (d.name || '').replace(/"/g, '&quot;') + '">&times; Delete</button></td>'
        + '</tr>';
    }).join('');
    tbody.querySelectorAll('tr[data-id]').forEach(function(row) {
      row.onclick = function(e) { if (e.target.closest('.dash-delete-btn')) return; location.hash = 'admin_builder?edit=' + this.dataset.id; };
    });
    tbody.querySelectorAll('.dash-delete-btn').forEach(function(btn) {
      btn.onclick = function(e) {
        e.stopPropagation();
        var id = this.dataset.delId;
        var name = this.dataset.delName;
        showDeleteConfirm(id, name);
      };
    });
  }

  searchEl.oninput = render;
  filterEl.onchange = render;
  sortEl.onchange = render;

  function showDeleteConfirm(id, name) {
    var modal = container.querySelector('#admin-dash-del-modal');
    container.querySelector('#admin-dash-del-msg').innerHTML = 'Delete dashboard <strong style="color:var(--t1)">' + (name || 'Untitled') + '</strong>? This cannot be undone.';
    modal.style.display = 'flex';
    container.querySelector('#admin-dash-del-close').onclick = function() { modal.style.display = 'none'; };
    container.querySelector('#admin-dash-del-cancel').onclick = function() { modal.style.display = 'none'; };
    container.querySelector('#admin-dash-del-confirm').onclick = function() {
      var btn = this; btn.disabled = true; btn.textContent = 'Deleting...';
      api.delete('/api/admin/dashboards/' + id).then(function(r) {
        btn.disabled = false; btn.textContent = 'Delete';
        modal.style.display = 'none';
        if (!r.ok) { if (window.__xrayToast) window.__xrayToast(r.error ? r.error.message : 'Failed to delete', 'error'); return; }
        if (window.__xrayToast) window.__xrayToast('Dashboard deleted', 'success');
        loadDashboards();
      });
    };
  }

  function loadDashboards() {
    api.get('/api/admin/dashboards?limit=100').then(function(r) {
      if (!r.ok) return;
      allItems = r.data.data || r.data || [];
      render();
    });
  }
  loadDashboards();
}

admin_connections.js:
function initAdminConnections(container, api, user) {
  var allConns = [];
  var editingId = null;
  var imageLibrary = [
    {name:'API',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/fastapi/fastapi-original.svg'},
    {name:'Database',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/postgresql/postgresql-original.svg'},
    {name:'Node.js',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/nodejs/nodejs-original.svg'},
    {name:'Google',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/google/google-original.svg'},
    {name:'AWS',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/amazonwebservices/amazonwebservices-original-wordmark.svg'},
    {name:'Azure',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/azure/azure-original.svg'},
    {name:'Python',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/python/python-original.svg'},
    {name:'Docker',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/docker/docker-original.svg'},
    {name:'MySQL',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/mysql/mysql-original.svg'},
    {name:'Redis',url:'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/redis/redis-original.svg'}
  ];
  var selectedImage = '';

  var tbody = container.querySelector('#admin-conn-tbody');
  var emptyEl = container.querySelector('#conn-empty');
  var overlay = container.querySelector('#conn-modal-overlay');
  var search = container.querySelector('#conn-search');
  var filterStatus = container.querySelector('#conn-filter-status');

  function statusBadge(s) {
    return '<span class="status-badge status-' + (s||'pending') + '">' + (s||'pending') + '</span>';
  }

  function renderTable() {
    var q = (search.value || '').toLowerCase();
    var fs = filterStatus.value;
    var filtered = allConns.filter(function(c) {
      if (fs && c.status !== fs) return false;
      if (q && c.name.toLowerCase().indexOf(q) === -1 && (c.tenant_name||'').toLowerCase().indexOf(q) === -1) return false;
      return true;
    });
    if (!filtered.length) {
      tbody.parentElement.style.display = 'none';
      emptyEl.style.display = '';
      return;
    }
    tbody.parentElement.style.display = '';
    emptyEl.style.display = 'none';
    tbody.innerHTML = filtered.map(function(c, i) {
      var img = c.image_url ? '<img src="' + c.image_url + '" alt="">' : '<div style="width:32px;height:32px;border-radius:6px;background:var(--bg4);display:flex;align-items:center;justify-content:center"><svg viewBox="0 0 24 24" width="16" height="16" stroke="var(--t3)" fill="none" stroke-width="1.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="16"/><line x1="8" y1="12" x2="16" y2="12"/></svg></div>';
      return '<tr data-id="' + c.id + '" style="cursor:pointer"><td>' + img + '</td><td><strong>' + c.name + '</strong>' + (c.description ? '<br><span style="font-size:12px;color:var(--t2)">' + c.description.substring(0,80) + '</span>' : '') + '</td><td>' + (c.tenant_name||'-') + '</td><td>' + (c.owner_email||'-') + '</td><td>' + (c.source_type||'-') + '</td><td>' + statusBadge(c.status) + '</td><td>' + new Date(c.created_at).toLocaleDateString() + '</td></tr>';
    }).join('');
    tbody.querySelectorAll('tr').forEach(function(row) {
      row.onclick = function() { openEdit(row.dataset.id); };
    });
  }

  function loadConns() {
    api.get('/api/admin/connections').then(function(r) {
      if (!r.ok) return;
      allConns = r.data.data || r.data || [];
      renderTable();
    });
  }

  search.oninput = renderTable;
  filterStatus.onchange = renderTable;

  // Image library
  var libContainer = container.querySelector('#conn-image-library');
  libContainer.innerHTML = imageLibrary.map(function(img) {
    return '<div class="img-opt" data-url="' + img.url + '" title="' + img.name + '"><img src="' + img.url + '" alt="' + img.name + '"></div>';
  }).join('');
  libContainer.querySelectorAll('.img-opt').forEach(function(el) {
    el.onclick = function() {
      selectedImage = el.dataset.url;
      container.querySelector('#conn-image-url').value = selectedImage;
      libContainer.querySelectorAll('.img-opt').forEach(function(e) { e.classList.remove('selected'); });
      el.classList.add('selected');
      updateImagePreview();
    };
  });
  container.querySelector('#conn-image-url').oninput = function() {
    selectedImage = this.value;
    libContainer.querySelectorAll('.img-opt').forEach(function(e) { e.classList.remove('selected'); });
    updateImagePreview();
  };

  function updateImagePreview() {
    var preview = container.querySelector('#conn-image-preview');
    if (selectedImage) {
      preview.innerHTML = '<img src="' + selectedImage + '" style="width:48px;height:48px;border-radius:8px;object-fit:contain;background:var(--bg4);padding:4px">';
    } else {
      preview.innerHTML = '';
    }
  }

  // Modal
  function openModal(title) {
    container.querySelector('#conn-modal-title').textContent = title;
    overlay.style.display = '';
  }
  function closeModal() { overlay.style.display = 'none'; editingId = null; }

  container.querySelector('#conn-modal-close').onclick = closeModal;
  container.querySelector('#conn-cancel-btn').onclick = closeModal;

  // Add connector
  container.querySelector('#btn-add-connector').onclick = function() {
    editingId = null;
    container.querySelector('#conn-name').value = '';
    container.querySelector('#conn-type').value = 'api';
    container.querySelector('#conn-description').value = '';
    container.querySelector('#conn-details').value = '';
    container.querySelector('#conn-status').value = 'pending';
    container.querySelector('#conn-image-url').value = '';
    selectedImage = '';
    updateImagePreview();
    libContainer.querySelectorAll('.img-opt').forEach(function(e) { e.classList.remove('selected'); });
    container.querySelector('#conn-comments-list').innerHTML = '';
    container.querySelector('#conn-delete-btn').style.display = 'none';
    loadTenants();
    openModal('Add Connector');
  };

  function loadTenants() {
    api.get('/api/admin/tenants?limit=100').then(function(r) {
      if (!r.ok) return;
      var tenants = r.data.data || r.data || [];
      var sel = container.querySelector('#conn-tenant-select');
      sel.innerHTML = tenants.map(function(t) {
        return '<option value="' + t.id + '">' + t.name + (t.owner_email ? ' (' + t.owner_email + ')' : '') + '</option>';
      }).join('');
    });
  }

  function openEdit(connId) {
    var conn = allConns.find(function(c) { return c.id === connId; });
    if (!conn) return;
    editingId = connId;
    loadTenants();
    setTimeout(function() {
      container.querySelector('#conn-tenant-select').value = conn.tenant_id || '';
    }, 200);
    container.querySelector('#conn-name').value = conn.name || '';
    container.querySelector('#conn-type').value = conn.source_type || 'api';
    container.querySelector('#conn-description').value = conn.description || '';
    container.querySelector('#conn-details').value = conn.connection_details || '';
    container.querySelector('#conn-status').value = conn.status || 'pending';
    container.querySelector('#conn-image-url').value = conn.image_url || '';
    selectedImage = conn.image_url || '';
    updateImagePreview();
    libContainer.querySelectorAll('.img-opt').forEach(function(e) {
      e.classList.toggle('selected', e.dataset.url === selectedImage);
    });
    container.querySelector('#conn-delete-btn').style.display = '';
    loadComments(connId);
    openModal('Edit Connector');
  }

  function loadComments(connId) {
    var list = container.querySelector('#conn-comments-list');
    list.innerHTML = '<div style="color:var(--t3);font-size:13px">Loading...</div>';
    api.get('/api/admin/connections/' + connId + '/comments').then(function(r) {
      if (!r.ok || !r.data || !r.data.length) {
        list.innerHTML = '<div style="color:var(--t3);font-size:13px;padding:8px">No comments yet.</div>';
        return;
      }
      list.innerHTML = r.data.map(function(c) {
        return '<div class="comment-item"><div>' + c.content + '</div><div class="comment-meta">' + (c.author_name || c.author_email || 'System') + ' &middot; ' + new Date(c.created_at).toLocaleString() + ' <a href="#" class="del-comment" data-id="' + c.id + '" style="color:var(--danger);margin-left:8px">delete</a></div></div>';
      }).join('');
      list.querySelectorAll('.del-comment').forEach(function(el) {
        el.onclick = function(e) {
          e.preventDefault();
          api.delete('/api/admin/connections/' + editingId + '/comments/' + el.dataset.id).then(function() { loadComments(editingId); });
        };
      });
    });
  }

  container.querySelector('#conn-comment-add').onclick = function() {
    var input = container.querySelector('#conn-comment-input');
    var text = input.value.trim();
    if (!text || !editingId) return;
    api.post('/api/admin/connections/' + editingId + '/comments', { content: text }).then(function(r) {
      if (r.ok) { input.value = ''; loadComments(editingId); }
    });
  };

  // Save
  container.querySelector('#conn-save-btn').onclick = function() {
    var name = container.querySelector('#conn-name').value.trim();
    if (!name) return;
    var payload = {
      name: name,
      sourceType: container.querySelector('#conn-type').value,
      description: container.querySelector('#conn-description').value.trim() || undefined,
      connectionDetails: container.querySelector('#conn-details').value.trim() || undefined,
      imageUrl: selectedImage || undefined,
      status: container.querySelector('#conn-status').value
    };
    if (editingId) {
      api.patch('/api/admin/connections/' + editingId, payload).then(function(r) {
        if (r.ok) { closeModal(); loadConns(); }
      });
    } else {
      payload.tenantId = container.querySelector('#conn-tenant-select').value;
      api.post('/api/admin/connections', payload).then(function(r) {
        if (r.ok) { closeModal(); loadConns(); }
      });
    }
  };

  // Delete
  container.querySelector('#conn-delete-btn').onclick = function() {
    if (!editingId || !confirm('Delete this connection?')) return;
    api.delete('/api/admin/connections/' + editingId).then(function(r) {
      if (r.ok) { closeModal(); loadConns(); }
    });
  };

  loadConns();
}

admin_roles.js:
function initAdminRoles(container, api, user) {
  var allPerms = [];
  var editingRoleId = null;
  var modal = container.querySelector('#role-modal');
  function loadRoles() {
    api.get('/api/roles').then(function(r) {
      if (!r.ok) return;
      var roles = r.data.data || r.data || [];
      container.querySelector('#roles-tbody').innerHTML = roles.map(function(role) {
        var perms = (role.permissions || []).map(function(p) {
          return '<span class="perm-badge">' + p + '</span>';
        }).join('');
        var actions = role.is_system ? '' : '<button class="btn-sm btn-edit" data-id="' + role.id + '">Edit</button> <button class="btn-sm btn-del" data-id="' + role.id + '">Delete</button>';
        return '<tr><td>' + role.name + (role.is_system ? ' <span style="opacity:.5;font-size:11px">(system)</span>' : '') + '</td><td><code>' + role.slug + '</code></td><td>' + perms + '</td><td>' + (role.user_count || '-') + '</td><td>' + actions + '</td></tr>';
      }).join('');
      container.querySelectorAll('.btn-edit').forEach(function(btn) {
        btn.onclick = function() {
          var id = this.getAttribute('data-id');
          var role = roles.find(function(r) { return r.id === id; });
          if (!role) return;
          editingRoleId = id;
          container.querySelector('#role-modal-title').textContent = 'Edit role';
          container.querySelector('#role-name').value = role.name;
          container.querySelector('#role-slug').value = role.slug;
          container.querySelector('#btn-submit-role').textContent = 'Save';
          renderPermCheckboxes(role.permissions || []);
          modal.style.display = 'flex';
        };
      });
      container.querySelectorAll('.btn-del').forEach(function(btn) {
        btn.onclick = function() {
          var id = this.getAttribute('data-id');
          if (!confirm('Delete this role?')) return;
          api.delete('/api/roles/' + id).then(function(r) {
            if (r.ok) loadRoles();
            else alert(r.error ? r.error.message : 'Failed to delete');
          });
        };
      });
    });
  }
  function loadPerms() {
    api.get('/api/roles').then(function(r) {
      if (!r.ok) return;
      var roles = r.data.data || r.data || [];
      var seen = {};
      roles.forEach(function(role) {
        (role.permissions || []).forEach(function(p) { seen[p] = true; });
      });
      allPerms = Object.keys(seen).sort();
    });
  }
  function renderPermCheckboxes(selected) {
    var sel = {};
    (selected || []).forEach(function(p) { sel[p] = true; });
    container.querySelector('#perm-checkboxes').innerHTML = allPerms.map(function(p) {
      return '<label><input type="checkbox" value="' + p + '"' + (sel[p] ? ' checked' : '') + '> ' + p + '</label>';
    }).join('');
  }
  function getSelectedPerms() {
    var perms = [];
    container.querySelectorAll('#perm-checkboxes input:checked').forEach(function(cb) {
      perms.push(cb.value);
    });
    return perms;
  }
  container.querySelector('#btn-create-role').onclick = function() {
    editingRoleId = null;
    container.querySelector('#role-modal-title').textContent = 'Create role';
    container.querySelector('#role-name').value = '';
    container.querySelector('#role-slug').value = '';
    container.querySelector('#btn-submit-role').textContent = 'Create';
    renderPermCheckboxes([]);
    modal.style.display = 'flex';
    container.querySelector('#role-name').focus();
  };
  container.querySelector('#btn-close-role-modal').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#btn-cancel-role').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#role-name').oninput = function() {
    if (!editingRoleId) container.querySelector('#role-slug').value = this.value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
  };
  ['role-name', 'role-slug'].forEach(function(id) {
    container.querySelector('#' + id).onkeydown = function(e) {
      if (e.key === 'Enter') container.querySelector('#btn-submit-role').click();
    };
  });
  container.querySelector('#btn-submit-role').onclick = function() {
    var name = container.querySelector('#role-name').value.trim();
    var slug = container.querySelector('#role-slug').value.trim();
    if (!name || !slug) { alert('Name and slug are required.'); return; }
    var perms = getSelectedPerms();
    var btn = this; btn.disabled = true;
    if (editingRoleId) {
      api.patch('/api/roles/' + editingRoleId, { name: name, slug: slug, permissions: perms }).then(function(r) {
        btn.disabled = false;
        if (!r.ok) { alert(r.error ? r.error.message : 'Failed to update'); return; }
        modal.style.display = 'none';
        loadRoles();
      });
    } else {
      api.post('/api/roles', { name: name, slug: slug, permissions: perms }).then(function(r) {
        btn.disabled = false;
        if (!r.ok) { alert(r.error ? r.error.message : 'Failed to create'); return; }
        modal.style.display = 'none';
        loadRoles();
      });
    }
  };
  loadPerms();
  loadRoles();
}

admin_email.js:
function initAdminEmail(container, api, user) {
  // ─── SMTP Settings ───
  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    (r.data || []).forEach(function(s) {
      var map = { smtp_host: '#email-smtp-host', smtp_port: '#email-smtp-port', smtp_user: '#email-smtp-user', smtp_from: '#email-from', smtp_encryption: '#email-encryption' };
      if (map[s.key]) { var el = container.querySelector(map[s.key]); if (el) el.value = s.value || ''; }
      if (s.key === 'smtp_pass' && s.value) { var pe = container.querySelector('#email-smtp-pass'); if (pe) pe.placeholder = 'Configured (enter new to change)'; }
    });
  });
  container.querySelector('#btn-save-email').onclick = function() {
    var updates = {};
    var fields = { smtp_host: '#email-smtp-host', smtp_port: '#email-smtp-port', smtp_user: '#email-smtp-user', smtp_from: '#email-from', smtp_encryption: '#email-encryption', smtp_pass: '#email-smtp-pass' };
    for (var k in fields) { var v = container.querySelector(fields[k]).value.trim(); if (v) updates[k] = v; }
    if (Object.keys(updates).length === 0) return;
    var btn = this; btn.disabled = true;
    api.patch('/api/admin/settings', updates).then(function(r) {
      btn.disabled = false;
      if (r.ok) { btn.textContent = 'Saved!'; setTimeout(function() { btn.textContent = 'Save'; }, 2000); }
    });
  };
  container.querySelector('#btn-test-email').onclick = function() {
    var btn = this; btn.disabled = true; btn.textContent = 'Sending...';
    api.post('/api/admin/email/test', { to: user.email }).then(function(r) {
      btn.disabled = false;
      btn.textContent = r.ok ? 'Sent!' : 'Failed';
      setTimeout(function() { btn.textContent = 'Send test'; }, 3000);
    });
  };

  // ─── Email Templates ───
  var tplList = container.querySelector('#email-tpl-list');
  var overlay = container.querySelector('#tpl-editor-overlay');
  var editingKey = null;

  function loadTemplates() {
    api.get('/api/admin/email-templates').then(function(r) {
      if (!r.ok || !r.data) return;
      tplList.innerHTML = r.data.map(function(t) {
        var updated = t.updated_at ? new Date(t.updated_at).toLocaleDateString() : '-';
        return '<div class="tpl-item" data-key="' + t.template_key + '">'
          + '<div class="tpl-item-info"><h4>' + t.template_key.replace(/_/g, ' ') + '</h4><p>' + (t.description || t.subject) + '</p></div>'
          + '<div class="tpl-item-meta">Updated: ' + updated + '<br>Vars: ' + (t.variables || []).join(', ') + '</div>'
          + '</div>';
      }).join('');
      tplList.querySelectorAll('.tpl-item').forEach(function(el) {
        el.onclick = function() { openEditor(el.dataset.key); };
      });
    });
  }

  function openEditor(key) {
    editingKey = key;
    container.querySelector('#tpl-editor-title').textContent = 'Edit: ' + key.replace(/_/g, ' ');
    container.querySelector('#tpl-key').value = key;
    // Fetch full template
    api.get('/api/admin/email-templates/' + key).then(function(r) {
      if (!r.ok || !r.data) return;
      var t = r.data;
      container.querySelector('#tpl-desc').value = t.description || '';
      container.querySelector('#tpl-subject').value = t.subject || '';
      container.querySelector('#tpl-body-html').value = t.body_html || '';
      container.querySelector('#tpl-body-text').value = t.body_text || '';
      // Variables
      var vars = t.variables || [];
      container.querySelector('#tpl-vars').innerHTML = vars.map(function(v) {
        return '<span class="tpl-var-tag" data-var="' + v + '">{{' + v + '}}</span>';
      }).join('');
      container.querySelectorAll('.tpl-var-tag').forEach(function(tag) {
        tag.onclick = function() {
          // Insert variable at cursor in focused textarea
          var focused = document.activeElement;
          if (focused && (focused.id === 'tpl-body-html' || focused.id === 'tpl-body-text' || focused.id === 'tpl-subject')) {
            var start = focused.selectionStart;
            var end = focused.selectionEnd;
            var val = focused.value;
            var insert = '{{' + tag.dataset.var + '}}';
            focused.value = val.substring(0, start) + insert + val.substring(end);
            focused.selectionStart = focused.selectionEnd = start + insert.length;
            focused.focus();
          }
        };
      });
      updatePreview();
      overlay.style.display = '';
    });
  }

  function updatePreview() {
    var html = container.querySelector('#tpl-body-html').value;
    var previewDiv = container.querySelector('#tpl-preview');
    // Replace variables with sample values for preview
    var sampleVars = { name: 'John Doe', code: '123456', link: '#', verify_url: '#', invite_url: '#', recovery_url: '#', platform_name: 'XRay BI', tenant_name: 'Acme Corp', inviter_name: 'Admin', email: 'john@example.com' };
    var rendered = html;
    for (var k in sampleVars) {
      rendered = rendered.replace(new RegExp('\\{\\{' + k + '\\}\\}', 'g'), sampleVars[k]);
    }
    var iframe = document.createElement('iframe');
    iframe.style.cssText = 'width:100%;height:300px;border:none';
    previewDiv.innerHTML = '';
    previewDiv.appendChild(iframe);
    var doc = iframe.contentDocument || iframe.contentWindow.document;
    doc.open();
    doc.write('<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{margin:12px;font-family:system-ui,sans-serif;font-size:14px;color:#333}</style></head><body>' + rendered + '</body></html>');
    doc.close();
  }

  // Debounced preview update
  var previewTimer;
  function schedulePreview() {
    clearTimeout(previewTimer);
    previewTimer = setTimeout(updatePreview, 500);
  }

  container.querySelector('#tpl-body-html').oninput = schedulePreview;
  container.querySelector('#tpl-editor-close').onclick = function() { overlay.style.display = 'none'; };
  container.querySelector('#tpl-cancel-btn').onclick = function() { overlay.style.display = 'none'; };

  container.querySelector('#tpl-save-btn').onclick = function() {
    if (!editingKey) return;
    var btn = this; btn.disabled = true;
    api.patch('/api/admin/email-templates/' + editingKey, {
      subject: container.querySelector('#tpl-subject').value,
      bodyHtml: container.querySelector('#tpl-body-html').value,
      bodyText: container.querySelector('#tpl-body-text').value
    }).then(function(r) {
      btn.disabled = false;
      if (r.ok) {
        btn.textContent = 'Saved!';
        setTimeout(function() { btn.textContent = 'Save template'; }, 2000);
        loadTemplates();
      }
    });
  };

  container.querySelector('#tpl-test-btn').onclick = function() {
    if (!editingKey) return;
    var btn = this; btn.disabled = true; btn.textContent = 'Sending...';
    api.post('/api/admin/email-templates/' + editingKey + '/test', {}).then(function(r) {
      btn.disabled = false;
      btn.textContent = r.ok ? 'Sent!' : 'Failed';
      setTimeout(function() { btn.textContent = 'Send test'; }, 3000);
    });
  };

  loadTemplates();
}

admin_stripe.js:
function initAdminStripe(container, api, user) {
  var gateProductIds = [];
  var allProducts = [];

  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    var settings = {};
    (r.data || []).forEach(function(s) { settings[s.key] = s.value; });
    var pk = container.querySelector('#stripe-pk');
    var sk = container.querySelector('#stripe-sk');
    var whSecret = container.querySelector('#stripe-wh-secret');
    var table = container.querySelector('#stripe-table');
    if (pk) pk.value = settings.stripe_publishable_key || '';
    if (sk) sk.value = settings.stripe_secret_key || '';
    if (whSecret) whSecret.value = settings.stripe_webhook_secret || '';
    if (table) table.value = settings.stripe_pricing_table_id || '';
    var portalUrl = container.querySelector('#stripe-portal-url');
    if (portalUrl) portalUrl.value = settings.stripe_portal_url || '';
  });

  var webhookUrl = container.querySelector('#stripe-webhook-url');
  if (webhookUrl) webhookUrl.value = window.location.origin + '/api/stripe/webhook';
  var copyBtn = container.querySelector('#btn-copy-webhook');
  if (copyBtn) {
    copyBtn.onclick = function() {
      navigator.clipboard.writeText(webhookUrl.value).then(function() {
        copyBtn.textContent = 'Copied!';
        setTimeout(function() { copyBtn.textContent = 'Copy'; }, 2000);
      });
    };
  }

  container.querySelector('#btn-save-stripe').onclick = function() {
    var updates = {};
    var pk = container.querySelector('#stripe-pk').value.trim();
    var sk = container.querySelector('#stripe-sk').value.trim();
    var whSecret = container.querySelector('#stripe-wh-secret').value.trim();
    var table = container.querySelector('#stripe-table').value.trim();
    if (pk) updates.stripe_publishable_key = pk;
    if (sk && sk.indexOf('\u2022\u2022') === -1) updates.stripe_secret_key = sk;
    if (whSecret && whSecret.indexOf('\u2022\u2022') === -1) updates.stripe_webhook_secret = whSecret;
    if (table) updates.stripe_pricing_table_id = table;
    var portalUrl = container.querySelector('#stripe-portal-url').value.trim();
    if (portalUrl) updates.stripe_portal_url = portalUrl;
    if (Object.keys(updates).length === 0) return;
    var btn = this; btn.disabled = true;
    api.patch('/api/admin/settings', updates).then(function(r) {
      btn.disabled = false;
      if (r.ok) { if (window.__xrayToast) window.__xrayToast('Stripe keys saved', 'success'); }
      else alert('Failed to save');
    });
  };

  // --- Gate Products (loaded from Stripe) ---
  function loadProducts() {
    var statusEl = container.querySelector('#products-status');
    if (statusEl) statusEl.textContent = 'Loading...';
    api.get('/api/stripe/admin/products').then(function(r) {
      if (statusEl) statusEl.textContent = '';
      if (!r.ok) {
        var list = container.querySelector('#stripe-products-list');
        if (list) list.innerHTML = '<div style="color:var(--danger,#ef4444);font-size:13px">Failed to load products: ' + (r.error ? escHtml(r.error.message) : 'Unknown error') + '</div>';
        return;
      }
      allProducts = r.data || [];
      gateProductIds = allProducts.filter(function(p) { return p.isGateProduct; }).map(function(p) { return p.id; });
      renderProducts();
    }).catch(function() {
      if (statusEl) statusEl.textContent = '';
      var list = container.querySelector('#stripe-products-list');
      if (list) list.innerHTML = '<div style="color:var(--danger,#ef4444);font-size:13px">Network error loading products.</div>';
    });
  }

  function renderProducts() {
    var list = container.querySelector('#stripe-products-list');
    if (!list) return;
    if (allProducts.length === 0) {
      list.innerHTML = '<div style="color:var(--t3);font-size:13px;padding:4px 0">No active products found in Stripe.</div>';
      return;
    }
    var gateSet = {};
    gateProductIds.forEach(function(id) { gateSet[id] = true; });
    var html = '';
    allProducts.forEach(function(p) {
      var isActive = !!gateSet[p.id];
      var btnStyle = isActive
        ? 'background:var(--acc);color:#000;border:1px solid var(--acc);font-weight:600'
        : 'background:var(--bg3);color:var(--t3);border:1px solid var(--bdr)';
      var btnLabel = isActive ? 'Active' : 'Inactive';
      html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px 12px;border:1px solid var(--bdr);border-radius:8px;margin-bottom:6px;background:var(--bg2)">';
      html += '<div style="flex:1;min-width:0"><div style="font-weight:600;font-size:14px;color:var(--t1)">' + escHtml(p.name) + '</div>';
      html += '<div style="font-family:monospace;font-size:11px;color:var(--t3);margin-top:2px">' + escHtml(p.id) + '</div></div>';
      html += '<button class="btn sm gate-toggle-btn" data-pid="' + escHtml(p.id) + '" style="' + btnStyle + ';padding:4px 14px;border-radius:6px;font-size:12px;cursor:pointer;min-width:70px">' + btnLabel + '</button>';
      html += '</div>';
    });
    list.innerHTML = html;
    list.querySelectorAll('.gate-toggle-btn').forEach(function(btn) {
      btn.onclick = function() {
        var pid = this.dataset.pid;
        var idx = gateProductIds.indexOf(pid);
        if (idx >= 0) {
          gateProductIds.splice(idx, 1);
        } else {
          gateProductIds.push(pid);
        }
        // Save and re-render locally immediately
        renderProducts();
        // Save to server then reload from API to confirm
        api.post('/api/stripe/admin/gate-products', { productIds: gateProductIds }).then(function(r) {
          if (r.ok) {
            if (window.__xrayToast) window.__xrayToast('Gate products updated', 'success');
          } else {
            // Fallback to generic settings endpoint if new endpoint not deployed yet
            api.patch('/api/admin/settings', { stripe_gate_products: JSON.stringify(gateProductIds) }).then(function(r2) {
              if (r2.ok) {
                if (window.__xrayToast) window.__xrayToast('Gate products updated', 'success');
              } else {
                alert('Save failed: ' + JSON.stringify(r2.error || r2));
              }
            });
          }
        }).catch(function(e) {
          // Network error — try fallback
          api.patch('/api/admin/settings', { stripe_gate_products: JSON.stringify(gateProductIds) }).then(function(r2) {
            if (r2.ok) { if (window.__xrayToast) window.__xrayToast('Gate products updated', 'success'); }
          }).catch(function() { alert('Network error'); });
        });
        // Reload billing table to reflect new gate access status
        setTimeout(function() { loadBillingTable(); }, 500);
      };
    });
  }

  function saveGateProducts() {
    var body = JSON.stringify({ stripe_gate_products: JSON.stringify(gateProductIds) });
    fetch('/api/admin/settings', {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + (window.getAccessToken ? window.getAccessToken() : '')
      },
      credentials: 'include',
      body: body
    }).then(function(r) { return r.json(); }).then(function(r) {
      if (r.ok) {
        if (window.__xrayToast) window.__xrayToast('Gate products updated', 'success');
      } else {
        alert('Failed to save gate products: ' + JSON.stringify(r.error || r));
      }
    }).catch(function(err) {
      alert('Network error saving gate products: ' + err.message);
    });
  }

  var refreshBtn = container.querySelector('#btn-refresh-products');
  if (refreshBtn) {
    refreshBtn.onclick = function() { loadProducts(); };
  }

  loadProducts();

  api.get('/api/stripe/config').then(function(r) {
    var el = container.querySelector('#stripe-status');
    if (!el) return;
    if (r.ok && r.data && r.data.publishableKey) {
      el.innerHTML = '<span style="color:var(--acc)">&#10003;</span> Stripe is configured. Publishable key and pricing table are set.';
    } else {
      el.innerHTML = '<span style="color:var(--danger)">&#10007;</span> Stripe keys are not configured yet.';
    }
  }).catch(function() {
    var el = container.querySelector('#stripe-status');
    if (el) el.innerHTML = '<span style="color:var(--danger)">&#10007;</span> Could not check Stripe status.';
  });

  // --- Billing table with pagination ---
  var billingData = [];
  var billingPage = 0;
  var billingLimit = 25;

  function loadBillingTable() {
    api.get('/api/stripe/admin/billing').catch(function(err) { var el = container.querySelector('#stripe-billing-list'); if (el) el.innerHTML = '<div style="color:var(--danger,#ef4444)">Network error loading billing data.</div>'; return { ok: false }; }).then(function(r) { if (!r) return;
      var el = container.querySelector('#stripe-billing-list');
      if (!el) return;
      if (!r.ok) {
        el.innerHTML = '<div style="color:var(--danger,#ef4444)">Failed to load billing data: ' + (r.error ? r.error.message : 'Unknown error') + '</div>';
        return;
      }
      if (!r.data || !r.data.length) {
        el.innerHTML = '<div style="color:var(--t3)">No tenants found.</div>';
        return;
      }
      billingData = r.data;
      billingPage = 0;
      if (r.meta && r.meta.stripeInitError) {
        el.insertAdjacentHTML('beforeend', '<div style="color:var(--danger,#ef4444);font-size:13px;margin-bottom:12px;padding:8px 12px;background:rgba(239,68,68,.06);border-radius:6px">Stripe API error: ' + escHtml(r.meta.stripeInitError) + '</div>');
      } else if (r.meta && !r.meta.stripeConnected) {
        el.insertAdjacentHTML('beforeend', '<div style="color:#f59e0b;font-size:13px;margin-bottom:12px;padding:8px 12px;background:rgba(245,158,11,.06);border-radius:6px">Stripe client not initialized. Check secret key in API Keys section above.</div>');
      }
      renderBillingPage();
    });
  }

  function renderBillingPage() {
    var el = container.querySelector('#stripe-billing-list');
    if (!el) return;
    var start = billingPage * billingLimit;
    var pageData = billingData.slice(start, start + billingLimit);
    var totalPages = Math.ceil(billingData.length / billingLimit);

    var html = '<table style="width:100%;border-collapse:collapse;font-size:13px">';
    html += '<thead><tr style="text-align:left;border-bottom:1px solid var(--bdr);color:var(--t3)">';
    html += '<th style="padding:8px 12px">Tenant</th><th style="padding:8px 12px">Owner</th><th style="padding:8px 12px">Gate Access</th><th style="padding:8px 12px">Subscriptions</th><th style="padding:8px 12px">Since</th><th style="padding:8px 12px">Stripe ID</th><th style="padding:8px 12px"></th>';
    html += '</tr></thead><tbody>';
    pageData.forEach(function(t) {
      var accessHtml = '';
      if (t.billingOverride) {
        accessHtml = '<span style="color:var(--acc);font-weight:600">\u2713 Override</span>';
      } else if (t.hasGateAccess) {
        accessHtml = '<span style="color:var(--acc)">\u2713 Active</span>';
      } else {
        accessHtml = '<span style="color:var(--danger,#ef4444)">\u2717 No access</span>';
      }
      var subsHtml = '-';
      if (t.stripeError) {
        subsHtml = '<span style="color:var(--danger,#ef4444);font-size:11px">' + escHtml(t.stripeError) + '</span>';
      } else if (t.stripeSubscriptions && t.stripeSubscriptions.length > 0) {
        subsHtml = t.stripeSubscriptions.map(function(s) {
          var badge = s.isGateProduct ? '<span style="background:rgba(62,232,181,.12);color:var(--acc);padding:1px 5px;border-radius:3px;font-size:10px;font-weight:600;margin-left:4px">GATE</span>' : '';
          var statusColor = s.status === 'active' ? 'var(--acc)' : s.status === 'trialing' ? '#3b82f6' : 'var(--t3)';
          return '<div style="margin-bottom:2px"><span style="color:' + statusColor + '">\u2022</span> ' + escHtml(s.productName) + badge + ' <span style="color:var(--t3);font-size:11px">(' + s.status + ')</span></div>';
        }).join('');
      }
      var sinceDate = t.tenant_created ? new Date(t.tenant_created).toLocaleDateString() : '-';
      html += '<tr style="border-bottom:1px solid var(--bdr)">';
      html += '<td style="padding:10px 12px;color:var(--t1);font-weight:500">' + escHtml(t.tenant_name) + '</td>';
      html += '<td style="padding:10px 12px;font-size:12px">' + escHtml(t.owner_email || '-') + '</td>';
      html += '<td style="padding:10px 12px">' + accessHtml + '</td>';
      html += '<td style="padding:10px 12px;font-size:12px">' + subsHtml + '</td>';
      html += '<td style="padding:10px 12px;font-size:12px">' + sinceDate + '</td>';
      html += '<td style="padding:10px 12px;font-family:monospace;font-size:11px">' + escHtml(t.stripe_customer_id || '-') + '</td>';
      html += '<td style="padding:10px 12px"><button class="btn sm link-stripe-btn" data-tid="' + t.tenant_id + '" data-name="' + escHtml(t.tenant_name) + '" data-cid="' + escHtml(t.stripe_customer_id || '') + '">Link</button> <button class="btn sm debug-stripe-btn" data-cid="' + escHtml(t.stripe_customer_id || '') + '" data-name="' + escHtml(t.tenant_name) + '" style="font-size:11px;opacity:.7">Debug</button></td>';
      html += '</tr>';
    });
    html += '</tbody></table>';
    if (totalPages > 1) {
      html += '<div style="display:flex;align-items:center;justify-content:center;gap:8px;margin-top:12px;font-size:13px;color:var(--t2)">';
      html += '<button class="btn sm" id="bp-prev"' + (billingPage <= 0 ? ' disabled' : '') + '>\u2190 Prev</button>';
      html += '<span>Page ' + (billingPage + 1) + ' of ' + totalPages + '</span>';
      html += '<button class="btn sm" id="bp-next"' + (billingPage >= totalPages - 1 ? ' disabled' : '') + '>Next \u2192</button>';
      html += '</div>';
    }
    el.innerHTML = html;
    var prevB = el.querySelector('#bp-prev');
    var nextB = el.querySelector('#bp-next');
    if (prevB) prevB.onclick = function() { billingPage--; renderBillingPage(); };
    if (nextB) nextB.onclick = function() { billingPage++; renderBillingPage(); };
    el.querySelectorAll('.link-stripe-btn').forEach(function(btn) {
      btn.onclick = function() {
        showLinkModal(this.dataset.tid, this.dataset.name, this.dataset.cid);
      };
    });
    el.querySelectorAll('.debug-stripe-btn').forEach(function(btn) {
      btn.onclick = function() {
        var cid = this.dataset.cid;
        var name = this.dataset.name;
        if (!cid) { alert('No Stripe customer ID for ' + name); return; }
        this.textContent = '...';
        var dbtn = this;
        api.get('/api/stripe/admin/debug/' + cid).then(function(r) {
          dbtn.textContent = 'Debug';
          var msg = 'Debug for ' + name + ' (' + cid + '):\n\n';
          if (!r.ok) {
            msg += 'ERROR: ' + (r.error ? r.error.message : 'Unknown');
          } else {
            var d = r.data;
            msg += 'Key: ' + d.keyPrefix + '\n';
            msg += 'Customer: ' + d.customer.email + ' (' + d.customer.name + ')\n';
            msg += 'Subscriptions: ' + d.subscriptionCount + '\n';
            if (d.subscriptions) {
              d.subscriptions.forEach(function(s) {
                msg += '  - ' + s.productName + ' [' + s.status + '] (product: ' + s.productId + ')\n';
              });
            }
          }
          alert(msg);
        }).catch(function() { dbtn.textContent = 'Debug'; alert('Network error'); });
      };
    });
  }

  function showLinkModal(tid, name, existingCid) {
    var old = document.getElementById('stripe-link-ov');
    if (old) old.remove();
    var ov = document.createElement('div');
    ov.id = 'stripe-link-ov';
    ov.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.65);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px';
    var title = existingCid ? 'Activate Billing for ' + name : 'Link Stripe Customer to ' + name;
    var desc = existingCid
      ? '<p style="color:var(--t2);font-size:13px;margin:0 0 12px">This tenant already has a Stripe customer ID (<code style="color:var(--acc)">' + escHtml(existingCid) + '</code>). Confirm to re-link and activate billing.</p>'
      : '<p style="color:var(--t2);font-size:13px;margin:0 0 12px">Enter the Stripe customer ID from your Stripe Dashboard.</p>';
    ov.innerHTML = '<div style="background:var(--bg1);border:1px solid var(--bdr);border-radius:14px;width:440px;max-width:100%;box-shadow:0 20px 60px rgba(0,0,0,.6)">' +
      '<div style="padding:18px 22px;border-bottom:1px solid var(--bdr);font-weight:600;font-size:15px;color:var(--t1)">' + escHtml(title) + '</div>' +
      '<div style="padding:16px 22px">' + desc + '<input type="text" id="lnk-cid" value="' + escHtml(existingCid || '') + '" placeholder="cus_..." style="width:100%;padding:9px 12px;background:var(--bg3);border:1px solid var(--bdr);border-radius:8px;color:var(--t1);font-size:13px;font-family:monospace;outline:0;box-sizing:border-box"></div>' +
      '<div style="padding:14px 22px;border-top:1px solid var(--bdr);display:flex;gap:8px;justify-content:flex-end"><button class="btn" id="lnk-no">Cancel</button><button class="btn primary" id="lnk-yes">Link & Activate</button></div></div>';
    document.body.appendChild(ov);
    ov.onclick = function(e) { if (e.target === ov) ov.remove(); };
    ov.querySelector('#lnk-no').onclick = function() { ov.remove(); };
    ov.querySelector('#lnk-yes').onclick = function() {
      var cid = ov.querySelector('#lnk-cid').value.trim();
      if (!cid) return;
      this.disabled = true; this.textContent = 'Linking...';
      api.post('/api/stripe/admin/link-customer', { tenantId: tid, stripeCustomerId: cid }).then(function(lr) {
        ov.remove();
        if (lr.ok) {
          if (window.__xrayToast) window.__xrayToast('Linked and activated', 'success');
          loadBillingTable();
        } else { alert('Failed: ' + (lr.error ? lr.error.message : 'Error')); }
      }).catch(function() { ov.remove(); alert('Network error'); });
    };
  }

  // Sync button
  var syncBtn = container.querySelector('#btn-sync-billing');
  var syncStatus = container.querySelector('#sync-status');
  if (syncBtn) {
    syncBtn.onclick = function() {
      syncBtn.disabled = true;
      syncBtn.textContent = 'Syncing...';
      if (syncStatus) syncStatus.textContent = '';
      loadBillingTable();
      setTimeout(function() {
        syncBtn.disabled = false;
        syncBtn.textContent = 'Sync All from Stripe';
        if (syncStatus) syncStatus.textContent = 'Synced: ' + new Date().toLocaleTimeString();
      }, 2000);
    };
  }

  loadBillingTable();

  function escHtml(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }
}

admin_webhooks.js:
function initWebhooks(container, api, user) {
  var tbody = container.querySelector('#webhooks-tbody');
  var emptyEl = container.querySelector('#webhook-empty');
  var modal = container.querySelector('#webhook-modal');
  var banner = container.querySelector('#webhook-secret-banner');

  function loadWebhooks() {
    api.get('/api/webhooks').then(function(r) {
      if (!r.ok) return;
      var hooks = r.data;
      if (hooks.length === 0) {
        emptyEl.style.display = '';
        tbody.parentElement.style.display = 'none';
        return;
      }
      emptyEl.style.display = 'none';
      tbody.parentElement.style.display = '';
      tbody.innerHTML = hooks.map(function(h) {
        var statusBadge = h.is_active ? "<span class='badge active'>Active</span>" : "<span class='badge inactive'>Inactive</span>";
        var lastTriggered = h.last_triggered_at ? new Date(h.last_triggered_at).toLocaleString() : 'Never';
        var eventsStr = (h.events || []).join(', ');
        var urlDisplay = h.target_url || '-';
        if (urlDisplay.length > 50) urlDisplay = urlDisplay.substring(0, 50) + '...';
        return '<tr>'
          + '<td>' + escHtml(h.name) + '</td>'
          + '<td><code style="font-size:11px;word-break:break-all" title="' + escHtml(h.target_url || '') + '">' + escHtml(urlDisplay) + '</code></td>'
          + '<td><span style="font-size:12px;color:var(--t3)">' + escHtml(eventsStr) + '</span></td>'
          + '<td>' + statusBadge + '</td>'
          + '<td>' + lastTriggered + '</td>'
          + '<td>' + h.failure_count + '</td>'
          + '<td><div class="btn-group">'
            + (h.is_active
              ? "<button class='btn sm' onclick='toggleWebhook(\"" + h.id + "\", false)'>Disable</button>"
              : "<button class='btn sm' onclick='toggleWebhook(\"" + h.id + "\", true)'>Enable</button>")
            + "<button class='btn sm' onclick='testWebhook(\"" + h.id + "\")'>Test</button>"
            + "<button class='btn sm danger' onclick='deleteWebhook(\"" + h.id + "\")'>Delete</button>"
          + '</div></td></tr>';
      }).join('');
    });
  }

  container.querySelector('#btn-create-webhook').onclick = function() {
    modal.style.display = 'flex';
    container.querySelector('#webhook-name').value = '';
    container.querySelector('#webhook-url').value = '';
    container.querySelectorAll('#webhook-events input').forEach(function(cb) { cb.checked = cb.defaultChecked; });
  };
  container.querySelector('#btn-close-webhook-modal').onclick = function() { modal.style.display = 'none'; };
  container.querySelector('#btn-cancel-webhook').onclick = function() { modal.style.display = 'none'; };

  container.querySelector('#btn-submit-webhook').onclick = function() {
    var name = container.querySelector('#webhook-name').value.trim();
    var url = container.querySelector('#webhook-url').value.trim();
    var checked = container.querySelectorAll('#webhook-events input:checked');
    var events = [];
    checked.forEach(function(c) { events.push(c.value); });
    if (!name) { alert('Name is required.'); return; }
    if (!url) { alert('Target URL is required.'); return; }
    api.post('/api/webhooks', { name: name, url: url, events: events }).then(function(r) {
      if (!r.ok) { var msg = r.error ? r.error.message : 'Failed to create webhook'; if (r.error && r.error.details) { msg += ': ' + r.error.details.map(function(d) { return d.path + ' - ' + d.message; }).join(', '); } alert(msg); return; }
      modal.style.display = 'none';
      banner.style.display = '';
      container.querySelector('#webhook-created-secret').textContent = r.data.secret || '';
      loadWebhooks();
    });
  };

  var copySecretBtn = container.querySelector('#btn-copy-webhook-secret');
  if (copySecretBtn) {
    copySecretBtn.onclick = function() {
      var text = container.querySelector('#webhook-created-secret').textContent;
      navigator.clipboard.writeText(text).then(function() {
        copySecretBtn.textContent = 'Copied!';
        setTimeout(function() { copySecretBtn.textContent = 'Copy secret'; }, 2000);
      });
    };
  }

  window.toggleWebhook = function(id, active) {
    api.patch('/api/webhooks/' + id, { isActive: active }).then(function() { loadWebhooks(); });
  };

  window.testWebhook = function(id) {
    api.post('/api/webhooks/' + id + '/test').then(function(r) {
      if (r.ok) {
        if (window.__xrayToast) window.__xrayToast('Test event dispatched', 'success');
      } else {
        alert(r.error ? r.error.message : 'Test failed');
      }
    });
  };

  window.deleteWebhook = function(id) {
    if (!confirm('Delete this webhook? Events will no longer be sent to this URL.')) return;
    api.delete('/api/webhooks/' + id).then(function() { loadWebhooks(); });
  };

  function escHtml(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  loadWebhooks();
}

admin_portability.js:
function initAdminPortability(container, api, user) {
  var selectedFile = null;

  // Export
  container.querySelector('#btn-export').onclick = function() {
    var btn = this;
    var status = container.querySelector('#export-status');
    var options = {
      tenants: container.querySelector('#exp-tenants').checked,
      dashboards: container.querySelector('#exp-dashboards').checked,
      connections: container.querySelector('#exp-connections').checked,
      roles: container.querySelector('#exp-roles').checked,
      emailTemplates: container.querySelector('#exp-email').checked,
      connectionTemplates: container.querySelector('#exp-conn-tpl').checked
    };

    btn.disabled = true;
    btn.innerHTML = '<span class="spinner" style="width:14px;height:14px"></span> Exporting...';
    status.style.display = 'block';
    status.className = 'port-status-info';
    status.textContent = 'Generating export archive...';

    fetch('/api/admin/export', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + ((window.getAccessToken ? window.getAccessToken() : '') || '') },
      credentials: 'include',
      body: JSON.stringify(options)
    }).then(function(r) {
      if (!r.ok) return r.text().then(function(t) { throw new Error('Export failed: ' + r.status + ' ' + t); });
      var ct = r.headers.get('content-type') || '';
      if (ct.indexOf('application/zip') === -1 && ct.indexOf('octet') === -1) return r.text().then(function(t) { throw new Error('Unexpected response: ' + t.substring(0,200)); });
      return r.blob();
    }).then(function(blob) {
      var url = URL.createObjectURL(blob);
      var a = document.createElement('a');
      a.href = url;
      a.download = 'xray-export-' + new Date().toISOString().slice(0,10) + '.zip';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      status.className = 'port-status-ok';
      status.textContent = 'Export complete! File size: ' + formatSize(blob.size);
      btn.disabled = false;
      btn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Export ZIP';
    }).catch(function(err) {
      status.className = 'port-status-err';
      status.textContent = 'Export failed: ' + err.message;
      btn.disabled = false;
      btn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Export ZIP';
    });
  };

  // Import
  var dropzone = container.querySelector('#import-dropzone');
  var fileInput = container.querySelector('#import-file');
  var fileInfo = container.querySelector('#import-file-info');
  var importBtn = container.querySelector('#btn-import');

  dropzone.onclick = function() { fileInput.click(); };
  dropzone.ondragover = function(e) { e.preventDefault(); dropzone.classList.add('dragover'); };
  dropzone.ondragleave = function() { dropzone.classList.remove('dragover'); };
  dropzone.ondrop = function(e) {
    e.preventDefault();
    dropzone.classList.remove('dragover');
    var files = e.dataTransfer.files;
    if (files.length && files[0].name.endsWith('.zip')) setFile(files[0]);
  };

  fileInput.onchange = function() {
    if (this.files.length) setFile(this.files[0]);
  };

  function setFile(file) {
    selectedFile = file;
    container.querySelector('#import-file-name').textContent = file.name;
    container.querySelector('#import-file-size').textContent = formatSize(file.size);
    fileInfo.style.display = 'flex';
    dropzone.style.display = 'none';
    importBtn.disabled = false;
  }

  container.querySelector('#import-file-clear').onclick = function() {
    selectedFile = null;
    fileInfo.style.display = 'none';
    dropzone.style.display = '';
    importBtn.disabled = true;
    fileInput.value = '';
  };

  importBtn.onclick = function() {
    if (!selectedFile) return;
    var btn = this;
    var status = container.querySelector('#import-status');
    var results = container.querySelector('#import-results');

    btn.disabled = true;
    btn.innerHTML = '<span class="spinner" style="width:14px;height:14px"></span> Importing...';
    status.style.display = 'block';
    status.className = 'port-status-info';
    status.textContent = 'Uploading and processing archive...';
    results.style.display = 'none';

    var reader = new FileReader();
    reader.onload = function() {
      fetch('/api/admin/import', {
        method: 'POST',
        headers: { 'Content-Type': 'application/zip', 'Authorization': 'Bearer ' + ((window.getAccessToken ? window.getAccessToken() : '') || '') },
        body: reader.result
      }).then(function(r) { return r.json(); }).then(function(r) {
        btn.disabled = false;
        btn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg> Import ZIP';

        if (!r.ok) {
          status.className = 'port-status-err';
          status.textContent = 'Import failed: ' + (r.error ? r.error.message : 'Unknown error');
          return;
        }

        var d = r.data;
        var totalImported = 0, totalSkipped = 0;
        for (var k in d.imported) totalImported += d.imported[k];
        for (var k in d.skipped) totalSkipped += d.skipped[k];

        status.className = 'port-status-ok';
        status.textContent = 'Import complete! ' + totalImported + ' records imported, ' + totalSkipped + ' skipped (already exist).' + (d.errors && d.errors.length ? ' ' + d.errors.length + ' errors.' : '');

        var allKeys = {};
        for (var k in d.imported) allKeys[k] = 1;
        for (var k in d.skipped) allKeys[k] = 1;
        var rows = '';
        for (var k in allKeys) {
          rows += '<tr><td>' + k.replace(/_/g, ' ') + '</td><td class="num" style="color:var(--acc)">' + (d.imported[k] || 0) + '</td><td class="num" style="color:var(--t3)">' + (d.skipped[k] || 0) + '</td></tr>';
        }

        results.style.display = 'block';
        results.innerHTML = '<table class="import-result-table"><thead><tr><th>Section</th><th>Imported</th><th>Skipped</th></tr></thead><tbody>' + rows + '</tbody></table>';

        if (d.errors && d.errors.length) {
          results.innerHTML += '<div style="margin-top:8px;padding:10px;background:rgba(239,68,68,.08);border-radius:8px;font-size:12px;color:var(--danger)">' + d.errors.join('<br>') + '</div>';
        }
      }).catch(function(err) {
        btn.disabled = false;
        btn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg> Import ZIP';
        status.className = 'port-status-err';
        status.textContent = 'Import failed: ' + err.message;
      });
    };
    reader.readAsArrayBuffer(selectedFile);
  };

  function formatSize(bytes) {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / 1048576).toFixed(1) + ' MB';
  }
}

