n-height:0;flex:1}.inbox-mob-back{display:block}.inbox-layout.mob-thread-open .inbox-sidebar{display:none}.inbox-layout:not(.mob-thread-open) .inbox-content{display:none}.inbox-reply-bar{padding-bottom:calc(12px + 70px)}.inbox-view{height:calc(100vh - var(--header-h) - 70px);overflow:hidden}}.inbox-view .fg{margin-bottom:12px}.inbox-view .fg label{display:block;font-size:13px;color:var(--t2);margin-bottom:5px;font-weight:500}.inbox-view .fg input[type="text"],.inbox-view .fg input[type="email"],.inbox-view .fg textarea,.inbox-view .fg select{width:100%;padding:10px 14px;font-family:var(--font);font-size:14px;color:var(--t1);background:var(--bg4);border:1px solid var(--bdr);border-radius:8px;outline:0;box-sizing:border-box}.inbox-view .fg input:focus,.inbox-view .fg textarea:focus,.inbox-view .fg select:focus{border-color:var(--acc)}.inbox-view .fg select{appearance:auto}.inbox-view .fg textarea{resize:vertical;min-height:100px}.inbox-view .modal-foot{display:flex;gap:8px;justify-content:flex-end;padding:16px 0 0}
