function initInbox(container, api, user) {
  var threadList = container.querySelector('#inbox-thread-list');
  var emptyState = container.querySelector('#inbox-empty');
  var contentArea = container.querySelector('#inbox-content');
  var composeModal = container.querySelector('#inbox-compose-modal');
  var searchInput = container.querySelector('#inbox-search');
  var tagFilter = container.querySelector('#inbox-tag-filter');
  var tabInbox = container.querySelector('#inbox-tab-inbox');
  var tabArchive = container.querySelector('#inbox-tab-archive');
  var threads = [];
  var activeThreadId = null;
  var composeRecipients = [];
  var allRecipients = [];
  var allTenants = [];
  var isPlatformAdmin = user && user.is_platform_admin;
  var searchTimeout = null;
  var showArchived = false;
  var starFilter = false;

  // XRay Support pill — show for non-admin users (tenant owners/members)
  var supportPillWrap = container.querySelector('#inbox-support-pill-wrap');
  if (supportPillWrap && !isPlatformAdmin) {
    supportPillWrap.style.display = '';
    container.querySelector('#inbox-support-pill').onclick = function() {
      composeRecipients = [{ id: 'support', name: 'XRay Support', email: 'support', is_support: true }];
      composeModal.style.display = 'flex';
      container.querySelector('#inbox-compose-subject').value = '';
      container.querySelector('#inbox-compose-body').value = '';
      container.querySelector('#inbox-compose-files').value = '';
      container.querySelector('#inbox-compose-to').value = '';
      container.querySelector('#inbox-compose-tag').value = '';
      renderComposeTags();
      loadRecipients();
    };
  }

  // Tabs
  tabInbox.onclick = function() { showArchived = false; tabInbox.classList.add('active'); tabArchive.classList.remove('active'); loadThreads(searchInput.value.trim()); };
  tabArchive.onclick = function() { showArchived = true; tabArchive.classList.add('active'); tabInbox.classList.remove('active'); loadThreads(searchInput.value.trim()); };

  // Tag filter
  tagFilter.onchange = function() { renderThreadList(); };

  // Star filter
  var starFilterBtn = container.querySelector('#inbox-star-filter');
  if (starFilterBtn) {
    starFilterBtn.onclick = function() {
      starFilter = !starFilter;
      this.classList.toggle('active', starFilter);
      this.innerHTML = starFilter ? '\u2605 Starred' : '\u2606 Starred';
      renderThreadList();
    };
  }

  function loadThreads(search) {
    var url = '/api/inbox?limit=50';
    if (search) url += '&search=' + encodeURIComponent(search);
    if (showArchived) url += '&archived=true';
    api.get(url).then(function(r) {
      if (!r.ok) return;
      threads = r.data || [];
      renderThreadList();
    });
  }

  function tagBadge(tag) {
    if (!tag) return '';
    return '<span class="inbox-tag-badge tag-' + tag + '">' + tag.charAt(0).toUpperCase() + tag.slice(1) + '</span>';
  }

  function renderThreadList() {
    var filterTag = tagFilter.value;
    var filtered = threads;
    if (filterTag) filtered = threads.filter(function(t) { return t.tag === filterTag; });
    if (starFilter) filtered = filtered.filter(function(t) { return t.is_starred; });
    if (!filtered.length) {
      threadList.innerHTML = '';
      emptyState.style.display = '';
      return;
    }
    emptyState.style.display = 'none';
    threadList.innerHTML = filtered.map(function(t) {
      var isActive = t.id === activeThreadId;
      var cls = 'inbox-thread-item' + (isActive ? ' active' : '') + (!t.is_read ? ' unread' : '');
      var date = formatDate(t.last_message_at || t.created_at);
      var participantNames = (t.participants || []).filter(function(p) { return p.id !== user.id; }).map(function(p) { return p.name; }).join(', ') || 'You';
      return '<div class="' + cls + '" data-id="' + t.id + '">'
        + '<div class="inbox-thread-top"><span class="inbox-thread-sender">' + escHtml(participantNames) + '</span><span class="inbox-thread-date">' + date + '</span></div>'
        + '<div class="inbox-thread-subject">' + escHtml(t.subject) + tagBadge(t.tag) + '</div>'
        + '<div class="inbox-thread-bottom"><span class="inbox-thread-preview">' + escHtml(t.last_preview || '') + '</span>'
        + '<button class="inbox-thread-star' + (t.is_starred ? ' starred' : '') + '" data-star="' + t.id + '" title="Star">' + (t.is_starred ? '\u2605' : '\u2606') + '</button>'
        + (!t.is_read ? '<span class="inbox-thread-badge">new</span>' : '')
        + '</div></div>';
    }).join('');
    threadList.querySelectorAll('.inbox-thread-item').forEach(function(el) {
      el.onclick = function(e) {
        if (e.target.closest('.inbox-thread-star')) return;
        openThread(this.dataset.id);
      };
    });
    threadList.querySelectorAll('.inbox-thread-star').forEach(function(btn) {
      btn.onclick = function(e) {
        e.stopPropagation();
        var tid = this.dataset.star;
        api.patch('/api/inbox/' + tid + '/star').then(function(r) {
          if (!r.ok) return;
          var t = threads.find(function(th) { return th.id === tid; });
          if (t) t.is_starred = r.data.is_starred;
          renderThreadList();
        });
      };
    });
  }

  function openThread(threadId) {
    activeThreadId = threadId;
    // Mobile: show thread content
    var layout = container.querySelector('.inbox-layout');
    if (layout && window.innerWidth <= 768) layout.classList.add('mob-thread-open');
    renderThreadList();
    contentArea.innerHTML = '<div class="inbox-placeholder"><div class="spinner"></div> Loading...</div>';
    api.get('/api/inbox/' + threadId).then(function(r) {
      if (!r.ok) { contentArea.innerHTML = '<div class="inbox-placeholder">Failed to load messages</div>'; return; }
      var messages = r.data || [];
      var thread = threads.find(function(t) { return t.id === threadId; });
      if (thread) thread.is_read = true;
      renderThreadList();
      renderMessages(threadId, thread, messages);
    });
  }

  function renderMessages(threadId, thread, messages) {
    var participants = thread ? (thread.participants || []).map(function(p) { return p.name; }).join(', ') : '';
    var archiveLabel = (thread && thread.is_archived) ? 'Unarchive' : 'Archive';
    var isResolved = thread && thread.tag === 'resolved';
    var showCloseBtn = user && user.is_platform_admin;
    var html = '<button class="inbox-mob-back" id="inbox-mob-back">\u2190 Back to inbox</button>';
    html += '<div class="inbox-msg-header"><div style="flex:1"><h2>' + escHtml(thread ? thread.subject : '') + tagBadge(thread ? thread.tag : '') + (isResolved ? '<span class="inbox-tag-resolved">Resolved</span>' : '') + '</h2><div class="inbox-msg-participants">' + escHtml(participants) + '</div></div><div style="display:flex;gap:6px;flex-shrink:0">' + (showCloseBtn ? '<button class="inbox-close-btn" id="inbox-close-btn">' + (isResolved ? '\u2713 Resolved' : 'Close ticket') + '</button>' : '') + '<button class="inbox-archive-btn" id="inbox-archive-btn">' + archiveLabel + '</button></div></div>';
    html += '<div class="inbox-msg-list" id="inbox-msg-list-scroll">';
    messages.forEach(function(m) {
      var isSelf = m.sender_id === user.id;
      html += '<div class="inbox-msg-item" data-msg-id="' + m.id + '">'
        + '<div class="inbox-msg-item-head"><span class="inbox-msg-item-sender" style="color:' + (isSelf ? 'var(--acc)' : 'var(--t1)') + '">' + escHtml(m.sender_name || m.sender_email) + '</span><span class="inbox-msg-item-date">' + formatDateTime(m.created_at) + '</span></div>'
        + '<div class="inbox-msg-item-body">' + escHtml(m.body) + '</div>'
        + '<div class="inbox-msg-files" data-msg-id="' + m.id + '"></div>'
        + '</div>';
    });
    html += '</div>';
    html += '<div class="inbox-reply-bar"><button class="inbox-reply-attach" id="inbox-reply-attach-btn" title="Attach files">\ud83d\udcce</button><input type="file" id="inbox-reply-files" multiple style="display:none"><span id="inbox-reply-file-names" class="inbox-reply-file-names"></span><textarea id="inbox-reply-input" rows="2" placeholder="Write a reply..."></textarea><button class="btn primary" id="inbox-reply-send">Send</button></div>';
    contentArea.innerHTML = html;

    // Scroll to bottom (newest messages)
    var msgListEl = contentArea.querySelector('#inbox-msg-list-scroll');
    if (msgListEl) setTimeout(function() { msgListEl.scrollTop = msgListEl.scrollHeight; }, 50);

    // Mobile back button
    var mobBackBtn = contentArea.querySelector('#inbox-mob-back');
    if (mobBackBtn) {
      mobBackBtn.onclick = function() {
        var layout = container.querySelector('.inbox-layout');
        if (layout) layout.classList.remove('mob-thread-open');
        activeThreadId = null;
        renderThreadList();
      };
    }

    // Close ticket button
    var closeBtn = contentArea.querySelector('#inbox-close-btn');
    if (closeBtn) {
      closeBtn.onclick = function() {
        var newTag = (thread && thread.tag === 'resolved') ? null : 'resolved';
        api.patch('/api/inbox/' + threadId + '/tag', { tag: newTag }).then(function(r) {
          if (!r.ok) return;
          if (thread) thread.tag = newTag;
          renderThreadList();
          // Add system message about ticket status
          var statusMsg = newTag ? 'Ticket marked as closed.' : 'Ticket reopened.';
          api.post('/api/inbox', { threadId: threadId, body: statusMsg }).then(function() {
            openThread(threadId);
            loadThreads(searchInput.value.trim());
          });
        });
      };
    }

    // Archive button
    contentArea.querySelector('#inbox-archive-btn').onclick = function() {
      api.patch('/api/inbox/' + threadId + '/archive').then(function(r) {
        if (r.ok) loadThreads(searchInput.value.trim());
      });
    };

    // Load files inline with messages
    loadThreadFilesInline(threadId);

    // Reply attach
    var replyFilesInput = contentArea.querySelector('#inbox-reply-files');
    var fileNamesEl = contentArea.querySelector('#inbox-reply-file-names');
    contentArea.querySelector('#inbox-reply-attach-btn').onclick = function() { replyFilesInput.click(); };
    replyFilesInput.onchange = function() {
      if (replyFilesInput.files && replyFilesInput.files.length > 0) {
        var names = [];
        for (var i = 0; i < replyFilesInput.files.length; i++) names.push(replyFilesInput.files[i].name);
        fileNamesEl.textContent = names.join(', ');
      } else { fileNamesEl.textContent = ''; }
    };

    var replyInput = contentArea.querySelector('#inbox-reply-input');
    contentArea.querySelector('#inbox-reply-send').onclick = function() {
      var body = replyInput.value.trim();
      var hasFiles = replyFilesInput.files && replyFilesInput.files.length > 0;
      if (!body && !hasFiles) return;
      this.disabled = true;
      var btn = this;
      var filesToUpload = hasFiles ? replyFilesInput.files : null;
      var sendBody = body || (hasFiles ? '\ud83d\udcc4 Attachment' : '');
      api.post('/api/inbox', { threadId: threadId, body: sendBody }).then(function(r) {
        btn.disabled = false;
        if (!r.ok) { alert('Failed to send'); return; }
        // Upload reply files if any
        if (filesToUpload) {
          uploadFiles(filesToUpload, 'inbox', threadId, function() {
            openThread(threadId);
            loadThreads(searchInput.value.trim());
          });
        } else {
          openThread(threadId);
          loadThreads(searchInput.value.trim());
        }
        replyInput.value = '';
        replyFilesInput.value = '';
        fileNamesEl.textContent = '';
      });
    };
    replyInput.onkeydown = function(e) {
      if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) contentArea.querySelector('#inbox-reply-send').click();
    };
  }

  function loadThreadFilesInline(threadId) {
    fetch('/api/uploads/context/inbox/' + threadId, { headers: { Authorization: 'Bearer ' + window.getAccessToken() } })
      .then(function(r) { return r.json(); })
      .then(function(r) {
        if (!r.ok || !r.data || !r.data.length) return;
        var files = r.data;
        var msgEls = contentArea.querySelectorAll('.inbox-msg-item[data-msg-id]');
        if (!msgEls.length) return;
        // Attach each file to the last message in the thread (files are uploaded right after sending)
        // If there are multiple messages, attach to the most recent one
        files.forEach(function(f) {
          var targetEl = msgEls[msgEls.length - 1];
          var filesContainer = targetEl.querySelector('.inbox-msg-files');
          if (!filesContainer) return;
          var fileEl = document.createElement('div');
          fileEl.className = 'inbox-file-item clickable';
          fileEl.dataset.url = '/api/uploads/' + f.id + '/download';
          fileEl.dataset.name = f.original_name || f.file_name || 'file';
          fileEl.dataset.mime = f.mime_type || '';
          fileEl.innerHTML = '\ud83d\udcc4 ' + escHtml(f.original_name || f.file_name || 'file');
          fileEl.style.cursor = 'pointer';
          fileEl.onclick = function() {
            if (window.__xrayOpenViewer) window.__xrayOpenViewer(fileEl.dataset.url, fileEl.dataset.name, fileEl.dataset.mime);
            else window.open(fileEl.dataset.url, '_blank');
          };
          filesContainer.appendChild(fileEl);
        });
      }).catch(function() {});
  }

  function uploadFiles(files, contextType, contextId, cb) {
    var fd = new FormData();
    for (var i = 0; i < files.length; i++) fd.append('files', files[i]);
    fd.append('contextType', contextType);
    if (contextId) fd.append('contextId', contextId);
    fetch('/api/uploads', { method: 'POST', headers: { Authorization: 'Bearer ' + window.getAccessToken() }, body: fd })
      .then(function() { if (cb) cb(); })
      .catch(function() { if (cb) cb(); });
  }

  searchInput.oninput = function() {
    clearTimeout(searchTimeout);
    var q = this.value.trim();
    searchTimeout = setTimeout(function() { loadThreads(q); }, 300);
  };

  // Compose
  container.querySelector('#inbox-compose-btn').onclick = function() {
    composeRecipients = [];
    composeModal.style.display = 'flex';
    container.querySelector('#inbox-compose-subject').value = '';
    container.querySelector('#inbox-compose-body').value = '';
    container.querySelector('#inbox-compose-to').value = '';
    container.querySelector('#inbox-compose-tag').value = '';
    container.querySelector('#inbox-compose-files').value = '';
    renderComposeTags();
    loadRecipients();
  };
  container.querySelector('#inbox-compose-close').onclick = function() { composeModal.style.display = 'none'; };
  container.querySelector('#inbox-compose-cancel').onclick = function() { composeModal.style.display = 'none'; };

  function loadRecipients(tenantId) {
    var url = tenantId ? '/api/inbox/recipients/' + tenantId : '/api/inbox/recipients';
    api.get(url).then(function(r) {
      if (!r.ok) return;
      if (tenantId) { allRecipients = r.data || []; }
      else {
        allRecipients = r.data.members || [];
        allTenants = r.data.tenants || [];
        if (isPlatformAdmin && allTenants.length > 0) {
          container.querySelector('#inbox-compose-tenant-row').style.display = '';
          setupTenantSearch(allTenants);
        }
      }
    });
  }

  var toInput = container.querySelector('#inbox-compose-to');
  var toDropdown = container.querySelector('#inbox-compose-to-dropdown');
  toInput.onfocus = function() { showRecipientDropdown(this.value); };
  toInput.oninput = function() { showRecipientDropdown(this.value); };

  function showRecipientDropdown(val) {
    var q = (val || '').toLowerCase();
    var filtered = allRecipients.filter(function(r) {
      if (composeRecipients.find(function(cr) { return cr.id === r.id; })) return false;
      if (!q) return true;
      return (r.name && r.name.toLowerCase().indexOf(q) >= 0) || (r.email && r.email.toLowerCase().indexOf(q) >= 0);
    });
    if (!filtered.length) { toDropdown.style.display = 'none'; return; }
    toDropdown.style.display = '';
    toDropdown.innerHTML = filtered.map(function(r, i) {
      return '<div class="inbox-to-option" data-idx="' + i + '"><span class="opt-name">' + escHtml(r.name) + '</span>' + (r.is_support ? '<span class="opt-support">Support</span>' : '<span class="opt-email">' + escHtml(r.email) + '</span>') + '</div>';
    }).join('');
    toDropdown.querySelectorAll('.inbox-to-option').forEach(function(opt, i) {
      opt.onclick = function() { composeRecipients.push(filtered[i]); toInput.value = ''; toDropdown.style.display = 'none'; renderComposeTags(); };
    });
  };
  toInput.onblur = function() { setTimeout(function() { toDropdown.style.display = 'none'; }, 200); };

  function renderComposeTags() {
    var tagsEl = container.querySelector('#inbox-compose-to-tags');
    tagsEl.innerHTML = composeRecipients.map(function(r, i) {
      return '<span class="inbox-to-tag">' + escHtml(r.name) + '<button data-rm="' + i + '">&times;</button></span>';
    }).join('');
    tagsEl.querySelectorAll('button').forEach(function(btn) {
      btn.onclick = function() { composeRecipients.splice(parseInt(this.dataset.rm), 1); renderComposeTags(); };
    });
  }

  container.querySelector('#inbox-compose-send').onclick = function() {
    var subject = container.querySelector('#inbox-compose-subject').value.trim();
    var body = container.querySelector('#inbox-compose-body').value.trim();
    var tag = container.querySelector('#inbox-compose-tag').value || undefined;
    if (!composeRecipients.length) { alert('Add at least one recipient'); return; }
    if (!subject) { alert('Subject is required'); return; }
    if (!body) { alert('Message is required'); return; }
    var btn = this; btn.disabled = true; btn.textContent = 'Sending...';
    api.post('/api/inbox', {
      recipientIds: composeRecipients.map(function(r) { return r.id; }),
      subject: subject, body: body, tag: tag
    }).then(function(r) {
      btn.disabled = false; btn.textContent = 'Send';
      if (!r.ok) { alert('Failed to send: ' + (r.error ? r.error.message : 'Unknown error')); return; }
      var filesInput = container.querySelector('#inbox-compose-files');
      if (filesInput.files && filesInput.files.length > 0) {
        uploadFiles(filesInput.files, 'inbox', r.data.threadId);
      }
      composeModal.style.display = 'none';
      activeThreadId = r.data.threadId;
      loadThreads();
      setTimeout(function() { openThread(r.data.threadId); }, 300);
    });
  };

  function setupTenantSearch(tenants) {
    var input = container.querySelector('#inbox-compose-tenant-search');
    var dropdown = container.querySelector('#inbox-compose-tenant-dropdown');
    if (!input || !dropdown) return;
    function showTenantDropdown(filter) {
      var q = (filter || '').toLowerCase();
      var filtered = tenants.filter(function(t) { if (!q) return true; return (t.name && t.name.toLowerCase().indexOf(q) >= 0) || (t.slug && t.slug.toLowerCase().indexOf(q) >= 0); });
      if (!filtered.length) { dropdown.innerHTML = '<div style="padding:10px;color:var(--t3);font-size:13px">No tenants found</div>'; dropdown.style.display = ''; return; }
      dropdown.style.display = '';
      dropdown.innerHTML = filtered.map(function(t) {
        return '<div class="inbox-to-option" data-tenant-id="' + t.id + '"><span class="opt-name">' + escHtml(t.name) + '</span><span class="opt-email">' + escHtml(t.slug) + '</span></div>';
      }).join('');
      dropdown.querySelectorAll('.inbox-to-option').forEach(function(opt) {
        opt.onclick = function() { var tid = this.dataset.tenantId; var tn = tenants.find(function(t) { return t.id === tid; }); input.value = tn ? tn.name : ''; dropdown.style.display = 'none'; loadRecipients(tid); composeRecipients = []; renderComposeTags(); };
      });
    }
    input.onfocus = function() { showTenantDropdown(this.value); };
    input.oninput = function() { showTenantDropdown(this.value); };
    input.onblur = function() { setTimeout(function() { dropdown.style.display = 'none'; }, 200); };
  }

  function escHtml(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }
  function formatDate(d) { if (!d) return ''; var dt = new Date(d); var now = new Date(); var diff = now - dt; if (diff < 86400000 && dt.getDate() === now.getDate()) return dt.toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}); if (diff < 604800000) return dt.toLocaleDateString([], {weekday:'short'}); return dt.toLocaleDateString([], {month:'short',day:'numeric'}); }
  function formatDateTime(d) { if (!d) return ''; var dt = new Date(d); return dt.toLocaleDateString() + ' ' + dt.toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}); }

  // Email forwarding toggle
  var fwdToggle = container.querySelector('#inbox-fwd-email');
  if (fwdToggle) {
    // Load current setting
    api.get('/api/users/me/settings').then(function(r) {
      if (r.ok && r.data) fwdToggle.checked = !!r.data.forward_inbox_to_email;
    }).catch(function() {});
    fwdToggle.onchange = function() {
      var enabled = this.checked;
      api.patch('/api/users/me/settings', { forward_inbox_to_email: enabled }).then(function(r) {
        if (r.ok) {
          if (window.__xrayToast) window.__xrayToast(enabled ? 'Email forwarding enabled' : 'Email forwarding disabled', 'info');
        }
      });
    };
  }

  loadThreads();

  // Expose refresh hook for WebSocket real-time updates
  window.__xrayRefreshInboxView = function() {
    loadThreads(searchInput.value.trim());
    if (activeThreadId) openThread(activeThreadId);
    if (window.__xrayRefreshInbox) window.__xrayRefreshInbox();
  };
}

