files.js:
function initFiles(container, api, user) {
  var searchEl = container.querySelector('#files-search');
  var filterTypeEl = container.querySelector('#files-filter-type');
  var filterFileTypeEl = container.querySelector('#files-filter-filetype');
  var filterOwnerEl = container.querySelector('#files-filter-owner');
  var listEl = container.querySelector('#files-list');
  var pagEl = container.querySelector('#files-pagination');
  var uploadBtn = container.querySelector('#files-upload-btn');
  var uploadInput = container.querySelector('#files-upload-input');
  var allFiles = [];
  var total = 0;
  var limit = 25;
  var offset = 0;
  var searchTimer = null;
  var isPlatformAdmin = user && user.is_platform_admin;
  var tenants = [];

  // Platform admin: show owner filter and load tenants
  if (isPlatformAdmin) {
    filterOwnerEl.style.display = '';
    api.get('/api/admin/tenants').then(function(r) {
      if (!r.ok || !r.data) return;
      tenants = Array.isArray(r.data) ? r.data : (r.data.data || []);
      tenants.forEach(function(t) {
        var opt = document.createElement('option');
        opt.value = t.id;
        opt.textContent = t.name;
        filterOwnerEl.appendChild(opt);
      });
    }).catch(function() {});
  }

  function getFileIcon(name, mime) {
    var ext = (name || '').split('.').pop().toLowerCase();
    var imgExts = ['jpg','jpeg','png','gif','svg','webp','bmp','ico'];
    var vidExts = ['mp4','webm','ogg','mov','avi','mkv'];
    var audExts = ['mp3','wav','ogg','flac','aac','m4a'];
    var docExts = ['doc','docx','ppt','pptx'];
    var xlsExts = ['xls','xlsx'];
    if (imgExts.indexOf(ext) !== -1 || (mime && mime.indexOf('image') === 0))
      return '<div class="file-row-icon img">\ud83d\uddbc\ufe0f</div>';
    if (ext === 'pdf') return '<div class="file-row-icon pdf">\ud83d\udcc4</div>';
    if (docExts.indexOf(ext) !== -1) return '<div class="file-row-icon doc">\ud83d\udcc3</div>';
    if (xlsExts.indexOf(ext) !== -1) return '<div class="file-row-icon csv">\ud83d\udcca</div>';
    if (vidExts.indexOf(ext) !== -1 || (mime && mime.indexOf('video') === 0))
      return '<div class="file-row-icon vid">\ud83c\udfac</div>';
    if (audExts.indexOf(ext) !== -1 || (mime && mime.indexOf('audio') === 0))
      return '<div class="file-row-icon aud">\ud83c\udfb5</div>';
    if (ext === 'csv') return '<div class="file-row-icon csv">\ud83d\udcca</div>';
    return '<div class="file-row-icon other">\ud83d\udcc1</div>';
  }

  function getFileCategory(name, mime) {
    var ext = (name || '').split('.').pop().toLowerCase();
    if (['jpg','jpeg','png','gif','svg','webp','bmp','ico'].indexOf(ext) !== -1 || (mime && mime.indexOf('image') === 0)) return 'image';
    if (ext === 'pdf') return 'pdf';
    if (['doc','docx','ppt','pptx'].indexOf(ext) !== -1) return 'doc';
    if (['xls','xlsx'].indexOf(ext) !== -1) return 'spreadsheet';
    if (['mp4','webm','ogg','mov','avi','mkv'].indexOf(ext) !== -1 || (mime && mime.indexOf('video') === 0)) return 'video';
    if (['mp3','wav','flac','aac','m4a'].indexOf(ext) !== -1 || (mime && mime.indexOf('audio') === 0)) return 'audio';
    if (ext === 'csv') return 'csv';
    return 'other';
  }

  function fmtSize(bytes) {
    if (!bytes) return '-';
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / 1048576).toFixed(1) + ' MB';
  }

  function fmtDate(s) {
    if (!s) return '-';
    try {
      var d = new Date(s);
      return d.toLocaleDateString(undefined, {month:'short',day:'numeric',year:'numeric'}) + ' ' +
             d.toLocaleTimeString(undefined, {hour:'2-digit',minute:'2-digit'});
    } catch(e) { return '-'; }
  }

  function escHtml(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  function contextLabel(type) {
    var labels = { connection: 'Connection', inbox: 'Message', invoice: 'Invoice', general: 'General' };
    return labels[type] || type || 'General';
  }

  function loadFiles() {
    var params = '?limit=' + limit + '&offset=' + offset;
    if (filterTypeEl.value) params += '&contextType=' + filterTypeEl.value;
    if (isPlatformAdmin && filterOwnerEl.value === 'me') {
      params += '&tenantId=' + encodeURIComponent(user.tenant_id || '');
    } else if (isPlatformAdmin && filterOwnerEl.value) {
      params += '&tenantId=' + encodeURIComponent(filterOwnerEl.value);
    }
    api.get('/api/uploads' + params).then(function(r) {
      if (!r.ok) { listEl.innerHTML = '<div class="files-empty">Failed to load files.</div>'; return; }
      allFiles = r.data || [];
      total = (r.meta && r.meta.total) || 0;
      renderFiles();
      renderPagination();
    });
  }

  function renderFiles() {
    var q = searchEl.value.toLowerCase();
    var ft = filterFileTypeEl.value;
    var filtered = allFiles;
    if (q) {
      filtered = filtered.filter(function(f) {
        return (f.original_name || '').toLowerCase().indexOf(q) !== -1 ||
               (f.uploader_email || '').toLowerCase().indexOf(q) !== -1 ||
               (f.uploader_name || '').toLowerCase().indexOf(q) !== -1 ||
               (f.tenant_name || '').toLowerCase().indexOf(q) !== -1;
      });
    }
    if (ft) {
      filtered = filtered.filter(function(f) {
        return getFileCategory(f.original_name, f.mime_type) === ft;
      });
    }
    if (!filtered.length) {
      listEl.innerHTML = '<div class="files-empty"><svg viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>' + (total === 0 ? 'No files uploaded yet.<br>Upload files using the button above.' : 'No files match your filters.') + '</div>';
      return;
    }
    listEl.innerHTML = filtered.map(function(f) {
      var downloadUrl = '/api/uploads/' + f.id + '/download';
      var tenantBadge = (isPlatformAdmin && f.tenant_name) ? '<span class="tenant-tag">' + escHtml(f.tenant_name) + '</span>' : '';
      var canShare = isPlatformAdmin && f.uploaded_by === user.id;
      var shareBtn = canShare ? '<button class="share-btn" data-id="' + f.id + '" data-name="' + escHtml(f.original_name || '') + '">Share</button>' : '';
      return '<div class="file-row" data-id="' + f.id + '">' +
        getFileIcon(f.original_name, f.mime_type) +
        '<div class="file-row-info">' +
          '<div class="file-row-name">' + escHtml(f.original_name || 'Unnamed file') + '</div>' +
          '<div class="file-row-meta">' +
            '<span>' + fmtSize(f.size_bytes) + '</span>' +
            '<span>' + contextLabel(f.context_type) + '</span>' +
            tenantBadge +
            '<span>' + fmtDate(f.created_at) + '</span>' +
            (f.uploader_name || f.uploader_email ? '<span>by ' + escHtml(f.uploader_name || f.uploader_email) + '</span>' : '') +
          '</div>' +
        '</div>' +
        '<div class="file-row-actions">' +
          '<button class="view-btn" data-url="' + escHtml(downloadUrl) + '" data-name="' + escHtml(f.original_name || '') + '" data-mime="' + escHtml(f.mime_type || '') + '">View</button>' +
          '<button class="dl-btn" data-url="' + escHtml(downloadUrl) + '" data-name="' + escHtml(f.original_name || '') + '">Download</button>' +
          shareBtn +
          '<button class="del-btn" data-id="' + f.id + '">Delete</button>' +
        '</div></div>';
    }).join('');

    listEl.querySelectorAll('.view-btn').forEach(function(btn) {
      btn.onclick = function(e) { e.stopPropagation(); if (window.__xrayOpenViewer) window.__xrayOpenViewer(this.dataset.url, this.dataset.name, this.dataset.mime); };
    });
    listEl.querySelectorAll('.dl-btn').forEach(function(btn) {
      btn.onclick = function(e) { e.stopPropagation(); var a = document.createElement('a'); a.href = this.dataset.url; a.download = this.dataset.name || 'file'; a.click(); };
    });
    listEl.querySelectorAll('.del-btn').forEach(function(btn) {
      btn.onclick = function(e) {
        e.stopPropagation();
        if (!confirm('Delete this file permanently?')) return;
        api.delete('/api/uploads/' + this.dataset.id).then(function(r) { if (r.ok) loadFiles(); else alert('Failed to delete'); });
      };
    });
    listEl.querySelectorAll('.share-btn').forEach(function(btn) {
      btn.onclick = function(e) { e.stopPropagation(); openShareModal(this.dataset.id, this.dataset.name); };
    });
    listEl.querySelectorAll('.file-row').forEach(function(row) {
      row.onclick = function() {
        var vb = this.querySelector('.view-btn');
        if (vb && window.__xrayOpenViewer) window.__xrayOpenViewer(vb.dataset.url, vb.dataset.name, vb.dataset.mime);
      };
    });
  }

  function renderPagination() {
    if (total <= limit) { pagEl.innerHTML = ''; return; }
    var page = Math.floor(offset / limit) + 1;
    var pages = Math.ceil(total / limit);
    pagEl.innerHTML =
      '<button id="files-prev"' + (page <= 1 ? ' disabled' : '') + '>\u2190 Prev</button>' +
      '<span>Page ' + page + ' of ' + pages + ' (' + total + ' files)</span>' +
      '<button id="files-next"' + (page >= pages ? ' disabled' : '') + '>Next \u2192</button>';
    pagEl.querySelector('#files-prev').onclick = function() { offset = Math.max(0, offset - limit); loadFiles(); };
    pagEl.querySelector('#files-next').onclick = function() { offset += limit; loadFiles(); };
  }

  // ── Share Modal ──
  // ── Share Modal (created dynamically) ──
  var shareFileId = null;
  var selectedTenants = [];
  var _shareOverlay = null;

  function closeShareModal() {
    if (_shareOverlay) { _shareOverlay.remove(); _shareOverlay = null; }
    shareFileId = null;
    selectedTenants = [];
  }

  function openShareModal(fid, fname) {
    closeShareModal();
    shareFileId = fid;
    selectedTenants = [];
    var chosenTenantId = null;

    // Ensure tenants are loaded before building modal
    function buildModal() {
    var ov = document.createElement('div');
    ov.className = 'files-share-overlay';
    ov.innerHTML =
      '<div class="files-share-dialog">' +
        '<div class="files-share-header"><span>Share File</span><button class="files-share-x" id="xshare-close">&times;</button></div>' +
        '<div class="files-share-fname">' + escHtml(fname) + '</div>' +
        '<div class="files-share-section">' +
          '<label>Select Tenant</label>' +
          '<input type="text" class="files-share-search" id="xshare-tenant-search" placeholder="Search tenants..." autocomplete="off">' +
          '<div class="files-share-tlist" id="xshare-tlist"></div>' +
        '</div>' +
        '<div class="files-share-section" id="xshare-members-wrap" style="display:none">' +
          '<label>Share with</label>' +
          '<input type="text" class="files-share-search" id="xshare-member-search" placeholder="Search members..." autocomplete="off">' +
          '<div class="files-share-mlist" id="xshare-mlist"></div>' +
        '</div>' +
        '<div class="files-share-footer"><button class="btn primary" id="xshare-confirm" disabled>Share</button><button class="btn" id="xshare-cancel">Cancel</button></div>' +
      '</div>';
    document.body.appendChild(ov);
    _shareOverlay = ov;

    ov.querySelector('#xshare-close').onclick = closeShareModal;
    ov.querySelector('#xshare-cancel').onclick = closeShareModal;
    ov.onclick = function(e) { if (e.target === ov) closeShareModal(); };

    var tlist = ov.querySelector('#xshare-tlist');
    var tSearch = ov.querySelector('#xshare-tenant-search');
    var membersWrap = ov.querySelector('#xshare-members-wrap');
    var mlist = ov.querySelector('#xshare-mlist');
    var mSearch = ov.querySelector('#xshare-member-search');
    var confirmBtn = ov.querySelector('#xshare-confirm');

    // Render tenant list
    function renderTenants(q) {
      var filtered = tenants;
      if (q) { var lq = q.toLowerCase(); filtered = tenants.filter(function(t) { return t.name.toLowerCase().indexOf(lq) !== -1 || (t.slug || '').toLowerCase().indexOf(lq) !== -1; }); }
      if (!filtered.length) { tlist.innerHTML = '<div class="files-share-empty">No tenants found</div>'; return; }
      tlist.innerHTML = filtered.map(function(t) {
        var sel = t.id === chosenTenantId ? ' selected' : '';
        return '<div class="files-share-tenant-item' + sel + '" data-id="' + t.id + '"><div class="files-share-tenant-name">' + escHtml(t.name) + '</div></div>';
      }).join('');
      tlist.querySelectorAll('.files-share-tenant-item').forEach(function(el) {
        el.onclick = function() {
          chosenTenantId = this.dataset.id;
          tlist.querySelectorAll('.files-share-tenant-item').forEach(function(x) { x.classList.remove('selected'); });
          this.classList.add('selected');
          confirmBtn.disabled = false;
          loadMembers(chosenTenantId);
        };
      });
    }
    renderTenants('');
    tSearch.oninput = function() { renderTenants(this.value.trim()); };

    // Load and render members for selected tenant
    function loadMembers(tid) {
      selectedTenants = [];
      confirmBtn.disabled = true;
      membersWrap.style.display = '';
      mSearch.value = '';
      mlist.innerHTML = '<div style="padding:12px;color:var(--t3);font-size:13px">Loading members...</div>';
      var allMembers = [];
      api.get('/api/admin/tenants/' + tid + '/members').then(function(r) {
        if (!r.ok || !r.data || !r.data.length) { mlist.innerHTML = '<div class="files-share-empty">No members found.</div>'; return; }
        allMembers = r.data;
        renderMembers('');
      }).catch(function() { mlist.innerHTML = '<div class="files-share-empty">Failed to load members.</div>'; });

      mSearch.oninput = function() { renderMembers(this.value.trim()); };

      function renderMembers(q) {
        var filtered = allMembers;
        if (q) { var lq = q.toLowerCase(); filtered = allMembers.filter(function(m) { return (m.name || '').toLowerCase().indexOf(lq) !== -1 || (m.email || '').toLowerCase().indexOf(lq) !== -1; }); }
        var tenant = tenants.find(function(t) { return t.id === tid; });
        var ownerId = tenant ? tenant.owner_user_id : null;
        var h = '<div class="files-share-member" data-id="all"><div class="member-check"></div><div><strong>All members</strong><div style="font-size:11px;color:var(--t3)">Share with everyone in this tenant</div></div></div>';
        filtered.forEach(function(m) {
          var isOwn = m.id === ownerId;
          h += '<div class="files-share-member" data-id="' + m.id + '"><div class="member-check"></div><div>' + escHtml(m.name || m.email) + (m.name ? '<div style="font-size:11px;color:var(--t3)">' + escHtml(m.email) + '</div>' : '') + '</div>' + (isOwn ? '<span class="owner-badge">Owner</span>' : '') + '</div>';
        });
        mlist.innerHTML = h;
        bindMemberClicks();
      }

      function bindMemberClicks() {
        mlist.querySelectorAll('.files-share-member').forEach(function(el) {
          el.onclick = function() {
            var mid = this.dataset.id;
            if (mid === 'all') {
              var wasAll = this.classList.contains('selected');
              mlist.querySelectorAll('.files-share-member').forEach(function(x) { x.classList.remove('selected'); x.querySelector('.member-check').textContent = ''; });
              if (!wasAll) { this.classList.add('selected'); this.querySelector('.member-check').textContent = '\u2713'; selectedTenants = ['all']; }
              else { selectedTenants = []; }
            } else {
              var allEl = mlist.querySelector('[data-id="all"]');
              if (allEl) { allEl.classList.remove('selected'); allEl.querySelector('.member-check').textContent = ''; }
              this.classList.toggle('selected');
              this.querySelector('.member-check').textContent = this.classList.contains('selected') ? '\u2713' : '';
              selectedTenants = [];
              mlist.querySelectorAll('.files-share-member.selected').forEach(function(s) { if (s.dataset.id !== 'all') selectedTenants.push(s.dataset.id); });
            }
            confirmBtn.disabled = selectedTenants.length === 0;
          };
        });
      }
    }

    confirmBtn.onclick = function() {
      if (!shareFileId || !chosenTenantId) return;
      var tid = chosenTenantId;
      confirmBtn.disabled = true;
      confirmBtn.textContent = 'Sharing...';
      api.post('/api/uploads/' + shareFileId + '/share', { tenantId: tid }).then(function(r) {
        confirmBtn.textContent = 'Share';
        if (r.ok) {
          closeShareModal();
          if (window.__xrayToast) window.__xrayToast('File shared successfully', 'success');
          loadFiles();
        } else {
          confirmBtn.disabled = false;
          alert((r.error && r.error.message) || 'Failed to share');
        }
      }).catch(function() { confirmBtn.textContent = 'Share'; confirmBtn.disabled = false; alert('Network error'); });
    };
    } // end buildModal

    if (tenants.length > 0) {
      buildModal();
    } else {
      api.get('/api/admin/tenants').then(function(r) {
        if (r.ok && r.data) tenants = Array.isArray(r.data) ? r.data : (r.data.data || []);
        buildModal();
      }).catch(function() { buildModal(); });
    }
  }

  // ── Upload ──
  uploadBtn.onclick = function() { uploadInput.click(); };
  uploadInput.onchange = function() {
    if (!this.files || this.files.length === 0) return;
    doUpload(this.files);
    uploadInput.value = '';
  };

  function doUpload(fileList) {
    var fd = new FormData();
    for (var i = 0; i < fileList.length; i++) fd.append('files', fileList[i]);
    fd.append('contextType', 'general');
    uploadBtn.disabled = true;
    uploadBtn.textContent = 'Uploading...';
    fetch('/api/uploads', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + (window.getAccessToken ? window.getAccessToken() : '') },
      body: fd,
      credentials: 'include'
    }).then(function(r) { return r.json(); }).then(function(r) {
      uploadBtn.disabled = false;
      uploadBtn.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg> Upload';
      if (r.ok) { offset = 0; loadFiles(); }
      else alert((r.error && r.error.message) || 'Upload failed');
    }).catch(function() {
      uploadBtn.disabled = false;
      uploadBtn.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" stroke="currentColor" fill="none" stroke-width="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg> Upload';
      alert('Network error');
    });
  }

  // Drag and drop
  var dropZone = document.createElement('div');
  dropZone.className = 'file-drop-zone';
  dropZone.textContent = 'Drop files here to upload';
  container.insertBefore(dropZone, container.firstChild);
  var dragCounter = 0;
  container.ondragenter = function(e) { e.preventDefault(); dragCounter++; dropZone.classList.add('active','drag-over'); };
  container.ondragleave = function(e) { e.preventDefault(); dragCounter--; if (dragCounter <= 0) { dragCounter = 0; dropZone.classList.remove('active','drag-over'); } };
  container.ondragover = function(e) { e.preventDefault(); };
  container.ondrop = function(e) {
    e.preventDefault(); dragCounter = 0; dropZone.classList.remove('active','drag-over');
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) doUpload(e.dataTransfer.files);
  };

  // Event handlers
  filterTypeEl.onchange = function() { offset = 0; loadFiles(); };
  filterOwnerEl.onchange = function() { offset = 0; loadFiles(); };
  filterFileTypeEl.onchange = function() { renderFiles(); };
  searchEl.oninput = function() { clearTimeout(searchTimer); searchTimer = setTimeout(renderFiles, 200); };

  loadFiles();
}

