session_replay.js:
function initSessionReplay(container, api, user) {
  var PAGE_SIZE = 25;
  var currentPage = 1;
  var currentSegments = [];
  var totalCount = 0;
  var isPlatform = user && user.is_platform_admin;
  var canManage = isPlatform || (user && (user.is_owner || user.role === 'admin'));

  var searchEl = container.querySelector('#replay-search');
  var filterType = container.querySelector('#replay-filter-type');
  var filterFlag = container.querySelector('#replay-filter-flag');
  var listEl = container.querySelector('#replay-list');
  var pagEl = container.querySelector('#replay-pagination');
  var playerOverlay = container.querySelector('#replay-player-overlay');
  var liveOverlay = container.querySelector('#replay-live-overlay');
  var liveBtn = container.querySelector('#replay-live-btn');

  function fmtDuration(ms) {
    if (!ms) return '-';
    var s = Math.floor(ms / 1000);
    var m = Math.floor(s / 60); s = s % 60;
    return m + ':' + (s < 10 ? '0' : '') + s;
  }

  function fmtDate(d) {
    if (!d) return '-';
    return new Date(d).toLocaleString();
  }

  function esc(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  // ── Load segment list ──
  function loadSegments() {
    var params = '?limit=' + PAGE_SIZE + '&offset=' + ((currentPage - 1) * PAGE_SIZE);
    if (user && user.tenant_id) params += '&tenantId=' + encodeURIComponent(user.tenant_id);
    var q = searchEl.value.trim();
    if (q) params += '&search=' + encodeURIComponent(q);
    var t = filterType.value;
    if (t) params += '&segmentType=' + encodeURIComponent(t);
    var fl = filterFlag.value;
    if (fl === 'training') params += '&training=true';
    if (fl === 'permanent') params += '&permanent=true';

    api.get('/api/v1/replay/segments' + params).then(function(r) {
      if (!r.ok) { listEl.innerHTML = '<div class="replay-no-data">Failed to load segments</div>'; return; }
      var body = r.data || {};
      currentSegments = body.data || body.segments || (Array.isArray(body) ? body : []);
      totalCount = body.total || body.count || currentSegments.length;
      renderList();
      renderPagination();
    });
  }

  function renderList() {
    if (currentSegments.length === 0) {
      listEl.innerHTML = '<div class="replay-no-data">No session recordings found</div>';
      return;
    }
    var html = '<div class="replay-row replay-row-head"><div><input type="checkbox" id="replay-select-all" class="replay-row-check"></div><div>Session</div><div>Type</div><div>Dashboard</div><div>Date</div><div>Duration</div><div>Clicks</div><div>Tags</div><div>Flags</div><div></div></div>';
    currentSegments.forEach(function(seg) {
      var tags = (seg.tags || []).map(function(t) { return '<span class="replay-tag">' + esc(t) + '</span>'; }).join('');
      var flags = '';
      if (seg.is_training) flags += '<span class="replay-flag replay-flag-training">Training</span>';
      if (seg.is_permanent) flags += '<span class="replay-flag replay-flag-permanent">Permanent</span>';
      var liveBadge = seg.session_is_active ? '<span class="replay-live-badge">LIVE</span>' : '';
      html += '<div class="replay-row' + (seg.session_is_active ? ' replay-row-live' : '') + '" data-seg-id="' + seg.id + '" data-session-id="' + (seg.session_id || '') + '" data-is-live="' + (seg.session_is_active ? '1' : '0') + '">';
      html += '<div><input type="checkbox" class="replay-row-check" data-check-id="' + seg.id + '"></div>';
      html += '<div>' + esc(seg.user_name || '-') + (seg.user_email ? ' <span style="color:var(--t3);font-size:12px">' + esc(seg.user_email) + '</span>' : '') + '</div>';
      html += '<div>' + esc(seg.type || seg.segment_type || '-') + ' ' + liveBadge + '</div>';
      html += '<div>' + esc(seg.dashboard_name || '-') + '</div>';
      html += '<div>' + fmtDate(seg.started_at || seg.created_at) + '</div>';
      html += '<div>' + fmtDuration((seg.session_duration_seconds || seg.duration_seconds || 0) * 1000) + '</div>';
      html += '<div>' + (seg.click_count != null ? seg.click_count : '-') + '</div>';
      html += '<div>' + (tags || '-') + '</div>';
      html += '<div>' + (flags || '-') + '</div>';
      html += '<div><button class="replay-del-btn" data-del-id="' + seg.id + '" title="Delete">×</button></div>';
      html += '</div>';
    });
    listEl.innerHTML = html;
  }

  function renderPagination() {
    var pages = Math.ceil(totalCount / PAGE_SIZE);
    if (pages <= 1) { pagEl.innerHTML = ''; return; }
    var html = '';
    for (var i = 1; i <= pages && i <= 10; i++) {
      html += '<button class="' + (i === currentPage ? 'active' : '') + '" data-page="' + i + '">' + i + '</button>';
    }
    if (pages > 10) html += '<button disabled>...</button><button data-page="' + pages + '">' + pages + '</button>';
    pagEl.innerHTML = html;
    pagEl.querySelectorAll('button[data-page]').forEach(function(btn) {
      btn.onclick = function() { currentPage = parseInt(btn.getAttribute('data-page')); 



  loadSegments(); };
    });
  }

  // ── Debounced search ──
  var searchTimer;
  searchEl.oninput = function() { clearTimeout(searchTimer); searchTimer = setTimeout(function() { currentPage = 1; loadSegments(); }, 300); };
  filterType.onchange = function() { currentPage = 1; loadSegments(); };
  filterFlag.onchange = function() { currentPage = 1; loadSegments(); };

  // ── rrweb-player loader ──
  function loadRRWebPlayer(cb) {
    if (window.rrwebPlayer || window.RRWebPlayer) return cb();
    var css = document.createElement('link');
    css.rel = 'stylesheet';
    css.href = 'https://cdn.jsdelivr.net/npm/rrweb-player@latest/dist/style.css';
    document.head.appendChild(css);
    var sc = document.createElement('script');
    sc.src = 'https://cdn.jsdelivr.net/npm/rrweb-player@latest/dist/index.js';
    sc.onload = function() { cb(); };
    sc.onerror = function() { cb(new Error('Failed to load rrweb-player')); };
    document.head.appendChild(sc);
  }

  // ── Player overlay ──
  function openPlayer(segId) {
    playerOverlay.style.display = 'flex';
    playerOverlay.onclick = function(e) { if (e.target === playerOverlay) { playerOverlay.style.display = 'none'; playerOverlay.innerHTML = ''; } };
    playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Loading...</div></div>';

    Promise.all([
      api.get('/api/v1/replay/segments/' + segId),
      api.get('/api/v1/replay/segments/' + segId + '/events'),
      api.get('/api/v1/replay/segments/' + segId + '/comments'),
      api.get('/api/v1/replay/segments/' + segId + '/tags')
    ]).then(function(results) {
      var segR = results[0], evtR = results[1], comR = results[2], tagR = results[3];
      if (!segR.ok) { playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Failed to load segment<br><button class="btn sm" style="margin-top:12px" onclick="document.querySelector(\'#replay-player-overlay\').style.display=\'none\'">Close</button></div></div>'; return; }
      var seg = segR.data || {};
      var events = (evtR.ok ? (evtR.data.data || evtR.data.events || evtR.data || []) : []);
      var comments = (comR.ok ? (comR.data.data || comR.data.comments || comR.data || []) : []);
      var tags = (tagR.ok ? (tagR.data.data || tagR.data.tags || tagR.data || []) : []);

      loadRRWebPlayer(function(err) {
        if (err) { playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Failed to load player<br><button class="btn sm" style="margin-top:12px" onclick="document.querySelector(\'#replay-player-overlay\').style.display=\'none\'">Close</button></div></div>'; return; }

        var html = '<div class="replay-player-main"><button class="replay-player-close" id="rp-close">&times;</button><div id="rp-container"></div></div>';
        html += '<div class="replay-player-sidebar">';

        // Metadata
        html += '<div class="replay-sidebar-section"><h4>Details</h4><div class="replay-sidebar-meta">';
        html += '<span>User:</span> ' + esc(seg.user_name || '-') + (seg.user_email ? ' <span style="color:var(--t3);font-size:12px">' + esc(seg.user_email) + '</span>' : '') + '<br>';
        html += '<span>Dashboard:</span> ' + esc(seg.dashboard_name || '-') + '<br>';
        html += '<span>Date:</span> ' + fmtDate(seg.started_at || seg.created_at) + '<br>';
        html += '<span>Duration:</span> ' + fmtDuration((seg.session_duration_seconds || seg.duration_seconds || 0) * 1000) + '<br>';
        if (seg.viewport_width) html += '<span>Viewport:</span> ' + seg.viewport_width + '&times;' + seg.viewport_height + '<br>';
        html += '<span>Clicks:</span> ' + (seg.click_count != null ? seg.click_count : '-') + '<br>';
        html += '<span>Inputs:</span> ' + (seg.input_count != null ? seg.input_count : '-') + '<br>';
        html += '<span>Storage:</span> <span id="rp-storage">loading...</span><br>';
        html += '</div></div>';

        // Speed controls handled by rrweb player's built-in controls

        // Click Details
        html += '<div class="replay-sidebar-section"><h4>Click Details</h4><div id="rp-clicks" style="max-height:150px;overflow-y:auto;font-size:12px;color:var(--t2)">Loading...</div></div>';

        // Export
        html += '<div class="replay-sidebar-section"><h4>Export</h4><div style="display:flex;gap:8px;flex-wrap:wrap">';
        html += '<button class="btn btn-sm" id="rp-export-json">JSON (AI Review)</button>';
        html += '<button class="btn btn-sm" id="rp-export-csv">CSV</button>';

        html += '</div></div>';

        // Tags
        html += '<div class="replay-sidebar-section"><h4>Tags</h4><div class="replay-tags-list" id="rp-tags">';
        tags.forEach(function(t) {
          var name = t.name || t.tag || t;
          html += '<span class="replay-tag">' + esc(name) + (canManage ? '<span class="replay-tag-remove" data-tag="' + esc(name) + '">&times;</span>' : '') + '</span>';
        });
        html += '</div>';
        if (canManage) html += '<div class="replay-tag-add"><input type="text" id="rp-tag-input" placeholder="Add tag..."><button class="btn btn-sm" id="rp-tag-add-btn">Add</button></div>';
        html += '</div>';

        // Flags
        if (canManage) {
          html += '<div class="replay-sidebar-section"><h4>Flags</h4><div class="replay-flag-toggles">';
          html += '<label><input type="checkbox" id="rp-flag-training"' + (seg.is_training ? ' checked' : '') + '> Training</label>';
          html += '<label><input type="checkbox" id="rp-flag-permanent"' + (seg.is_permanent ? ' checked' : '') + '> Permanent</label>';
          html += '</div></div>';
        }

        // Comments
        html += '<div class="replay-sidebar-section" style="flex:1;display:flex;flex-direction:column"><h4>Comments</h4>';
        html += '<div id="rp-comments" style="flex:1;overflow-y:auto">';
        comments.forEach(function(c) {
          html += '<div class="replay-comment">';
          if (c.timestamp_ms != null) html += '<span class="replay-comment-time" data-ts="' + c.timestamp_ms + '">' + fmtDuration(c.timestamp_ms) + '</span>';
          html += '<span class="replay-comment-author">' + esc(c.user_name || c.user_email || 'Unknown') + '</span>';
          html += esc(c.body || c.text || '') + '</div>';
        });
        html += '</div>';
        html += '<div class="replay-comment-form"><textarea id="rp-comment-text" placeholder="Add a comment..." rows="2"></textarea>';
        html += '<div class="replay-comment-form-actions"><label><input type="checkbox" id="rp-comment-pin"> Pin to current time</label><button class="btn btn-sm" id="rp-comment-submit">Post</button></div>';
        html += '</div></div>';

        html += '</div>';
        playerOverlay.innerHTML = html;

        // Init player
        var playerContainer = playerOverlay.querySelector('#rp-container');
        var playerInstance = null;
        try {
          var RRWebPlayer = window.rrwebPlayer || window.RRWebPlayer || (window.rrweb && window.rrweb.Replayer);
          if (window.rrwebPlayer && window.rrwebPlayer.default) RRWebPlayer = window.rrwebPlayer.default;
          if (!RRWebPlayer && typeof rrwebPlayer !== 'undefined') RRWebPlayer = rrwebPlayer.default || rrwebPlayer;
          console.log('[XRay Replay] Player constructor:', !!RRWebPlayer, 'Events:', events.length, 'FullSnapshots:', events.filter(function(e){return e.type===2}).length);
          if (events.length < 2) {
              playerContainer.innerHTML = '<div class="replay-no-data">This segment has insufficient recording data (' + events.length + ' event' + (events.length !== 1 ? 's' : '') + '). The session was too short to produce a playback.</div>';
            } else {
              playerInstance = new RRWebPlayer({
                target: playerContainer,
                props: {
                  events: events,
                  showController: true,
                  autoPlay: true,
                  speed: 1,
                  showWarning: false,
                  mouseTail: { strokeStyle: 'rgba(74,222,128,0.6)', lineWidth: 2, lineCap: 'round' },
                  insertStyleRules: [
                    '.replayer-mouse-tail{stroke-width:2}',
                    '.replayer-mouse.active::after{content:\'\';position:absolute;width:30px;height:30px;border-radius:50%;border:3px solid rgba(239,68,68,0.8);background:rgba(239,68,68,0.15);top:-15px;left:-15px;pointer-events:none;animation:replay-click-ring 0.8s ease-out forwards}',
                    '@keyframes replay-click-ring{0%{transform:scale(0.3);opacity:1}70%{transform:scale(1.2);opacity:0.6}100%{transform:scale(1.8);opacity:0}}'
                  ]
                }
              });
            }
        } catch(e) { console.error('rrweb player init error', e); playerContainer.innerHTML = '<div class="replay-no-data">Could not initialize player. ' + esc(e.message) + '</div>'; }

        // Fetch storage size
        api.get('/api/v1/replay/segments/' + segId + '/storage').then(function(sr) {
          var el = playerOverlay.querySelector('#rp-storage');
          if (sr.ok && sr.data && el) {
            el.textContent = sr.data.segmentFormatted + ' (session: ' + sr.data.sessionFormatted + ')';
          }
        });

        // Fetch click details
        api.get('/api/v1/replay/segments/' + segId + '/clicks').then(function(cr) {
          var el = playerOverlay.querySelector('#rp-clicks');
          if (!el) return;
          var clickList = cr.ok ? (cr.data.data || cr.data || []) : [];
          if (clickList.length === 0) { el.textContent = 'No clicks recorded'; return; }
          el.innerHTML = clickList.map(function(c, i) {
            var ctx = c.context || {};
            var ctxText = ctx.rowContent ? ctx.rowContent : (ctx.nearbyText && ctx.nearbyText.length ? ctx.nearbyText.join(', ') : '');
            return '<div style="padding:5px 0;border-bottom:1px solid var(--bd);cursor:pointer" class="rp-click-item" data-ts="' + (c.timeOffset || 0) + '" data-x="' + (c.x || 0) + '" data-y="' + (c.y || 0) + '">' +
              '<span style="color:var(--ac);font-weight:600">' + (c.timeFormatted || '-') + '</span> ' +
              '<b>&lt;' + esc(c.element || '?') + '&gt;</b>' +
              (c.text ? ' "' + esc(c.text.substring(0, 50)) + '"' : '') +
              (c.selector ? '<br><span style="font-size:11px;color:var(--t3)">' + esc(c.selector.substring(0, 80)) + '</span>' : '') +
              (ctxText ? '<br><span style="font-size:11px;color:var(--ac2,#8b5cf6)">Row: ' + esc(ctxText.substring(0, 120)) + '</span>' : '') +
              '</div>';
          }).join('');
          // Click on a click detail to seek the player to that time
          el.querySelectorAll('.rp-click-item').forEach(function(item) {
            item.onclick = function() {
              var ts = parseInt(item.getAttribute('data-ts'));
              seekToTime(ts);
            };
          });
        });

        // Export buttons
        var exportJsonBtn = playerOverlay.querySelector('#rp-export-json');
        var exportCsvBtn = playerOverlay.querySelector('#rp-export-csv');
        function downloadExport(segIdExp, fmt) {
          api.get('/api/v1/replay/segments/' + segIdExp + '/export?format=' + fmt).then(function(r) {
            if (!r.ok) { if (window.__xrayToast) window.__xrayToast('Export failed', 'error'); return; }
            var exportData = r.data;
            var content, mimeType, ext;
            if (fmt === 'csv') {
              content = typeof exportData === 'string' ? exportData : JSON.stringify(exportData);
              mimeType = 'text/csv';
              ext = 'csv';
            } else {
              content = JSON.stringify(exportData, null, 2);
              mimeType = 'application/json';
              ext = 'json';
            }
            var blob = new Blob([content], { type: mimeType });
            var url = URL.createObjectURL(blob);
            var a = document.createElement('a');
            a.href = url;
            a.download = 'session-replay-' + segIdExp.substring(0,8) + '.' + ext;
            document.body.appendChild(a); a.click(); document.body.removeChild(a);
            URL.revokeObjectURL(url);
            if (window.__xrayToast) window.__xrayToast('Export downloaded', 'success');
          });
        }
        if (exportJsonBtn) exportJsonBtn.onclick = function() { downloadExport(segId, 'json'); };
        if (exportCsvBtn) exportCsvBtn.onclick = function() { downloadExport(segId, 'csv'); };



        // Close
        playerOverlay.querySelector('#rp-close').onclick = function() { document.removeEventListener('keydown', onKeyDown); _isPlaying = true; playerOverlay.style.display = 'none'; playerOverlay.innerHTML = ''; if (playerInstance && playerInstance.$destroy) playerInstance.$destroy(); };

        // Seeking disabled — rrweb goto skips DOM mutations causing partial renders.
        // Users should watch from start at chosen speed (0.25x–8x).
        function seekToTime(ms) {
          // no-op: seeking is disabled
        }

        // Play/Pause toggle
        var _isPlaying = true;
        function togglePlayPause() {
          if (!playerInstance) return;
          if (_isPlaying) {
            try { playerInstance.pause(); } catch(e) {}
            _isPlaying = false;
          } else {
            try { playerInstance.play(); } catch(e) {}
            _isPlaying = true;
          }
        }

        // Spacebar to pause/play
        function onKeyDown(e) {
          if (e.code === 'Space' && playerOverlay.style.display !== 'none') {
            e.preventDefault();
            togglePlayPause();
          }
        }
        document.addEventListener('keydown', onKeyDown);

        // Click on replay content to pause/play
        var rpMain = playerOverlay.querySelector('.replay-player-main');
        if (rpMain) rpMain.addEventListener('click', function(e) {
          if (e.target.closest('.rr-controller') || e.target.closest('button') || e.target.closest('.replay-player-sidebar')) return;
          togglePlayPause();
        });


        // Speed handled by rrweb player built-in controls

        // Comment timestamps: click to seek
        playerOverlay.querySelectorAll('.replay-comment-time').forEach(function(el) {
          el.onclick = function() { var ts = parseInt(el.getAttribute('data-ts')); seekToTime(ts); };
        });

        // Add tag
        if (canManage) {
          var tagAddBtn = playerOverlay.querySelector('#rp-tag-add-btn');
          var tagInput = playerOverlay.querySelector('#rp-tag-input');
          if (tagAddBtn) tagAddBtn.onclick = function() {
            var v = tagInput.value.trim();
            if (!v) return;
            api.post('/api/v1/replay/segments/' + segId + '/tags', { name: v }).then(function(r) {
              if (r.ok) { tagInput.value = ''; openPlayer(segId); }
            });
          };
          // Remove tag
          playerOverlay.querySelectorAll('.replay-tag-remove').forEach(function(el) {
            el.onclick = function(e) {
              e.stopPropagation();
              var tname = el.getAttribute('data-tag');
              api.del('/api/v1/replay/segments/' + segId + '/tags/' + encodeURIComponent(tname)).then(function(r) { if (r.ok) openPlayer(segId); });
            };
          });

          // Flag toggles
          var trainCb = playerOverlay.querySelector('#rp-flag-training');
          var permCb = playerOverlay.querySelector('#rp-flag-permanent');
          if (trainCb) trainCb.onchange = function() { api.patch('/api/v1/replay/segments/' + segId, { is_training: trainCb.checked }); };
          if (permCb) permCb.onchange = function() { api.patch('/api/v1/replay/segments/' + segId, { is_permanent: permCb.checked }); };
        }

        // Post comment
        var commentSubmit = playerOverlay.querySelector('#rp-comment-submit');
        if (commentSubmit) commentSubmit.onclick = function() {
          var txt = playerOverlay.querySelector('#rp-comment-text').value.trim();
          if (!txt) return;
          var pin = playerOverlay.querySelector('#rp-comment-pin').checked;
          var payload = { body: txt };
          if (pin && playerInstance) {
            try {
              var meta = playerInstance.getMetaData ? playerInstance.getMetaData() : {};
              var ct = playerInstance.getCurrentTime ? playerInstance.getCurrentTime() : 0;
              payload.timestamp_ms = ct;
            } catch(e) {}
          }
          api.post('/api/v1/replay/segments/' + segId + '/comments', payload).then(function(r) {
            if (r.ok) openPlayer(segId);
          });
        };
      });
    });
  }

  // ── Live sessions overlay ──
  liveBtn.onclick = function() { openLiveOverlay(); };

  function openLiveOverlay() {
    liveOverlay.style.display = 'flex';
    liveOverlay.innerHTML = '<div class="replay-live-header"><h3>Live Sessions</h3><button class="replay-player-close" id="rl-close">&times;</button></div><div class="replay-live-list"><div class="replay-no-data">Loading...</div></div>';
    liveOverlay.querySelector('#rl-close').onclick = function() { liveOverlay.style.display = 'none'; liveOverlay.innerHTML = ''; };

    api.get('/api/v1/replay/sessions/active').then(function(r) {
      var sessions = r.ok ? (r.data.data || r.data.sessions || r.data || []) : [];
      var listDiv = liveOverlay.querySelector('.replay-live-list');
      if (!sessions.length) { listDiv.innerHTML = '<div class="replay-no-data">No active sessions</div>'; return; }
      listDiv.innerHTML = sessions.map(function(s) {
        return '<div class="replay-live-row"><div class="replay-live-row-info">' +
          esc(s.user_name || s.user_email || 'Unknown') +
          (s.user_email ? ' <span style="color:var(--t3);font-size:12px">' + esc(s.user_email) + '</span>' : '') +
          '<span>' + esc(s.current_dashboard_name || s.current_segment_type || '-') + ' &middot; Started ' + fmtDate(s.started_at) + '</span></div>' +
          '<button class="btn btn-sm" data-session-id="' + (s.id || s.session_id) + '">Shadow</button></div>';
      }).join('');
      listDiv.querySelectorAll('button[data-session-id]').forEach(function(btn) {
        btn.onclick = function() { openShadow(btn.getAttribute('data-session-id')); };
      });
    });
  }

  function openShadow(sessionId) {
    liveOverlay.style.display = 'none';
    playerOverlay.style.display = 'flex';
    playerOverlay.innerHTML = '<div class="replay-player-main"><button class="replay-player-close" id="rs-close">&times;</button><div id="rs-container"></div></div>' +
      '<div class="replay-player-sidebar"><div class="replay-sidebar-section"><h4>Live Shadow</h4><div class="replay-sidebar-meta">Watching session in real-time.<br>Events stream in as they happen.</div></div></div>';

    loadRRWebPlayer(function(err) {
      if (err) { playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Failed to load player<br><button class="btn sm" style="margin-top:12px" onclick="document.querySelector(\'#replay-player-overlay\').style.display=\'none\'">Close</button></div></div>'; return; }

      var shadowContainer = playerOverlay.querySelector('#rs-container');
      var shadowPlayer = null;
      var shadowEvents = [];

      // Subscribe via WebSocket
      // Subscribe to live events
      if (window.__xrayWs && window.__xrayWs.readyState === 1) {
        window.__xrayWs.send(JSON.stringify({ type: 'replay:shadow-subscribe', data: { sessionId: sessionId } }));
      }

      // Fetch existing events for this session's current segment to pre-populate the player
      api.get('/api/v1/replay/segments?limit=1&sessionId=' + sessionId).then(function(r) {
        var segs = r.ok ? (r.data.data || r.data || []) : [];
        if (segs.length > 0) {
          var latestSeg = segs[0];
          api.get('/api/v1/replay/segments/' + latestSeg.id + '/events').then(function(evtR) {
            var existingEvents = evtR.ok ? (evtR.data.data || evtR.data || []) : [];
            if (existingEvents.length >= 2 && !shadowPlayer) {
              existingEvents.forEach(function(evt) { shadowEvents.push(evt); });
              try {
                var RRWebPlayer = window.rrwebPlayer || window.RRWebPlayer || (window.rrweb && window.rrweb.Player);
                if (!RRWebPlayer && window.rrwebPlayer && window.rrwebPlayer.default) RRWebPlayer = window.rrwebPlayer.default;
                shadowPlayer = new RRWebPlayer({ target: shadowContainer, props: { events: shadowEvents, showController: true, autoPlay: true, liveMode: true } });
              } catch(ex) { console.error('shadow player init from existing events', ex); }
            }
          });
        }
      });

      // Listen for new live events
      function onWsMessage(e) {
        try {
          var msg = JSON.parse(e.data);
          if (msg.type === 'replay:shadow-events' && msg.data && msg.data.sessionId === sessionId) {
            var evts = msg.data.events || [];
            evts.forEach(function(evt) {
              shadowEvents.push(evt);
              if (shadowPlayer) {
                try { shadowPlayer.addEvent(evt); } catch(ex) {}
              }
            });
            if (!shadowPlayer && shadowEvents.length >= 2) {
              try {
                var RRWebPlayer = window.rrwebPlayer || window.RRWebPlayer || (window.rrweb && window.rrweb.Player);
                if (!RRWebPlayer && window.rrwebPlayer && window.rrwebPlayer.default) RRWebPlayer = window.rrwebPlayer.default;
                shadowPlayer = new RRWebPlayer({ target: shadowContainer, props: { events: shadowEvents, showController: true, autoPlay: true, liveMode: true } });
              } catch(ex) { console.error('shadow player init', ex); }
            }
          }
        } catch(ex) {}
      }
      if (window.__xrayWs) window.__xrayWs.addEventListener('message', onWsMessage);

      playerOverlay.querySelector('#rs-close').onclick = function() {
        if (window.__xrayWs && window.__xrayWs.readyState === 1) {
          window.__xrayWs.send(JSON.stringify({ type: 'replay:shadow-unsubscribe', data: { sessionId: sessionId } }));
        }
        if (window.__xrayWs) window.__xrayWs.removeEventListener('message', onWsMessage);
        if (shadowPlayer && shadowPlayer.$destroy) shadowPlayer.$destroy();
        playerOverlay.style.display = 'none';
        playerOverlay.innerHTML = '';
      };
    });
  }

  // Listen for cross-view open requests (e.g. from dashboard detail modal)
  window.addEventListener('xray-open-replay', function(e) {
    if (e.detail && e.detail.segmentId) openPlayer(e.detail.segmentId);
  });

  // Initial load
  loadSegments();

  // ── DELETE + CHECKBOX + ROW CLICK — single delegated handler ──
  listEl.addEventListener('click', function(e) {
    // 1. Delete button
    var db = e.target.closest('.replay-del-btn');
    if (db) {
      e.stopPropagation();
      e.preventDefault();
      var sid = db.getAttribute('data-del-id');
      if (!sid) return;
      var m = document.createElement('div');
      m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:10000;display:flex;align-items:center;justify-content:center';
      m.innerHTML = '<div style="background:var(--bg2);border-radius:10px;padding:24px;max-width:400px;width:90%"><h3 style="margin:0 0 12px;color:var(--t1)">Delete Recording</h3><p style="color:var(--t2);margin:0 0 20px">Delete this recording? This cannot be undone.</p><div style="display:flex;gap:10px;justify-content:flex-end"><button class="btn" data-act="cancel">Cancel</button><button class="btn" data-act="delete" style="background:#ef4444;color:#fff;border-color:#ef4444">Delete</button></div></div>';
      document.body.appendChild(m);
      m.addEventListener('click', function(me) {
        if (me.target.getAttribute('data-act') === 'cancel' || me.target === m) m.remove();
        if (me.target.getAttribute('data-act') === 'delete') {
          api.delete('/api/v1/replay/segments/' + sid).then(function() { m.remove(); loadSegments(); if(window.__xrayToast) window.__xrayToast('Deleted','success'); });
        }
      });
      return;
    }
    // 2. Checkbox
    if (e.target.type === 'checkbox') {
      e.stopPropagation();
      if (e.target.id === 'replay-select-all') {
        _selIds = [];
        listEl.querySelectorAll('input[data-check-id]').forEach(function(c) { c.checked = e.target.checked; if(e.target.checked) _selIds.push(c.getAttribute('data-check-id')); });
      } else {
        var cid = e.target.getAttribute('data-check-id');
        if (cid) { if(e.target.checked) _selIds.push(cid); else _selIds = _selIds.filter(function(x){return x!==cid;}); }
      }
      _updateBulk();
      return;
    }
    // 3. Row click → open player
    var row = e.target.closest('.replay-row:not(.replay-row-head)');
    if (row) {
      if (row.getAttribute('data-is-live') === '1') openShadow(row.getAttribute('data-session-id'));
      else openPlayer(row.getAttribute('data-seg-id'));
    }
  });

  // ── BULK STATE ──
  var _selIds = [];
  function _updateBulk() {
    var bar = container.querySelector('#replay-bulk-bar');
    if (bar) { bar.style.display = _selIds.length > 0 ? 'flex' : 'none'; var c = bar.querySelector('#bulk-count'); if(c) c.textContent = _selIds.length + ' selected'; }
  }
  var _bdb = container.querySelector('#bulk-delete-btn');
  if (_bdb) _bdb.addEventListener('click', function() {
    if (_selIds.length === 0) return;
    var n = _selIds.length;
    var m = document.createElement('div');
    m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:10000;display:flex;align-items:center;justify-content:center';
    m.innerHTML = '<div style="background:var(--bg2);border-radius:10px;padding:24px;max-width:400px;width:90%"><h3 style="margin:0 0 12px;color:var(--t1)">Delete '+n+' Recording'+(n>1?'s':'')+'</h3><p style="color:var(--t2);margin:0 0 20px">This cannot be undone.</p><div style="display:flex;gap:10px;justify-content:flex-end"><button class="btn" data-act="cancel">Cancel</button><button class="btn" data-act="delete" style="background:#ef4444;color:#fff;border-color:#ef4444">Delete</button></div></div>';
    document.body.appendChild(m);
    m.addEventListener('click', function(me) {
      if (me.target.getAttribute('data-act') === 'cancel' || me.target === m) m.remove();
      if (me.target.getAttribute('data-act') === 'delete') {
        Promise.all(_selIds.map(function(id){return api.delete('/api/v1/replay/segments/'+id);})).then(function(){m.remove();_selIds=[];_updateBulk();loadSegments();if(window.__xrayToast)window.__xrayToast('Deleted '+n+' recordings','success');});
      }
    });
  });
  var _bcb = container.querySelector('#bulk-clear-btn');
  if (_bcb) _bcb.addEventListener('click', function() { _selIds = []; listEl.querySelectorAll('input[type=checkbox]').forEach(function(c){c.checked=false;}); _updateBulk(); });



  // Real-time updates: listen for replay events on WebSocket and refresh
  var _refreshTimer = setInterval(function() {
    if (document.contains(container)) loadSegments();

    else clearInterval(_refreshTimer);
  }, 15000);
  // Also listen for WS segment updates for faster refresh
  function _onReplayWs(e) {
    try {
      var msg = JSON.parse(e.data);
      if (msg.type === 'replay:segment-update' || msg.type === 'replay:session-ended' || msg.type === 'replay:events' || msg.type === 'replay:shadow-events') {
        if (document.contains(container)) loadSegments();

      }
    } catch(ex) {}
  }
  if (window.__xrayWs) window.__xrayWs.addEventListener('message', _onReplayWs);
}

admin_replay.css:
.replay-view{max-width:1200px;margin:0 auto;padding:0 16px}
.replay-toolbar{display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px;align-items:center}
.replay-toolbar .toolbar-search{flex:1;min-width:180px;padding:8px 12px;border:1px solid var(--bd);border-radius:6px;background:var(--bg2);color:var(--t1);font-size:14px}
.replay-toolbar .toolbar-select{padding:8px 12px;border:1px solid var(--bd);border-radius:6px;background:var(--bg2);color:var(--t1);font-size:14px}
.replay-list{display:flex;flex-direction:column;gap:2px}
.replay-row{display:grid;grid-template-columns:28px 1fr 1.2fr 0.7fr 1fr 0.9fr 0.5fr 0.4fr 0.8fr 0.6fr 32px;gap:8px;align-items:center;padding:10px 14px;border-radius:6px;cursor:pointer;font-size:13px;color:var(--t1);background:var(--bg2);transition:background .15s}
.replay-row:hover{background:var(--bg3)}
.replay-row-head{font-weight:600;color:var(--t2);font-size:12px;text-transform:uppercase;letter-spacing:.03em;cursor:default;background:transparent}
.replay-row-head:hover{background:transparent}
.replay-tag{display:inline-block;padding:2px 8px;border-radius:10px;font-size:11px;background:var(--ac);color:#fff;margin-right:4px}
.replay-flag{display:inline-block;padding:2px 8px;border-radius:10px;font-size:11px;margin-right:4px}
.replay-flag-training{background:#f59e0b;color:#fff}
.replay-flag-permanent{background:#3b82f6;color:#fff}
.replay-pagination{display:flex;gap:6px;justify-content:center;margin-top:16px}
.replay-pagination button{padding:6px 14px;border:1px solid var(--bd);border-radius:6px;background:var(--bg2);color:var(--t1);cursor:pointer;font-size:13px}
.replay-pagination button.active{background:var(--ac);color:#fff;border-color:var(--ac)}
.replay-pagination button:hover:not(.active){background:var(--bg3)}
.replay-player-overlay{position:fixed;top:0;left:0;right:0;bottom:0;z-index:9999;background:rgba(0,0,0,.85);display:flex}
.replay-player-main{flex:1;display:flex;align-items:center;justify-content:center;position:relative;overflow:hidden}
.replay-player-sidebar{width:340px;background:var(--bg1);border-left:1px solid var(--bd);overflow-y:auto;display:flex;flex-direction:column;padding:20px}
.replay-player-close{position:absolute;top:16px;right:16px;z-index:10;background:rgba(0,0,0,.6);color:#fff;border:none;border-radius:50%;width:36px;height:36px;font-size:20px;cursor:pointer;display:flex;align-items:center;justify-content:center}
.replay-player-close:hover{background:rgba(255,255,255,.2)}
.replay-sidebar-section{margin-bottom:16px}
.replay-sidebar-section h4{font-size:13px;font-weight:600;color:var(--t2);margin-bottom:8px;text-transform:uppercase;letter-spacing:.03em}
.replay-sidebar-meta{font-size:13px;color:var(--t1);line-height:1.8}
.replay-sidebar-meta span{color:var(--t2)}
.replay-speed-btns{display:flex;gap:4px;flex-wrap:wrap}
.replay-speed-btns button{padding:4px 10px;border:1px solid var(--bd);border-radius:4px;background:var(--bg2);color:var(--t1);cursor:pointer;font-size:12px}
.replay-speed-btns button.active{background:var(--ac);color:#fff;border-color:var(--ac)}
.replay-comment{padding:8px 0;border-bottom:1px solid var(--bd);font-size:13px;color:var(--t1)}
.replay-comment-time{font-size:11px;color:var(--ac);cursor:pointer;margin-right:6px}
.replay-comment-author{font-size:11px;color:var(--t2);margin-right:6px}
.replay-comment-form{display:flex;flex-direction:column;gap:6px;margin-top:8px}
.replay-comment-form textarea{padding:8px;border:1px solid var(--bd);border-radius:6px;background:var(--bg2);color:var(--t1);font-size:13px;resize:vertical;min-height:40px}
.replay-comment-form-actions{display:flex;gap:8px;align-items:center}
.replay-comment-form-actions label{font-size:12px;color:var(--t2);display:flex;align-items:center;gap:4px}
.replay-tags-list{display:flex;flex-wrap:wrap;gap:4px;margin-bottom:6px}
.replay-tag-remove{cursor:pointer;margin-left:4px;opacity:.7}
.replay-tag-remove:hover{opacity:1}
.replay-tag-add{display:flex;gap:4px}
.replay-tag-add input{flex:1;padding:4px 8px;border:1px solid var(--bd);border-radius:4px;background:var(--bg2);color:var(--t1);font-size:12px}
.replay-flag-toggles{display:flex;gap:8px;flex-wrap:wrap;margin-top:6px}
.replay-flag-toggles label{font-size:12px;color:var(--t1);display:flex;align-items:center;gap:4px;cursor:pointer}
.replay-live-overlay{position:fixed;top:0;left:0;right:0;bottom:0;z-index:9998;background:rgba(0,0,0,.85);display:flex;flex-direction:column}
.replay-live-header{display:flex;align-items:center;justify-content:space-between;padding:16px 24px;border-bottom:1px solid var(--bd)}
.replay-live-header h3{color:#fff;margin:0;font-size:16px}
.replay-live-list{flex:1;overflow-y:auto;padding:16px 24px}
.replay-live-row{display:flex;align-items:center;justify-content:space-between;padding:12px 16px;background:var(--bg2);border-radius:8px;margin-bottom:8px}
.replay-live-row-info{font-size:13px;color:var(--t1)}
.replay-live-row-info span{display:block;font-size:12px;color:var(--t2)}
.replay-no-data{text-align:center;padding:60px 24px;color:var(--t2);font-size:14px}
@media(max-width:900px){
  .replay-row{grid-template-columns:1fr 1fr 1fr;font-size:12px}
  .replay-row>:nth-child(n+4){display:none}
  .replay-row-head>:nth-child(n+4){display:none}
  .replay-player-overlay{flex-direction:column}
  .replay-player-sidebar{width:100%;max-height:40vh;border-left:none;border-top:1px solid var(--bd)}
}
.replay-dash-mini{margin-top:8px}
.replay-dash-mini .replay-row{grid-template-columns:1fr 1fr 0.8fr 0.5fr 0.5fr;font-size:12px}
::-webkit-scrollbar{width:6px}::-webkit-scrollbar-track{background:var(--bg2)}::-webkit-scrollbar-thumb{background:var(--bdr);border-radius:3px}::-webkit-scrollbar-thumb:hover{background:var(--t3)}
.replay-live-badge{display:inline-block;padding:1px 6px;border-radius:8px;font-size:10px;font-weight:700;background:#ef4444;color:#fff;animation:replay-pulse 2s infinite;vertical-align:middle;margin-left:4px}
@keyframes replay-pulse{0%,100%{opacity:1}50%{opacity:.5}}
.replay-row-live{border-left:3px solid #ef4444}
.btn-icon.replay-delete-btn{width:28px;height:28px;padding:0;border:none;background:transparent;color:var(--t3);font-size:18px;cursor:pointer;border-radius:4px;display:flex;align-items:center;justify-content:center;transition:all .15s}
.btn-icon.replay-delete-btn:hover{background:rgba(239,68,68,.15);color:#ef4444}
@keyframes rp-marker{0%{transform:scale(0.5);opacity:1}50%{transform:scale(2);opacity:0.7}100%{transform:scale(3);opacity:0}}
.replay-row-check{width:16px;height:16px;accent-color:var(--ac);cursor:pointer}
#replay-select-all{width:16px;height:16px;accent-color:var(--ac);cursor:pointer}
.replay-del-btn{width:28px;height:28px;padding:0;border:1px solid #ef4444;background:transparent;color:#ef4444;font-size:16px;cursor:pointer;border-radius:4px;display:flex;align-items:center;justify-content:center;transition:all .15s;font-weight:bold}
.replay-del-btn:hover{background:#ef4444;color:#fff}
.rr-progress{pointer-events:none;opacity:.5}

admin_replay.js:
function initAdminReplay(container, api, user) {
  var PAGE_SIZE = 25;
  var currentPage = 1;
  var currentSegments = [];
  var totalCount = 0;
  var isPlatform = user && user.is_platform_admin;
  var canManage = isPlatform || (user && (user.is_owner || user.role === 'admin'));

  var searchEl = container.querySelector('#ar-search');
  var filterType = container.querySelector('#ar-filter-type');
  var filterFlag = container.querySelector('#ar-filter-flag');
  var listEl = container.querySelector('#ar-list');
  var pagEl = container.querySelector('#ar-pagination');
  var playerOverlay = container.querySelector('#ar-player-overlay');
  var liveOverlay = container.querySelector('#ar-live-overlay');
  var liveBtn = container.querySelector('#ar-live-btn');

  function fmtDuration(ms) {
    if (!ms) return '-';
    var s = Math.floor(ms / 1000);
    var m = Math.floor(s / 60); s = s % 60;
    return m + ':' + (s < 10 ? '0' : '') + s;
  }

  function fmtDate(d) {
    if (!d) return '-';
    return new Date(d).toLocaleString();
  }

  function esc(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  // ── Load segment list ──
  function loadSegments() {
    var params = '?limit=' + PAGE_SIZE + '&offset=' + ((currentPage - 1) * PAGE_SIZE);
    var q = searchEl.value.trim();
    if (q) params += '&search=' + encodeURIComponent(q);
    var t = filterType.value;
    if (t) params += '&segmentType=' + encodeURIComponent(t);
    var fl = filterFlag.value;
    if (fl === 'training') params += '&training=true';
    if (fl === 'permanent') params += '&permanent=true';

    api.get('/api/v1/replay/segments' + params).then(function(r) {
      if (!r.ok) { listEl.innerHTML = '<div class="replay-no-data">Failed to load segments</div>'; return; }
      var body = r.data || {};
      currentSegments = body.data || body.segments || (Array.isArray(body) ? body : []);
      totalCount = body.total || body.count || currentSegments.length;
      renderList();
      renderPagination();
    });
  }

  function renderList() {
    if (currentSegments.length === 0) {
      listEl.innerHTML = '<div class="replay-no-data">No session recordings found</div>';
      return;
    }
    var html = '<div class="replay-row replay-row-head"><div><input type="checkbox" id="ar-select-all" class="replay-row-check"></div><div>Tenant</div><div>Session</div><div>Type</div><div>Dashboard</div><div>Date</div><div>Duration</div><div>Clicks</div><div>Tags</div><div>Flags</div><div></div></div>';
    currentSegments.forEach(function(seg) {
      var tags = (seg.tags || []).map(function(t) { return '<span class="replay-tag">' + esc(t) + '</span>'; }).join('');
      var flags = '';
      if (seg.is_training) flags += '<span class="replay-flag replay-flag-training">Training</span>';
      if (seg.is_permanent) flags += '<span class="replay-flag replay-flag-permanent">Permanent</span>';
      var liveBadge = seg.session_is_active ? '<span class="replay-live-badge">LIVE</span>' : '';
      html += '<div class="replay-row' + (seg.session_is_active ? ' replay-row-live' : '') + '" data-seg-id="' + seg.id + '" data-session-id="' + (seg.session_id || '') + '" data-is-live="' + (seg.session_is_active ? '1' : '0') + '">';
      html += '<div><input type="checkbox" class="replay-row-check" data-check-id="' + seg.id + '"></div>';
      html += '<div>' + esc(seg.tenant_name || '-') + '</div>';
      html += '<div>' + esc(seg.user_name || '-') + (seg.user_email ? ' <span style="color:var(--t3);font-size:12px">' + esc(seg.user_email) + '</span>' : '') + '</div>';
      html += '<div>' + esc(seg.type || seg.segment_type || '-') + ' ' + liveBadge + '</div>';
      html += '<div>' + esc(seg.dashboard_name || '-') + '</div>';
      html += '<div>' + fmtDate(seg.started_at || seg.created_at) + '</div>';
      html += '<div>' + fmtDuration((seg.session_duration_seconds || seg.duration_seconds || 0) * 1000) + '</div>';
      html += '<div>' + (seg.click_count != null ? seg.click_count : '-') + '</div>';
      html += '<div>' + (tags || '-') + '</div>';
      html += '<div>' + (flags || '-') + '</div>';
      html += '<div><button class="replay-del-btn" data-del-id="' + seg.id + '" title="Delete">×</button></div>';
      html += '</div>';
    });
    listEl.innerHTML = html;
  }

  function renderPagination() {
    var pages = Math.ceil(totalCount / PAGE_SIZE);
    if (pages <= 1) { pagEl.innerHTML = ''; return; }
    var html = '';
    for (var i = 1; i <= pages && i <= 10; i++) {
      html += '<button class="' + (i === currentPage ? 'active' : '') + '" data-page="' + i + '">' + i + '</button>';
    }
    if (pages > 10) html += '<button disabled>...</button><button data-page="' + pages + '">' + pages + '</button>';
    pagEl.innerHTML = html;
    pagEl.querySelectorAll('button[data-page]').forEach(function(btn) {
      btn.onclick = function() { currentPage = parseInt(btn.getAttribute('data-page')); 



  loadSegments(); };
    });
  }

  // ── Debounced search ──
  var searchTimer;
  searchEl.oninput = function() { clearTimeout(searchTimer); searchTimer = setTimeout(function() { currentPage = 1; loadSegments(); }, 300); };
  filterType.onchange = function() { currentPage = 1; loadSegments(); };
  filterFlag.onchange = function() { currentPage = 1; loadSegments(); };

  // ── rrweb-player loader ──
  function loadRRWebPlayer(cb) {
    if (window.rrwebPlayer || window.RRWebPlayer) return cb();
    var css = document.createElement('link');
    css.rel = 'stylesheet';
    css.href = 'https://cdn.jsdelivr.net/npm/rrweb-player@latest/dist/style.css';
    document.head.appendChild(css);
    var sc = document.createElement('script');
    sc.src = 'https://cdn.jsdelivr.net/npm/rrweb-player@latest/dist/index.js';
    sc.onload = function() { cb(); };
    sc.onerror = function() { cb(new Error('Failed to load rrweb-player')); };
    document.head.appendChild(sc);
  }

  // ── Player overlay ──
  function openPlayer(segId) {
    playerOverlay.style.display = 'flex';
    playerOverlay.onclick = function(e) { if (e.target === playerOverlay) { playerOverlay.style.display = 'none'; playerOverlay.innerHTML = ''; } };
    playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Loading...</div></div>';

    Promise.all([
      api.get('/api/v1/replay/segments/' + segId),
      api.get('/api/v1/replay/segments/' + segId + '/events'),
      api.get('/api/v1/replay/segments/' + segId + '/comments'),
      api.get('/api/v1/replay/segments/' + segId + '/tags')
    ]).then(function(results) {
      var segR = results[0], evtR = results[1], comR = results[2], tagR = results[3];
      if (!segR.ok) { playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Failed to load segment<br><button class="btn sm" style="margin-top:12px" onclick="document.querySelector(\'#replay-player-overlay\').style.display=\'none\'">Close</button></div></div>'; return; }
      var seg = segR.data || {};
      var events = (evtR.ok ? (evtR.data.data || evtR.data.events || evtR.data || []) : []);
      var comments = (comR.ok ? (comR.data.data || comR.data.comments || comR.data || []) : []);
      var tags = (tagR.ok ? (tagR.data.data || tagR.data.tags || tagR.data || []) : []);

      loadRRWebPlayer(function(err) {
        if (err) { playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Failed to load player<br><button class="btn sm" style="margin-top:12px" onclick="document.querySelector(\'#replay-player-overlay\').style.display=\'none\'">Close</button></div></div>'; return; }

        var html = '<div class="replay-player-main"><button class="replay-player-close" id="rp-close">&times;</button><div id="rp-container"></div></div>';
        html += '<div class="replay-player-sidebar">';

        // Metadata
        html += '<div class="replay-sidebar-section"><h4>Details</h4><div class="replay-sidebar-meta">';
        html += '<span>Tenant:</span> ' + esc(seg.tenant_name || '-') + '<br>';
        html += '<span>User:</span> ' + esc(seg.user_name || '-') + (seg.user_email ? ' <span style="color:var(--t3);font-size:12px">' + esc(seg.user_email) + '</span>' : '') + '<br>';
        html += '<span>Dashboard:</span> ' + esc(seg.dashboard_name || '-') + '<br>';
        html += '<span>Date:</span> ' + fmtDate(seg.started_at || seg.created_at) + '<br>';
        html += '<span>Duration:</span> ' + fmtDuration((seg.session_duration_seconds || seg.duration_seconds || 0) * 1000) + '<br>';
        if (seg.viewport_width) html += '<span>Viewport:</span> ' + seg.viewport_width + '&times;' + seg.viewport_height + '<br>';
        html += '<span>Clicks:</span> ' + (seg.click_count != null ? seg.click_count : '-') + '<br>';
        html += '<span>Inputs:</span> ' + (seg.input_count != null ? seg.input_count : '-') + '<br>';
        html += '<span>Storage:</span> <span id="rp-storage">loading...</span><br>';
        html += '</div></div>';

        // Speed controls handled by rrweb player's built-in controls

        // Click Details
        html += '<div class="replay-sidebar-section"><h4>Click Details</h4><div id="rp-clicks" style="max-height:150px;overflow-y:auto;font-size:12px;color:var(--t2)">Loading...</div></div>';

        // Export
        html += '<div class="replay-sidebar-section"><h4>Export</h4><div style="display:flex;gap:8px;flex-wrap:wrap">';
        html += '<button class="btn btn-sm" id="rp-export-json">JSON (AI Review)</button>';
        html += '<button class="btn btn-sm" id="rp-export-csv">CSV</button>';

        html += '</div></div>';

        // Tags
        html += '<div class="replay-sidebar-section"><h4>Tags</h4><div class="replay-tags-list" id="rp-tags">';
        tags.forEach(function(t) {
          var name = t.name || t.tag || t;
          html += '<span class="replay-tag">' + esc(name) + (canManage ? '<span class="replay-tag-remove" data-tag="' + esc(name) + '">&times;</span>' : '') + '</span>';
        });
        html += '</div>';
        if (canManage) html += '<div class="replay-tag-add"><input type="text" id="rp-tag-input" placeholder="Add tag..."><button class="btn btn-sm" id="rp-tag-add-btn">Add</button></div>';
        html += '</div>';

        // Flags
        if (canManage) {
          html += '<div class="replay-sidebar-section"><h4>Flags</h4><div class="replay-flag-toggles">';
          html += '<label><input type="checkbox" id="rp-flag-training"' + (seg.is_training ? ' checked' : '') + '> Training</label>';
          html += '<label><input type="checkbox" id="rp-flag-permanent"' + (seg.is_permanent ? ' checked' : '') + '> Permanent</label>';
          html += '</div></div>';
        }

        // Comments
        html += '<div class="replay-sidebar-section" style="flex:1;display:flex;flex-direction:column"><h4>Comments</h4>';
        html += '<div id="rp-comments" style="flex:1;overflow-y:auto">';
        comments.forEach(function(c) {
          html += '<div class="replay-comment">';
          if (c.timestamp_ms != null) html += '<span class="replay-comment-time" data-ts="' + c.timestamp_ms + '">' + fmtDuration(c.timestamp_ms) + '</span>';
          html += '<span class="replay-comment-author">' + esc(c.user_name || c.user_email || 'Unknown') + '</span>';
          html += esc(c.body || c.text || '') + '</div>';
        });
        html += '</div>';
        html += '<div class="replay-comment-form"><textarea id="rp-comment-text" placeholder="Add a comment..." rows="2"></textarea>';
        html += '<div class="replay-comment-form-actions"><label><input type="checkbox" id="rp-comment-pin"> Pin to current time</label><button class="btn btn-sm" id="rp-comment-submit">Post</button></div>';
        html += '</div></div>';

        html += '</div>';
        playerOverlay.innerHTML = html;

        // Init player
        var playerContainer = playerOverlay.querySelector('#rp-container');
        var playerInstance = null;
        try {
          var RRWebPlayer = window.rrwebPlayer || window.RRWebPlayer || (window.rrweb && window.rrweb.Replayer);
          if (window.rrwebPlayer && window.rrwebPlayer.default) RRWebPlayer = window.rrwebPlayer.default;
          if (!RRWebPlayer && typeof rrwebPlayer !== 'undefined') RRWebPlayer = rrwebPlayer.default || rrwebPlayer;
          console.log('[XRay Replay] Player constructor:', !!RRWebPlayer, 'Events:', events.length, 'FullSnapshots:', events.filter(function(e){return e.type===2}).length);
          if (events.length < 2) {
              playerContainer.innerHTML = '<div class="replay-no-data">This segment has insufficient recording data (' + events.length + ' event' + (events.length !== 1 ? 's' : '') + '). The session was too short to produce a playback.</div>';
            } else {
              playerInstance = new RRWebPlayer({
                target: playerContainer,
                props: {
                  events: events,
                  showController: true,
                  autoPlay: true,
                  speed: 1,
                  showWarning: false,
                  mouseTail: { strokeStyle: 'rgba(74,222,128,0.6)', lineWidth: 2, lineCap: 'round' },
                  insertStyleRules: [
                    '.replayer-mouse-tail{stroke-width:2}',
                    '.replayer-mouse.active::after{content:\'\';position:absolute;width:30px;height:30px;border-radius:50%;border:3px solid rgba(239,68,68,0.8);background:rgba(239,68,68,0.15);top:-15px;left:-15px;pointer-events:none;animation:replay-click-ring 0.8s ease-out forwards}',
                    '@keyframes replay-click-ring{0%{transform:scale(0.3);opacity:1}70%{transform:scale(1.2);opacity:0.6}100%{transform:scale(1.8);opacity:0}}'
                  ]
                }
              });
            }
        } catch(e) { console.error('rrweb player init error', e); playerContainer.innerHTML = '<div class="replay-no-data">Could not initialize player. ' + esc(e.message) + '</div>'; }

        // Fetch storage size
        api.get('/api/v1/replay/segments/' + segId + '/storage').then(function(sr) {
          var el = playerOverlay.querySelector('#rp-storage');
          if (sr.ok && sr.data && el) {
            el.textContent = sr.data.segmentFormatted + ' (session: ' + sr.data.sessionFormatted + ')';
          }
        });

        // Fetch click details
        api.get('/api/v1/replay/segments/' + segId + '/clicks').then(function(cr) {
          var el = playerOverlay.querySelector('#rp-clicks');
          if (!el) return;
          var clickList = cr.ok ? (cr.data.data || cr.data || []) : [];
          if (clickList.length === 0) { el.textContent = 'No clicks recorded'; return; }
          el.innerHTML = clickList.map(function(c, i) {
            var ctx = c.context || {};
            var ctxText = ctx.rowContent ? ctx.rowContent : (ctx.nearbyText && ctx.nearbyText.length ? ctx.nearbyText.join(', ') : '');
            return '<div style="padding:5px 0;border-bottom:1px solid var(--bd);cursor:pointer" class="rp-click-item" data-ts="' + (c.timeOffset || 0) + '" data-x="' + (c.x || 0) + '" data-y="' + (c.y || 0) + '">' +
              '<span style="color:var(--ac);font-weight:600">' + (c.timeFormatted || '-') + '</span> ' +
              '<b>&lt;' + esc(c.element || '?') + '&gt;</b>' +
              (c.text ? ' "' + esc(c.text.substring(0, 50)) + '"' : '') +
              (c.selector ? '<br><span style="font-size:11px;color:var(--t3)">' + esc(c.selector.substring(0, 80)) + '</span>' : '') +
              (ctxText ? '<br><span style="font-size:11px;color:var(--ac2,#8b5cf6)">Row: ' + esc(ctxText.substring(0, 120)) + '</span>' : '') +
              '</div>';
          }).join('');
          // Click on a click detail to seek the player to that time
          el.querySelectorAll('.rp-click-item').forEach(function(item) {
            item.onclick = function() {
              var ts = parseInt(item.getAttribute('data-ts'));
              seekToTime(ts);
            };
          });
        });

        // Export buttons
        var exportJsonBtn = playerOverlay.querySelector('#rp-export-json');
        var exportCsvBtn = playerOverlay.querySelector('#rp-export-csv');
        function downloadExport(segIdExp, fmt) {
          api.get('/api/v1/replay/segments/' + segIdExp + '/export?format=' + fmt).then(function(r) {
            if (!r.ok) { if (window.__xrayToast) window.__xrayToast('Export failed', 'error'); return; }
            var exportData = r.data;
            var content, mimeType, ext;
            if (fmt === 'csv') {
              content = typeof exportData === 'string' ? exportData : JSON.stringify(exportData);
              mimeType = 'text/csv';
              ext = 'csv';
            } else {
              content = JSON.stringify(exportData, null, 2);
              mimeType = 'application/json';
              ext = 'json';
            }
            var blob = new Blob([content], { type: mimeType });
            var url = URL.createObjectURL(blob);
            var a = document.createElement('a');
            a.href = url;
            a.download = 'session-replay-' + segIdExp.substring(0,8) + '.' + ext;
            document.body.appendChild(a); a.click(); document.body.removeChild(a);
            URL.revokeObjectURL(url);
            if (window.__xrayToast) window.__xrayToast('Export downloaded', 'success');
          });
        }
        if (exportJsonBtn) exportJsonBtn.onclick = function() { downloadExport(segId, 'json'); };
        if (exportCsvBtn) exportCsvBtn.onclick = function() { downloadExport(segId, 'csv'); };



        // Close
        playerOverlay.querySelector('#rp-close').onclick = function() { document.removeEventListener('keydown', onKeyDown); _isPlaying = true; playerOverlay.style.display = 'none'; playerOverlay.innerHTML = ''; if (playerInstance && playerInstance.$destroy) playerInstance.$destroy(); };

        // Seeking disabled — rrweb goto skips DOM mutations causing partial renders.
        // Users should watch from start at chosen speed (0.25x–8x).
        function seekToTime(ms) {
          // no-op: seeking is disabled
        }

        // Play/Pause toggle
        var _isPlaying = true;
        function togglePlayPause() {
          if (!playerInstance) return;
          if (_isPlaying) {
            try { playerInstance.pause(); } catch(e) {}
            _isPlaying = false;
          } else {
            try { playerInstance.play(); } catch(e) {}
            _isPlaying = true;
          }
        }

        // Spacebar to pause/play
        function onKeyDown(e) {
          if (e.code === 'Space' && playerOverlay.style.display !== 'none') {
            e.preventDefault();
            togglePlayPause();
          }
        }
        document.addEventListener('keydown', onKeyDown);

        // Click on replay content to pause/play
        var rpMain = playerOverlay.querySelector('.replay-player-main');
        if (rpMain) rpMain.addEventListener('click', function(e) {
          if (e.target.closest('.rr-controller') || e.target.closest('button') || e.target.closest('.replay-player-sidebar')) return;
          togglePlayPause();
        });


        // Speed handled by rrweb player built-in controls

        // Comment timestamps: click to seek
        playerOverlay.querySelectorAll('.replay-comment-time').forEach(function(el) {
          el.onclick = function() { var ts = parseInt(el.getAttribute('data-ts')); seekToTime(ts); };
        });

        // Add tag
        if (canManage) {
          var tagAddBtn = playerOverlay.querySelector('#rp-tag-add-btn');
          var tagInput = playerOverlay.querySelector('#rp-tag-input');
          if (tagAddBtn) tagAddBtn.onclick = function() {
            var v = tagInput.value.trim();
            if (!v) return;
            api.post('/api/v1/replay/segments/' + segId + '/tags', { name: v }).then(function(r) {
              if (r.ok) { tagInput.value = ''; openPlayer(segId); }
            });
          };
          // Remove tag
          playerOverlay.querySelectorAll('.replay-tag-remove').forEach(function(el) {
            el.onclick = function(e) {
              e.stopPropagation();
              var tname = el.getAttribute('data-tag');
              api.del('/api/v1/replay/segments/' + segId + '/tags/' + encodeURIComponent(tname)).then(function(r) { if (r.ok) openPlayer(segId); });
            };
          });

          // Flag toggles
          var trainCb = playerOverlay.querySelector('#rp-flag-training');
          var permCb = playerOverlay.querySelector('#rp-flag-permanent');
          if (trainCb) trainCb.onchange = function() { api.patch('/api/v1/replay/segments/' + segId, { is_training: trainCb.checked }); };
          if (permCb) permCb.onchange = function() { api.patch('/api/v1/replay/segments/' + segId, { is_permanent: permCb.checked }); };
        }

        // Post comment
        var commentSubmit = playerOverlay.querySelector('#rp-comment-submit');
        if (commentSubmit) commentSubmit.onclick = function() {
          var txt = playerOverlay.querySelector('#rp-comment-text').value.trim();
          if (!txt) return;
          var pin = playerOverlay.querySelector('#rp-comment-pin').checked;
          var payload = { body: txt };
          if (pin && playerInstance) {
            try {
              var meta = playerInstance.getMetaData ? playerInstance.getMetaData() : {};
              var ct = playerInstance.getCurrentTime ? playerInstance.getCurrentTime() : 0;
              payload.timestamp_ms = ct;
            } catch(e) {}
          }
          api.post('/api/v1/replay/segments/' + segId + '/comments', payload).then(function(r) {
            if (r.ok) openPlayer(segId);
          });
        };
      });
    });
  }

  // ── Live sessions overlay ──
  liveBtn.onclick = function() { openLiveOverlay(); };

  function openLiveOverlay() {
    liveOverlay.style.display = 'flex';
    liveOverlay.innerHTML = '<div class="replay-live-header"><h3>Live Sessions (All Tenants)</h3><button class="replay-player-close" id="rl-close">&times;</button></div><div class="replay-live-list"><div class="replay-no-data">Loading...</div></div>';
    liveOverlay.querySelector('#rl-close').onclick = function() { liveOverlay.style.display = 'none'; liveOverlay.innerHTML = ''; };

    api.get('/api/v1/replay/sessions/active').then(function(r) {
      var sessions = r.ok ? (r.data.data || r.data.sessions || r.data || []) : [];
      var listDiv = liveOverlay.querySelector('.replay-live-list');
      if (!sessions.length) { listDiv.innerHTML = '<div class="replay-no-data">No active sessions</div>'; return; }
      listDiv.innerHTML = sessions.map(function(s) {
        return '<div class="replay-live-row"><div class="replay-live-row-info">' +
          esc(s.user_name || s.user_email || 'Unknown') +
          (s.user_email ? ' <span style="color:var(--t3);font-size:12px">' + esc(s.user_email) + '</span>' : '') +
          '<span>' + esc(s.current_dashboard_name || s.current_segment_type || '-') + ' &middot; Started ' + fmtDate(s.started_at) + '</span></div>' +
          '<button class="btn btn-sm" data-session-id="' + (s.id || s.session_id) + '">Shadow</button></div>';
      }).join('');
      listDiv.querySelectorAll('button[data-session-id]').forEach(function(btn) {
        btn.onclick = function() { openShadow(btn.getAttribute('data-session-id')); };
      });
    });
  }

  function openShadow(sessionId) {
    liveOverlay.style.display = 'none';
    playerOverlay.style.display = 'flex';
    playerOverlay.innerHTML = '<div class="replay-player-main"><button class="replay-player-close" id="rs-close">&times;</button><div id="rs-container"></div></div>' +
      '<div class="replay-player-sidebar"><div class="replay-sidebar-section"><h4>Live Shadow</h4><div class="replay-sidebar-meta">Watching session in real-time.<br>Events stream in as they happen.</div></div></div>';

    loadRRWebPlayer(function(err) {
      if (err) { playerOverlay.innerHTML = '<div class="replay-player-main"><div class="replay-no-data">Failed to load player<br><button class="btn sm" style="margin-top:12px" onclick="document.querySelector(\'#replay-player-overlay\').style.display=\'none\'">Close</button></div></div>'; return; }

      var shadowContainer = playerOverlay.querySelector('#rs-container');
      var shadowPlayer = null;
      var shadowEvents = [];

      // Subscribe via WebSocket
      // Subscribe to live events
      if (window.__xrayWs && window.__xrayWs.readyState === 1) {
        window.__xrayWs.send(JSON.stringify({ type: 'replay:shadow-subscribe', data: { sessionId: sessionId } }));
      }

      // Fetch existing events for this session's current segment to pre-populate the player
      api.get('/api/v1/replay/segments?limit=1&sessionId=' + sessionId).then(function(r) {
        var segs = r.ok ? (r.data.data || r.data || []) : [];
        if (segs.length > 0) {
          var latestSeg = segs[0];
          api.get('/api/v1/replay/segments/' + latestSeg.id + '/events').then(function(evtR) {
            var existingEvents = evtR.ok ? (evtR.data.data || evtR.data || []) : [];
            if (existingEvents.length >= 2 && !shadowPlayer) {
              existingEvents.forEach(function(evt) { shadowEvents.push(evt); });
              try {
                var RRWebPlayer = window.rrwebPlayer || window.RRWebPlayer || (window.rrweb && window.rrweb.Player);
                if (!RRWebPlayer && window.rrwebPlayer && window.rrwebPlayer.default) RRWebPlayer = window.rrwebPlayer.default;
                shadowPlayer = new RRWebPlayer({ target: shadowContainer, props: { events: shadowEvents, showController: true, autoPlay: true, liveMode: true } });
              } catch(ex) { console.error('shadow player init from existing events', ex); }
            }
          });
        }
      });

      // Listen for new live events
      function onWsMessage(e) {
        try {
          var msg = JSON.parse(e.data);
          if (msg.type === 'replay:shadow-events' && msg.data && msg.data.sessionId === sessionId) {
            var evts = msg.data.events || [];
            evts.forEach(function(evt) {
              shadowEvents.push(evt);
              if (shadowPlayer) {
                try { shadowPlayer.addEvent(evt); } catch(ex) {}
              }
            });
            if (!shadowPlayer && shadowEvents.length >= 2) {
              try {
                var RRWebPlayer = window.rrwebPlayer || window.RRWebPlayer || (window.rrweb && window.rrweb.Player);
                if (!RRWebPlayer && window.rrwebPlayer && window.rrwebPlayer.default) RRWebPlayer = window.rrwebPlayer.default;
                shadowPlayer = new RRWebPlayer({ target: shadowContainer, props: { events: shadowEvents, showController: true, autoPlay: true, liveMode: true } });
              } catch(ex) { console.error('shadow player init', ex); }
            }
          }
        } catch(ex) {}
      }
      if (window.__xrayWs) window.__xrayWs.addEventListener('message', onWsMessage);

      playerOverlay.querySelector('#rs-close').onclick = function() {
        if (window.__xrayWs && window.__xrayWs.readyState === 1) {
          window.__xrayWs.send(JSON.stringify({ type: 'replay:shadow-unsubscribe', data: { sessionId: sessionId } }));
        }
        if (window.__xrayWs) window.__xrayWs.removeEventListener('message', onWsMessage);
        if (shadowPlayer && shadowPlayer.$destroy) shadowPlayer.$destroy();
        playerOverlay.style.display = 'none';
        playerOverlay.innerHTML = '';
      };
    });
  }

  // Listen for cross-view open requests (e.g. from dashboard detail modal)
  window.addEventListener('xray-open-replay', function(e) {
    if (e.detail && e.detail.segmentId) openPlayer(e.detail.segmentId);
  });

  // Initial load
  loadSegments();

  // ── DELETE + CHECKBOX + ROW CLICK — single delegated handler ──
  listEl.addEventListener('click', function(e) {
    // 1. Delete button
    var db = e.target.closest('.replay-del-btn');
    if (db) {
      e.stopPropagation();
      e.preventDefault();
      var sid = db.getAttribute('data-del-id');
      if (!sid) return;
      var m = document.createElement('div');
      m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:10000;display:flex;align-items:center;justify-content:center';
      m.innerHTML = '<div style="background:var(--bg2);border-radius:10px;padding:24px;max-width:400px;width:90%"><h3 style="margin:0 0 12px;color:var(--t1)">Delete Recording</h3><p style="color:var(--t2);margin:0 0 20px">Delete this recording? This cannot be undone.</p><div style="display:flex;gap:10px;justify-content:flex-end"><button class="btn" data-act="cancel">Cancel</button><button class="btn" data-act="delete" style="background:#ef4444;color:#fff;border-color:#ef4444">Delete</button></div></div>';
      document.body.appendChild(m);
      m.addEventListener('click', function(me) {
        if (me.target.getAttribute('data-act') === 'cancel' || me.target === m) m.remove();
        if (me.target.getAttribute('data-act') === 'delete') {
          api.delete('/api/v1/replay/segments/' + sid).then(function() { m.remove(); loadSegments(); if(window.__xrayToast) window.__xrayToast('Deleted','success'); });
        }
      });
      return;
    }
    // 2. Checkbox
    if (e.target.type === 'checkbox') {
      e.stopPropagation();
      if (e.target.id === 'replay-select-all') {
        _selIds = [];
        listEl.querySelectorAll('input[data-check-id]').forEach(function(c) { c.checked = e.target.checked; if(e.target.checked) _selIds.push(c.getAttribute('data-check-id')); });
      } else {
        var cid = e.target.getAttribute('data-check-id');
        if (cid) { if(e.target.checked) _selIds.push(cid); else _selIds = _selIds.filter(function(x){return x!==cid;}); }
      }
      _updateBulk();
      return;
    }
    // 3. Row click → open player
    var row = e.target.closest('.replay-row:not(.replay-row-head)');
    if (row) {
      if (row.getAttribute('data-is-live') === '1') openShadow(row.getAttribute('data-session-id'));
      else openPlayer(row.getAttribute('data-seg-id'));
    }
  });

  // ── BULK STATE ──
  var _selIds = [];
  function _updateBulk() {
    var bar = container.querySelector('#ar-bulk-bar');
    if (bar) { bar.style.display = _selIds.length > 0 ? 'flex' : 'none'; var c = bar.querySelector('#ar-bulk-count'); if(c) c.textContent = _selIds.length + ' selected'; }
  }
  var _bdb = container.querySelector('#ar-bulk-delete-btn');
  if (_bdb) _bdb.addEventListener('click', function() {
    if (_selIds.length === 0) return;
    var n = _selIds.length;
    var m = document.createElement('div');
    m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:10000;display:flex;align-items:center;justify-content:center';
    m.innerHTML = '<div style="background:var(--bg2);border-radius:10px;padding:24px;max-width:400px;width:90%"><h3 style="margin:0 0 12px;color:var(--t1)">Delete '+n+' Recording'+(n>1?'s':'')+'</h3><p style="color:var(--t2);margin:0 0 20px">This cannot be undone.</p><div style="display:flex;gap:10px;justify-content:flex-end"><button class="btn" data-act="cancel">Cancel</button><button class="btn" data-act="delete" style="background:#ef4444;color:#fff;border-color:#ef4444">Delete</button></div></div>';
    document.body.appendChild(m);
    m.addEventListener('click', function(me) {
      if (me.target.getAttribute('data-act') === 'cancel' || me.target === m) m.remove();
      if (me.target.getAttribute('data-act') === 'delete') {
        Promise.all(_selIds.map(function(id){return api.delete('/api/v1/replay/segments/'+id);})).then(function(){m.remove();_selIds=[];_updateBulk();loadSegments();if(window.__xrayToast)window.__xrayToast('Deleted '+n+' recordings','success');});
      }
    });
  });
  var _bcb = container.querySelector('#ar-bulk-clear-btn');
  if (_bcb) _bcb.addEventListener('click', function() { _selIds = []; listEl.querySelectorAll('input[type=checkbox]').forEach(function(c){c.checked=false;}); _updateBulk(); });



  // Real-time updates: listen for replay events on WebSocket and refresh
  var _refreshTimer = setInterval(function() {
    if (document.contains(container)) loadSegments();

    else clearInterval(_refreshTimer);
  }, 15000);
  // Also listen for WS segment updates for faster refresh
  function _onReplayWs(e) {
    try {
      var msg = JSON.parse(e.data);
      if (msg.type === 'replay:segment-update' || msg.type === 'replay:session-ended' || msg.type === 'replay:events' || msg.type === 'replay:shadow-events') {
        if (document.contains(container)) loadSegments();

      }
    } catch(ex) {}
  }
  if (window.__xrayWs) window.__xrayWs.addEventListener('message', _onReplayWs);
}

admin_replay_config.js:
function initReplayConfig(container, api, user) {
  var storageType = container.querySelector('#rc-storage-type');
  var retention = container.querySelector('#rc-retention');
  var s3Section = container.querySelector('#rc-s3-section');
  var s3Endpoint = container.querySelector('#rc-s3-endpoint');
  var s3Bucket = container.querySelector('#rc-s3-bucket');
  var s3Region = container.querySelector('#rc-s3-region');
  var s3Access = container.querySelector('#rc-s3-access');
  var s3Secret = container.querySelector('#rc-s3-secret');
  var saveBtn = container.querySelector('#rc-save');

  storageType.onchange = function() {
    s3Section.style.display = storageType.value === 's3' ? '' : 'none';
  };

  // Load current settings
  api.get('/api/admin/settings').then(function(r) {
    if (!r.ok) return;
    var s = r.data || {};
    if (s.replay_storage_type) storageType.value = s.replay_storage_type;
    if (s.replay_retention_days) retention.value = s.replay_retention_days;
    if (s.replay_s3_endpoint) s3Endpoint.value = s.replay_s3_endpoint;
    if (s.replay_s3_bucket) s3Bucket.value = s.replay_s3_bucket;
    if (s.replay_s3_region) s3Region.value = s.replay_s3_region;
    if (s.replay_s3_access_key) s3Access.value = s.replay_s3_access_key;
    if (s.replay_s3_secret_key) s3Secret.value = s.replay_s3_secret_key;
    storageType.onchange();
  });

  saveBtn.onclick = function() {
    saveBtn.disabled = true;
    var payload = {
      replay_storage_type: storageType.value,
      replay_retention_days: retention.value
    };
    if (storageType.value === 's3') {
      payload.replay_s3_endpoint = s3Endpoint.value;
      payload.replay_s3_bucket = s3Bucket.value;
      payload.replay_s3_region = s3Region.value;
      if (s3Access.value) payload.replay_s3_access_key = s3Access.value;
      if (s3Secret.value) payload.replay_s3_secret_key = s3Secret.value;
    }
    api.patch('/api/admin/settings', payload).then(function(r) {
      saveBtn.disabled = false;
      if (r.ok) {
        if (window.__xrayToast) window.__xrayToast('Replay configuration saved', 'success');
      } else {
        if (window.__xrayToast) window.__xrayToast('Failed to save configuration', 'error');
      }
    }).catch(function() {
      saveBtn.disabled = false;
      if (window.__xrayToast) window.__xrayToast('Failed to save configuration', 'error');
    });
  };
}
